// Prisma Database Seed
// This file seeds initial data for development/testing

import { PrismaClient, SubscriptionTier } from '@prisma/client';

const prisma = new PrismaClient();

async function main() {
  console.log('­ƒî▒ Starting database seed...');

  // 1. Create billing plans
  console.log('Creating billing plans...');
  const plans = await Promise.all([
    prisma.billingPlan.upsert({
      where: { tier: 'FREE' },
      update: {},
      create: {
        name: 'Free',
        tier: 'FREE',
        description: 'Perfect for getting started',
        pricePerMonth: 0,
        pricePerYear: 0,
        maxMembers: 5,
        maxProjects: 10,
        maxStorageGB: 5,
        features: ['basic-content', 'basic-scheduling'],
      },
    }),
    prisma.billingPlan.upsert({
      where: { tier: 'STARTER' },
      update: {},
      create: {
        name: 'Starter',
        tier: 'STARTER',
        description: 'For small teams',
        pricePerMonth: 29,
        pricePerYear: 290,
        maxMembers: 10,
        maxProjects: 50,
        maxStorageGB: 100,
        features: [
          'all-content-types',
          'basic-automation',
          'basic-analytics',
        ],
      },
    }),
    prisma.billingPlan.upsert({
      where: { tier: 'PROFESSIONAL' },
      update: {},
      create: {
        name: 'Professional',
        tier: 'PROFESSIONAL',
        description: 'For growing teams',
        pricePerMonth: 99,
        pricePerYear: 990,
        maxMembers: 50,
        maxProjects: 500,
        maxStorageGB: 1024,
        features: [
          'all-features',
          'advanced-automation',
          'advanced-analytics',
          'api-access',
          'priority-support',
        ],
      },
    }),
    prisma.billingPlan.upsert({
      where: { tier: 'ENTERPRISE' },
      update: {},
      create: {
        name: 'Enterprise',
        tier: 'ENTERPRISE',
        description: 'For large organizations',
        pricePerMonth: 9999,
        pricePerYear: 99990,
        maxMembers: 999,
        maxProjects: 9999,
        maxStorageGB: 10240,
        features: [
          'all-features',
          'custom-integration',
          'dedicated-support',
          'sso',
          'custom-contracts',
        ],
      },
    }),
  ]);

  console.log(`Ô£ô Created ${plans.length} billing plans`);

  // 2. Create demo user
  console.log('Creating demo user...');
  const demoUser = await prisma.user.upsert({
    where: { email: 'demo@belsuite.com' },
    update: {},
    create: {
      email: 'demo@belsuite.com',
      passwordHash: '$2b$10$demo.hashed.password', // bcrypt hash of "Demo123456!"
      firstName: 'Demo',
      lastName: 'User',
      status: 'ACTIVE',
    },
  });

  console.log(`Ô£ô Created demo user: ${demoUser.email}`);

  // 3. Create demo organization
  console.log('Creating demo organization...');
  const demoOrg = await prisma.organization.upsert({
    where: { slug: 'demo-organization' },
    update: {},
    create: {
      name: 'Demo Organization',
      slug: 'demo-organization',
      description: 'Demo workspace for testing Belsuite',
      status: 'ACTIVE',
      tier: 'PROFESSIONAL',
      maxMembers: 50,
      maxProjects: 500,
      maxStorageGB: 1024,
    },
  });

  console.log(`Ô£ô Created demo organization: ${demoOrg.name}`);

  // 4. Create roles
  console.log('Creating roles...');
  const adminRole = await prisma.role.upsert({
    where: {
      organizationId_name: {
        organizationId: demoOrg.id,
        name: 'Admin',
      },
    },
    update: {},
    create: {
      organizationId: demoOrg.id,
      name: 'Admin',
      isSystem: true,
    },
  });

  const creatorRole = await prisma.role.upsert({
    where: {
      organizationId_name: {
        organizationId: demoOrg.id,
        name: 'Creator',
      },
    },
    update: {},
    create: {
      organizationId: demoOrg.id,
      name: 'Creator',
      isSystem: false,
    },
  });

  console.log(`Ô£ô Created roles: Admin, Creator`);

  // 5. Create permissions
  console.log('Creating permissions...');
  const permissions = [
    { action: 'create', resource: 'content' },
    { action: 'read', resource: 'content' },
    { action: 'update', resource: 'content' },
    { action: 'delete', resource: 'content' },
    { action: 'manage', resource: 'users' },
    { action: 'manage', resource: 'organization' },
    { action: 'manage', resource: 'billing' },
  ];

  for (const perm of permissions) {
    await prisma.permission.upsert({
      where: {
        roleId_action_resource: {
          roleId: adminRole.id,
          action: perm.action,
          resource: perm.resource,
        },
      },
      update: {},
      create: {
        roleId: adminRole.id,
        action: perm.action,
        resource: perm.resource,
      },
    });
  }

  const creatorPermissions = ['create', 'read', 'update'].map((action) => ({
    action,
    resource: 'content',
  }));

  for (const perm of creatorPermissions) {
    await prisma.permission.upsert({
      where: {
        roleId_action_resource: {
          roleId: creatorRole.id,
          action: perm.action,
          resource: perm.resource,
        },
      },
      update: {},
      create: {
        roleId: creatorRole.id,
        action: perm.action,
        resource: perm.resource,
      },
    });
  }

  console.log(`Ô£ô Created ${permissions.length} permissions`);

  // 6. Add user to organization
  console.log('Adding user to organization...');
  await prisma.organizationMember.upsert({
    where: {
      organizationId_userId: {
        organizationId: demoOrg.id,
        userId: demoUser.id,
      },
    },
    update: {},
    create: {
      organizationId: demoOrg.id,
      userId: demoUser.id,
      roleId: adminRole.id,
      status: 'ACTIVE',
      roleName: 'Admin',
      permissions: permissions.map((p) => `${p.action}:${p.resource}`),
    },
  });

  console.log(`Ô£ô Added user to organization as Admin`);

  // 7. Create subscription
  console.log('Creating subscription...');
  const subscription = await prisma.subscription.upsert({
    where: { organizationId: demoOrg.id },
    update: {},
    create: {
      organizationId: demoOrg.id,
      planId: plans[2].id, // Professional plan
      status: 'ACTIVE',
      currentPeriodStart: new Date(),
      currentPeriodEnd: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
    },
  });

  console.log(`Ô£ô Created subscription`);

  // 8. Create sample content
  console.log('Creating sample content...');
  const content1 = await prisma.content.upsert({
    where: { organizationId_slug: { organizationId: demoOrg.id, slug: 'welcome-post' } },
    update: {},
    create: {
      organizationId: demoOrg.id,
      type: 'TEXT',
      title: 'Welcome to Belsuite',
      slug: 'welcome-post',
      description: 'Getting started with Belsuite platform',
      content: 'Welcome to Belsuite! This is your first content item.',
      creatorId: demoUser.id,
      status: 'PUBLISHED',
      publishedAt: new Date(),
    },
  });

  const content2 = await prisma.content.upsert({
    where: { organizationId_slug: { organizationId: demoOrg.id, slug: 'sample-image' } },
    update: {},
    create: {
      organizationId: demoOrg.id,
      type: 'IMAGE',
      title: 'Sample Image',
      slug: 'sample-image',
      description: 'Sample image for demonstration',
      creatorId: demoUser.id,
      status: 'DRAFT',
    },
  });

  console.log(`Ô£ô Created 2 sample content items`);

  // 9. Create billing profile
  console.log('Creating billing profile...');
  await prisma.billingProfile.upsert({
    where: { organizationId: demoOrg.id },
    update: {},
    create: {
      organizationId: demoOrg.id,
      billingEmail: 'billing@belsuite.com',
      billingName: 'Demo Organization',
      billingAddress: '123 Demo Street',
      billingCity: 'Demo City',
      billingState: 'DC',
      billingZip: '12345',
      billingCountry: 'USA',
    },
  });

  console.log(`Ô£ô Created billing profile`);

  console.log('\nÔ£à Database seeding completed successfully!');
  console.log('\nDemo credentials:');
  console.log('  Email: demo@belsuite.com');
  console.log('  Password: Demo123456!');
  console.log('\nYou can now log in and explore the platform.');
}

main()
  .catch((e) => {
    console.error('­ƒö┤ Seed failed:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import Link from 'next/link';
import { ArrowLeft, Sparkles, BarChart3 } from 'lucide-react';
import AIDashboard from '@/components/AIDashboard';

export default function DashboardPage() {
  const [timeRange, setTimeRange] = useState<'24h' | '7d' | '30d'>('30d');

  const timeRanges: Array<'24h' | '7d' | '30d'> = ['24h', '7d', '30d'];

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900">
      {/* Navigation */}
      <nav className="flex items-center justify-between px-6 py-4 border-b border-purple-500/20">
        <Link href="/ai" className="flex items-center gap-2 hover:opacity-80 transition">
          <ArrowLeft className="w-5 h-5 text-purple-400" />
          <span className="text-gray-300">Back to AI</span>
        </Link>
        <div className="flex items-center gap-2">
          <BarChart3 className="w-6 h-6 text-purple-400" />
          <span className="text-xl font-bold text-white">Analytics Dashboard</span>
        </div>
        <div className="w-24"></div>
      </nav>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-6 py-12">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="flex items-center justify-between mb-12"
        >
          <div>
            <h1 className="text-4xl font-bold text-white mb-4">AI Usage Analytics</h1>
            <p className="text-gray-300">
              Monitor your AI generation usage, costs, and performance metrics in real-time.
            </p>
          </div>

          {/* Time Range Selector */}
          <div className="flex gap-2">
            {timeRanges.map((range) => (
              <button
                key={range}
                onClick={() => setTimeRange(range)}
                className={`px-4 py-2 rounded-lg transition ${
                  timeRange === range
                    ? 'bg-purple-600 text-white'
                    : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
                }`}
              >
                {range === '24h' ? 'Last 24h' : range === '7d' ? 'Last 7 days' : 'Last 30 days'}
              </button>
            ))}
          </div>
        </motion.div>

        {/* Dashboard Component */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.2 }}
        >
          <AIDashboard timeRange={timeRange} />
        </motion.div>

        {/* Info Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.4 }}
          className="mt-12 grid md:grid-cols-3 gap-6"
        >
          {[
            {
              title: 'Smart Routing',
              description:
                'We automatically route your requests to the most cost-effective provider that meets your quality requirements.',
            },
            {
              title: 'Intelligent Caching',
              description:
                'Identical requests are cached for 24 hours, reducing costs and improving response times.',
            },
            {
              title: 'Cost Optimization',
              description:
                'Choose between models based on your needs: fastest, cheapest, or best quality.',
            },
          ].map((info, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.8, delay: index * 0.1 }}
              className="bg-gradient-to-br from-purple-600/20 to-purple-400/10 border border-purple-500/30 rounded-lg p-6"
            >
              <h3 className="text-lg font-semibold text-white mb-2">{info.title}</h3>
              <p className="text-gray-300">{info.description}</p>
            </motion.div>
          ))}
        </motion.div>

        {/* CTA Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.6 }}
          className="mt-12 bg-gradient-to-r from-purple-600 to-blue-600 rounded-lg p-8 text-center"
        >
          <h2 className="text-2xl font-bold text-white mb-4">Ready to Generate Content?</h2>
          <p className="text-gray-100 mb-6">
            Start creating high-quality content with our AI-powered tools. Multi-provider support, smart routing, and
            real-time analytics included.
          </p>
          <Link href="/ai/generate">
            <button className="px-8 py-3 bg-white text-purple-600 rounded-lg font-semibold hover:bg-gray-100 transition transform hover:scale-105">
              Go to Generator
            </button>
          </Link>
        </motion.div>
      </div>

      {/* Background Animation */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-20 left-10 w-72 h-72 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob"></div>
        <div className="absolute top-40 right-10 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-2000"></div>
      </div>
    </div>
  );
}

'use client';

import { useState, useRef, useCallback, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'motion/react';
import {
  ArrowLeft, Play, Pause, SkipBack, SkipForward, Volume2, VolumeX,
  Maximize2, Download, Loader2, Sparkles, ChevronRight, RotateCcw,
  Settings, Save, Clapperboard, AlertCircle, CheckCircle2,
} from 'lucide-react';
import { useVideoEditor } from '@/hooks/useVideoProject';
import { ScenePanel } from '@/components/video/ScenePanel';
import { MediaPanel } from '@/components/video/MediaPanel';
import { VideoTimeline } from '@/components/video/VideoTimeline';
import { PropertiesPanel } from '@/components/video/PropertiesPanel';
import { ScriptGeneratorModal } from '@/components/video/ScriptGeneratorModal';

type LeftTab = 'scenes' | 'media';

// ÔöÇÔöÇ Playback controls ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function PlaybackBar({
  playing,
  muted,
  currentMs,
  durationMs,
  onTogglePlay,
  onToggleMute,
  onSeek,
}: {
  playing: boolean;
  muted: boolean;
  currentMs: number;
  durationMs: number;
  onTogglePlay: () => void;
  onToggleMute: () => void;
  onSeek: (ms: number) => void;
}) {
  const fmt = (ms: number) => {
    const s = Math.floor(ms / 1000);
    const m = Math.floor(s / 60);
    return `${String(m).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;
  };

  return (
    <div className="flex items-center gap-3 px-4 py-2 bg-zinc-900/80 border-t border-white/5">
      <button onClick={() => onSeek(0)} className="text-zinc-400 hover:text-white transition-colors">
        <SkipBack className="w-4 h-4" />
      </button>
      <button
        onClick={onTogglePlay}
        className="w-8 h-8 rounded-full bg-primary/90 hover:bg-primary flex items-center justify-center transition-colors"
      >
        {playing ? <Pause className="w-4 h-4 text-white" /> : <Play className="w-4 h-4 text-white ml-0.5" />}
      </button>
      <button onClick={() => onSeek(durationMs)} className="text-zinc-400 hover:text-white transition-colors">
        <SkipForward className="w-4 h-4" />
      </button>

      <span className="text-xs text-zinc-500 font-mono w-24 shrink-0 text-center">
        {fmt(currentMs)} / {fmt(durationMs)}
      </span>

      <div className="flex-1 relative h-1.5 bg-zinc-700 rounded-full cursor-pointer group"
        onClick={(e) => {
          const rect = e.currentTarget.getBoundingClientRect();
          const ratio = (e.clientX - rect.left) / rect.width;
          onSeek(Math.round(ratio * durationMs));
        }}
      >
        <div
          className="absolute left-0 top-0 h-full bg-primary rounded-full transition-none"
          style={{ width: `${durationMs ? (currentMs / durationMs) * 100 : 0}%` }}
        />
        <div
          className="absolute top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-primary opacity-0 group-hover:opacity-100 transition-opacity"
          style={{ left: `${durationMs ? (currentMs / durationMs) * 100 : 0}%`, transform: 'translate(-50%, -50%)' }}
        />
      </div>

      <button onClick={onToggleMute} className="text-zinc-400 hover:text-white transition-colors">
        {muted ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
      </button>
    </div>
  );
}

// ÔöÇÔöÇ Preview panel ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function PreviewPanel({
  outputUrl,
  thumbnailUrl,
  width,
  height,
  status,
  onRender,
  rendering,
}: {
  outputUrl?: string;
  thumbnailUrl?: string;
  width: number;
  height: number;
  status: string;
  onRender: () => void;
  rendering: boolean;
}) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [playing, setPlaying] = useState(false);
  const [muted, setMuted] = useState(false);
  const [currentMs, setCurrentMs] = useState(0);
  const [durationMs, setDurationMs] = useState(0);

  const isPortrait = height > width;
  const maxH = isPortrait ? 'max-h-[380px]' : 'max-h-[340px]';

  useEffect(() => {
    const v = videoRef.current;
    if (!v) return;
    const onTime = () => setCurrentMs(v.currentTime * 1000);
    const onMeta = () => setDurationMs(v.duration * 1000);
    const onEnd  = () => setPlaying(false);
    v.addEventListener('timeupdate', onTime);
    v.addEventListener('loadedmetadata', onMeta);
    v.addEventListener('ended', onEnd);
    return () => {
      v.removeEventListener('timeupdate', onTime);
      v.removeEventListener('loadedmetadata', onMeta);
      v.removeEventListener('ended', onEnd);
    };
  }, [outputUrl]);

  const togglePlay = useCallback(() => {
    const v = videoRef.current;
    if (!v) return;
    if (playing) { v.pause(); setPlaying(false); }
    else { v.play(); setPlaying(true); }
  }, [playing]);

  const handleSeek = useCallback((ms: number) => {
    if (videoRef.current) videoRef.current.currentTime = ms / 1000;
    setCurrentMs(ms);
  }, []);

  return (
    <div className="flex flex-col h-full">
      <div className="flex-1 flex items-center justify-center bg-black/40 relative overflow-hidden">
        {outputUrl ? (
          <video
            ref={videoRef}
            src={outputUrl}
            poster={thumbnailUrl}
            muted={muted}
            className={`${maxH} w-auto max-w-full rounded-lg shadow-2xl`}
            onClick={togglePlay}
          />
        ) : (
          <div className="flex flex-col items-center gap-4 text-center px-8">
            {status === 'PROCESSING' ? (
              <>
                <div className="w-16 h-16 rounded-2xl bg-amber-500/10 border border-amber-500/20 flex items-center justify-center">
                  <Loader2 className="w-8 h-8 text-amber-400 animate-spin" />
                </div>
                <p className="text-zinc-400 text-sm">Rendering your videoÔÇª</p>
              </>
            ) : (
              <>
                <div className="w-16 h-16 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center">
                  <Clapperboard className="w-8 h-8 text-primary" />
                </div>
                <p className="text-zinc-300 font-semibold">No preview yet</p>
                <p className="text-zinc-500 text-sm">Add scenes and render to preview your video</p>
                <button
                  onClick={onRender}
                  disabled={rendering || status === 'PROCESSING'}
                  className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold disabled:opacity-40 transition-colors"
                >
                  {rendering ? <Loader2 className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4" />}
                  Render Video
                </button>
              </>
            )}
          </div>
        )}

        {/* Render button overlay when video exists */}
        {outputUrl && (
          <button
            onClick={onRender}
            disabled={rendering || status === 'PROCESSING'}
            className="absolute top-3 right-3 flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-black/60 hover:bg-black/80 text-white text-xs font-medium backdrop-blur-sm disabled:opacity-40 transition-colors"
          >
            {rendering ? <Loader2 className="w-3 h-3 animate-spin" /> : <RotateCcw className="w-3 h-3" />}
            Re-render
          </button>
        )}
      </div>

      {outputUrl && (
        <PlaybackBar
          playing={playing}
          muted={muted}
          currentMs={currentMs}
          durationMs={durationMs}
          onTogglePlay={togglePlay}
          onToggleMute={() => {
            setMuted(!muted);
            if (videoRef.current) videoRef.current.muted = !muted;
          }}
          onSeek={handleSeek}
        />
      )}
    </div>
  );
}

// ÔöÇÔöÇ Toast ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function Toast({ message, type }: { message: string; type: 'success' | 'error' }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 16, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      exit={{ opacity: 0, y: 8 }}
      className={`fixed bottom-6 right-6 z-50 flex items-center gap-2.5 px-4 py-3 rounded-xl shadow-2xl text-sm font-medium ${
        type === 'success'
          ? 'bg-emerald-500/10 border border-emerald-500/20 text-emerald-400'
          : 'bg-red-500/10 border border-red-500/20 text-red-400'
      }`}
    >
      {type === 'success' ? <CheckCircle2 className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
      {message}
    </motion.div>
  );
}

