                    showToast((e as Error).message, 'error');
                  }
                }}
                onDelete={async (id) => {
                  try {
                    await deleteAsset(id);
                    showToast('Asset deleted.');
                  } catch (e) {
                    showToast((e as Error).message, 'error');
                  }
                }}
              />
            )}
          </div>
        </div>

        {/* Center: Preview + Timeline */}
        <div className="flex-1 flex flex-col overflow-hidden">
          {/* Preview */}
          <div className="flex-1 min-h-0 overflow-hidden">
            <PreviewPanel
