    p.title.toLowerCase().includes(search.toLowerCase()),
  );

  const handleCreate = async (title: string, ratio: string) => {
    setCreating(true);
    try {
      const proj = await createProject(title, ratio);
      setShowNew(false);
      router.push(`/video/${proj.id}`);
    } catch (e) {
      console.error(e);
    } finally {
      setCreating(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0D0D0D] text-white">
      {/* Header */}
      <div className="border-b border-white/5">
        <div className="max-w-7xl mx-auto px-6 py-5 flex items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center">
              <Video className="w-5 h-5 text-primary" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-white">Video Studio</h1>
              <p className="text-xs text-zinc-500">AI-powered video creation</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            {/* Search */}
            <div className="relative hidden sm:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search projectsÔÇª"
                className="pl-9 pr-4 py-2 rounded-xl bg-white/5 border border-white/10 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary/30 transition-colors w-56"
              />
            </div>

            <button
              onClick={() => setShowNew(true)}
              className="flex items-center gap-2 px-4 py-2 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold transition-colors"
            >
              <Plus className="w-4 h-4" />
              New Project
            </button>
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="max-w-7xl mx-auto px-6 py-8">
        {loading ? (
          <div className="flex items-center justify-center h-64">
            <Loader2 className="w-8 h-8 text-primary animate-spin" />
          </div>
        ) : error ? (
          <div className="flex flex-col items-center justify-center h-64 text-center">
            <AlertCircle className="w-10 h-10 text-red-400 mb-3" />
            <p className="text-zinc-400">Failed to load projects</p>
            <p className="text-sm text-zinc-600 mt-1">{error}</p>
          </div>
        ) : filtered.length === 0 ? (
          <motion.div
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            className="flex flex-col items-center justify-center h-64 text-center"
          >
            <div className="w-16 h-16 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center mb-4">
              <Sparkles className="w-8 h-8 text-primary" />
            </div>
            <h2 className="text-xl font-bold text-white mb-2">
              {search ? 'No projects found' : 'Create your first video'}
            </h2>
            <p className="text-zinc-400 text-sm max-w-sm mb-6">
              {search
                ? `No projects match "${search}"`
                : 'Turn your script into a polished video in minutes with AI voiceovers, scenes, and subtitles.'}
            </p>
            {!search && (
              <button
                onClick={() => setShowNew(true)}
                className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold transition-colors"
              >
                <Plus className="w-4 h-4" /> New Project
              </button>
            )}
          </motion.div>
        ) : (
          <motion.div
            layout
            className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5"
          >
            <AnimatePresence mode="popLayout">
              {filtered.map((project) => (
                <ProjectCard
                  key={project.id}
                  project={project}
                  onOpen={() => router.push(`/video/${project.id}`)}
                  onDelete={() => deleteProject(project.id)}
                />
              ))}
            </AnimatePresence>
          </motion.div>
        )}
      </div>

      {/* New project modal */}
      <AnimatePresence>
        {showNew && (
          <NewProjectModal
            onClose={() => setShowNew(false)}
            onCreate={handleCreate}
          />
        )}
      </AnimatePresence>
    </div>
  );
}

/**
 * AI Service
 * Main orchestration layer with smart routing, caching, and cost tracking
 */

import { Injectable, Logger, BadRequestException, ServiceUnavailableException } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { OpenAIProvider } from './providers/openai.provider';
import { ClaudeProvider } from './providers/claude.provider';
import { LocalModelProvider } from './providers/local.provider';
import { AIUsageLimitService } from './services/ai-usage-limit.service';
import {
  AIRequest,
  AIResponse,
  ImageGenerationRequest,
  ImageGenerationResponse,
  AIProvider as AIProviderEnum,
  AIModel,
  AICapability,
  RoutingStrategy,
  CacheEntry,
  AIFinancialsData,
} from './types/ai.types';
import * as crypto from 'crypto';

type AIProviderInstance = OpenAIProvider | ClaudeProvider | LocalModelProvider;

@Injectable()
export class AIService {
  private readonly logger = new Logger(AIService.name);
  private providers: Map<AIProviderEnum, AIProviderInstance>;

  // Model configuration with capabilities
  private modelCapabilities: Map<AIModel, AICapability[]> = new Map([
    [
      AIModel.GPT_4_TURBO,
      [
        AICapability.TEXT_GENERATION,
        AICapability.CODE_GENERATION,
        AICapability.SUMMARIZATION,
      ],
    ],
    [
      AIModel.CLAUDE_3_OPUS,
      [
        AICapability.TEXT_GENERATION,
        AICapability.CODE_GENERATION,
        AICapability.SUMMARIZATION,
        AICapability.TRANSLATION,
      ],
    ],
    [
      AIModel.GPT_3_5_TURBO,
      [AICapability.TEXT_GENERATION, AICapability.SUMMARIZATION],
    ],
    [
      AIModel.OLLAMA_LLAMA2,
      [AICapability.TEXT_GENERATION, AICapability.CODE_GENERATION],
    ],
  ]);

  private modelCosts: Map<AIModel, { input: number; output: number }> = new Map([
    [AIModel.GPT_4_TURBO, { input: 0.01, output: 0.03 }],
    [AIModel.GPT_4, { input: 0.03, output: 0.06 }],
    [AIModel.GPT_3_5_TURBO, { input: 0.0015, output: 0.002 }],
    [AIModel.CLAUDE_3_OPUS, { input: 0.015, output: 0.075 }],
    [AIModel.CLAUDE_3_SONNET, { input: 0.003, output: 0.015 }],
    [AIModel.CLAUDE_3_HAIKU, { input: 0.00025, output: 0.00125 }],
    [AIModel.OLLAMA_LLAMA2, { input: 0, output: 0 }],
    [AIModel.OLLAMA_MISTRAL, { input: 0, output: 0 }],
  ]);

  // In-memory cache (in production, use Redis)
  private cache: Map<string, CacheEntry> = new Map();
  private readonly CACHE_TTL = 24 * 60 * 60 * 1000; // 24 hours

  constructor(
    private prisma: PrismaService,
    private openaiProvider: OpenAIProvider,
    private claudeProvider: ClaudeProvider,
    private localProvider: LocalModelProvider,
    private usageLimitService: AIUsageLimitService,
  ) {
    this.providers = new Map<AIProviderEnum, AIProviderInstance>([
      [AIProviderEnum.OPENAI, this.openaiProvider],
      [AIProviderEnum.CLAUDE, this.claudeProvider],
      [AIProviderEnum.LOCAL, this.localProvider],
    ]);
  }

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : 'Unknown error';
  }

  /**
   * Generate text with smart provider routing
   */
  async generateText(
    request: AIRequest,
    organizationId: string,
    userId: string,
    strategy: RoutingStrategy = { type: 'cheapest' },
    useCache = true,
  ): Promise<AIResponse> {
    try {
      // Estimate tokens for validation (4 chars = 1 token)
      const estimatedTokens = Math.ceil(request.prompt.length / 4) * 2; // 2x for safety

      // Check usage limits before generating
      await this.usageLimitService.validateUsageLimit(organizationId, userId, estimatedTokens);

      // Check cache first
      if (useCache) {
        const cached = this.getFromCache(request.prompt, request.model);
        if (cached) {
          this.logger.log(`Cache hit for prompt: ${request.prompt.substring(0, 30)}...`);
          cached.hits++;
          return { ...cached.response, cached: true };
        }
      }

      // Route to appropriate provider
      const selectedModel = request.model || (await this.selectBestModel(strategy, AICapability.TEXT_GENERATION));

      const provider = this.getProviderForModel(selectedModel);
      if (!provider) {
        throw new ServiceUnavailableException(
          `No provider available for model: ${selectedModel}`,
        );
      }

      // Generate response
      const response = await provider.generateText({
        ...request,
        model: selectedModel,
      });

      // Track usage
      await this.trackUsage(organizationId, userId, selectedModel, response);

      // Cache result
      if (useCache) {
        this.cacheResult(request.prompt, response);
      }

      this.logger.log(
        `Text generated via ${response.provider}: ${selectedModel} (Cost: $${response.cost.toFixed(4)})`,
      );

      return response;
    } catch (error) {
      this.logger.error(`Text generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Generate image with smart provider routing
   */
  async generateImage(
    request: ImageGenerationRequest,
    organizationId: string,
    userId: string,
    _strategy: RoutingStrategy = { type: 'cheapest' },
  ): Promise<ImageGenerationResponse> {
    try {
      // Estimate tokens for image generation (each image ~500 tokens)
      const estimatedTokens = (request.quantity || 1) * 500;

      // Check usage limits before generating
      await this.usageLimitService.validateUsageLimit(organizationId, userId, estimatedTokens);

      // Only OpenAI supports image generation for now
      const provider = this.providers.get(AIProviderEnum.OPENAI);
      if (!provider || !provider.isAvailable) {
        throw new ServiceUnavailableException(
          'Image generation provider not available',
        );
      }

      const response = await provider.generateImage(request);

      // Track usage
      await this.trackImageUsage(organizationId, userId, response);

      this.logger.log(
        `Image generated: ${request.prompt.substring(0, 30)}... (Cost: $${response.cost.toFixed(4)})`,
      );

      return response;
    } catch (error) {
      this.logger.error(`Image generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Smart model selection based on strategy
   */
  private async selectBestModel(
    strategy: RoutingStrategy,
    capability: AICapability,
  ): Promise<AIModel> {
    const availableModels = Array.from(this.modelCapabilities.entries())
      .filter(([_, caps]) => caps.includes(capability))
      .map(([model, _]) => model);

    if (availableModels.length === 0) {
      throw new BadRequestException(
        `No models available for capability: ${capability}`,
      );
    }

    switch (strategy.type) {
      case 'cheapest':
        return this.selectCheapestModel(availableModels, strategy);

      case 'fastest':
        return this.selectFastestModel(availableModels);

      case 'best_quality':
        return this.selectBestQualityModel(availableModels);

      case 'balanced':
        // Balance cost, speed, and quality
        return availableModels[0]; // Default to first available

      case 'custom':
        return this.selectCustomModel(availableModels, strategy);

      default:
        return availableModels[0];
    }
  }

  private selectCheapestModel(
    models: AIModel[],
    strategy: RoutingStrategy,
  ): AIModel {
    let cheapest = models[0];
    let lowestCost = Infinity;

    for (const model of models) {
      const cost = this.modelCosts.get(model)?.input || Infinity;
      const isBelowMax =
        !strategy.preferences?.maxCostPerRequest ||
        cost <= strategy.preferences.maxCostPerRequest;

      if (isBelowMax && cost < lowestCost) {
        lowestCost = cost;
        cheapest = model;
      }
    }

    return cheapest;
  }

  private selectFastestModel(
    models: AIModel[],
  ): AIModel {
    // GPT-3.5 is typically faster than GPT-4
    if (models.includes(AIModel.GPT_3_5_TURBO)) {
      return AIModel.GPT_3_5_TURBO;
    }
    if (models.includes(AIModel.CLAUDE_3_HAIKU)) {
      return AIModel.CLAUDE_3_HAIKU;
    }
    return models[0];
  }

  private selectBestQualityModel(
    models: AIModel[],
  ): AIModel {
    // GPT-4 and Claude Opus have best quality
    if (models.includes(AIModel.GPT_4_TURBO)) {
      return AIModel.GPT_4_TURBO;
    }
    if (models.includes(AIModel.CLAUDE_3_OPUS)) {
      return AIModel.CLAUDE_3_OPUS;
    }
    return models[0];
  }

  private selectCustomModel(
    models: AIModel[],
    strategy: RoutingStrategy,
  ): AIModel {
    const prefs = strategy.preferences;
    if (!prefs) return models[0];

    // Filter by preferred providers
    if (prefs.preferredProviders && prefs.preferredProviders.length > 0) {
      const filtered = models.filter(model => {
        const provider = this.getProviderForModel(model);
        return provider
          ? provider.name
              .toLowerCase()
              .includes(prefs.preferredProviders![0].toLowerCase())
          : false;
      });
      if (filtered.length > 0) {
        return filtered[0];
      }
    }

    return models[0];
  }

  /**
   * Get provider instance for model
   */
  private getProviderForModel(model: AIModel): AIProviderInstance | null {
    if (
      [
        AIModel.GPT_4_TURBO,
        AIModel.GPT_4,
        AIModel.GPT_3_5_TURBO,
        AIModel.GPT_3_5,
      ].includes(model)
    ) {
      return this.providers.get(AIProviderEnum.OPENAI) ?? null;
    }
    if (
      [
        AIModel.CLAUDE_3_OPUS,
        AIModel.CLAUDE_3_SONNET,
        AIModel.CLAUDE_3_HAIKU,
      ].includes(model)
    ) {
      return this.providers.get(AIProviderEnum.CLAUDE) ?? null;
    }
    if ([AIModel.OLLAMA_LLAMA2, AIModel.OLLAMA_MISTRAL].includes(model)) {
      return this.providers.get(AIProviderEnum.LOCAL) ?? null;
    }
    return null;
  }

  /**
   * Cache result in memory (should use Redis in production)
   */
  private cacheResult(prompt: string, response: AIResponse): void {
    const hash = this.hashPrompt(prompt);
    const entry: CacheEntry = {
      id: this.hashPrompt(prompt),
      hash,
      prompt,
      model: response.model,
      provider: response.provider,
      response,
      expiresAt: new Date(Date.now() + this.CACHE_TTL),
      hits: 0,
      size: JSON.stringify(response).length,
      createdAt: new Date(),
    };

    this.cache.set(hash, entry);
  }

  /**
   * Get from cache
   */
  private getFromCache(prompt: string, model: AIModel): CacheEntry | null {
    const hash = this.hashPrompt(prompt);
    const entry = this.cache.get(hash);

    if (!entry) return null;
    if (entry.expiresAt < new Date()) {
      this.cache.delete(hash);
      return null;
    }
    if (entry.model !== model) return null;

    return entry;
  }

  /**
   * Hash prompt for cache key
   */
  private hashPrompt(prompt: string): string {
    return crypto.createHash('sha256').update(prompt).digest('hex');
  }

  /**
   * Track usage and costs
   */
  private async trackUsage(organizationId: string, userId: string, model: AIModel, response: AIResponse): Promise<void> {
    try {
      const costs = this.modelCosts.get(model);
      if (!costs) return;

      // Store in database
      await this.prisma.aIUsage.create({
        data: {
          organizationId,
          userId,
          model: model.toString(),
          provider: response.provider.toString(),
          inputTokens: response.tokens.prompt,
          outputTokens: response.tokens.completion,
          totalTokens: response.tokens.total,
          cost: response.cost,
          usedCache: response.cached,
          contentType: 'text_generation',
          success: true,
        },
      });
    } catch (error) {
      this.logger.error(`Failed to track usage: ${this.getErrorMessage(error)}`);
    }
  }

  private async trackImageUsage(organizationId: string, userId: string, response: ImageGenerationResponse): Promise<void> {
    try {
      await this.prisma.aIUsage.create({
        data: {
          organizationId,
          userId,
          model: response.model.toString(),
          provider: response.provider.toString(),
          inputTokens: 0,
          outputTokens: 0,
          totalTokens: response.urls.length * 500,
          cost: response.cost,
          usedCache: false,
          contentType: 'image_generation',
          success: true,
        },
      });
    } catch (error) {
      this.logger.error(`Failed to track image usage: ${this.getErrorMessage(error)}`);
    }
  }

  /**
   * Get user's AI usage stats
   */
  async getUserStats(userId: string) {
    try {
      const stats = await this.prisma.aIUsage.findMany({
        where: { userId },
        orderBy: { createdAt: 'desc' },
        take: 100,
      });

      const summary = {
        totalRequests: stats.length,
        totalCost: stats.reduce((sum, s) => sum + s.cost, 0),
        totalTokens: stats.reduce((sum, s) => sum + s.totalTokens, 0),
        totalCached: stats.filter(s => s.usedCache).length,
        byModel: this.groupBy(stats, 'model'),
        byProvider: this.groupBy(stats, 'provider'),
        lastUsedAt: stats[0]?.createdAt,
      };

      return summary;
    } catch (error) {
      this.logger.error(`Failed to get user stats: ${this.getErrorMessage(error)}`);
      return null;
    }
  }

  private groupBy(items: any[], key: string) {
    return items.reduce(
      (result, item) => {
        const group = item[key];
        if (!result[group]) {
          result[group] = { count: 0, cost: 0, tokens: 0 };
        }
        result[group].count++;
        result[group].cost += item.cost || 0;
        result[group].tokens += item.totalTokens || 0;
        return result;
      },
      {} as Record<string, any>,
    );
  }

  /**
   * Validate all providers
   */
  async validateProviders(): Promise<Record<string, boolean>> {
    const results: Record<string, boolean> = {};

    for (const [name, provider] of this.providers) {
      try {
        results[name] = await provider.validateCredentials();
      } catch {
        results[name] = false;
      }
    }

    return results;
  }

  /**
   * Get cache statistics
   */
  getCacheStats() {
    let totalSize = 0;
    let totalHits = 0;

    for (const entry of this.cache.values()) {
      totalSize += entry.size;
      totalHits += entry.hits;
    }

    return {
      entries: this.cache.size,
      totalSize: totalSize,
      totalHits: totalHits,
      avgSize: this.cache.size > 0 ? totalSize / this.cache.size : 0,
    };
  }

  /**
   * Clear expired cache entries
   */
  clearExpiredCache(): number {
    let cleared = 0;
    const now = new Date();

    for (const [hash, entry] of this.cache) {
      if (entry.expiresAt < now) {
        this.cache.delete(hash);
        cleared++;
      }
    }

    this.logger.log(`Cleared ${cleared} expired cache entries`);
    return cleared;
  }
}

/**
 * Base AI Provider Interface
 * Abstract base for all provider implementations
 */

import { AIRequest, AIResponse, ImageGenerationRequest, ImageGenerationResponse, AIModel, AICapability } from '../types/ai.types';

export abstract class BaseAIProvider {
  abstract name: string;
  abstract isAvailable: boolean;

  abstract generateText(request: AIRequest): Promise<AIResponse>;
  abstract generateImage(request: ImageGenerationRequest): Promise<ImageGenerationResponse>;
  abstract getTokenCount(text: string): Promise<number>;
  abstract getAvailableModels(): AIModel[];
  abstract validateCredentials(): Promise<boolean>;

  protected generateId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  protected calculateCost(
    inputTokens: number,
    outputTokens: number,
    costPerInput: number,
    costPerOutput?: number,
  ): number {
    const inputCost = (inputTokens / 1000) * costPerInput;
    const outputCost = outputTokens && costPerOutput 
      ? (outputTokens / 1000) * costPerOutput 
      : 0;
    return inputCost + outputCost;
  }
}

/**
 * Claude Provider Implementation
 * Handles integration with Anthropic's Claude API
 */

import { Injectable, Logger } from '@nestjs/common';
import axios from 'axios';
import { BaseAIProvider } from './base.provider';
import {
  AIRequest,
  AIResponse,
  ImageGenerationRequest,
  ImageGenerationResponse,
  AIModel,
  AIProvider as AIProviderEnum,
} from '../types/ai.types';

@Injectable()
export class ClaudeProvider extends BaseAIProvider {
  name = 'Claude';
  isAvailable = true;
  private readonly logger = new Logger(ClaudeProvider.name);
  private readonly apiKey = process.env.ANTHROPIC_API_KEY;
  private readonly baseUrl = 'https://api.anthropic.com/v1';

  // Model configurations with costs (per 1k tokens)
  private modelConfigs: Partial<Record<AIModel, { inputCost: number; outputCost: number }>> = {
    [AIModel.CLAUDE_3_OPUS]: { inputCost: 0.015, outputCost: 0.075 },
    [AIModel.CLAUDE_3_SONNET]: { inputCost: 0.003, outputCost: 0.015 },
    [AIModel.CLAUDE_3_HAIKU]: { inputCost: 0.00025, outputCost: 0.00125 },
  };

  async generateText(request: AIRequest): Promise<AIResponse> {
    try {
      this.logger.log(`Generating text with Claude model: ${request.model}`);

      const response = await axios.post(
        `${this.baseUrl}/messages`,
        {
          model: request.model,
          max_tokens: request.maxTokens || 1000,
          messages: [{ role: 'user', content: request.prompt }],
          temperature: request.temperature ?? 0.7,
          top_p: request.topP ?? 1,
        },
        {
          headers: {
            'x-api-key': this.apiKey,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json',
          },
        },
      );

      const { content, usage } = response.data;
      const config =
        this.modelConfigs[request.model as AIModel] ??
        this.modelConfigs[AIModel.CLAUDE_3_SONNET]!;

      const cost = this.calculateCost(
        usage.input_tokens,
        usage.output_tokens,
        config.inputCost,
        config.outputCost,
      );

      return {
        id: this.generateId(),
        text: content[0].text,
        model: request.model as AIModel,
        provider: AIProviderEnum.CLAUDE,
        tokens: {
          prompt: usage.input_tokens,
          completion: usage.output_tokens,
          total: usage.input_tokens + usage.output_tokens,
        },
        cost,
        cached: false,
        generatedAt: new Date(),
      };
    } catch (error) {
      this.logger.error(`Claude text generation failed: ${error.message}`);
      throw error;
    }
  }

  async generateImage(request: ImageGenerationRequest): Promise<ImageGenerationResponse> {
    // Claude doesn't natively support image generation
    // This would need to be delegated to another provider
    throw new Error('Claude does not support image generation. Use OpenAI or another provider.');
  }

  async getTokenCount(text: string): Promise<number> {
    try {
      // Using estimation: ~4 chars = 1 token for Claude as well
      return Math.ceil(text.length / 4);
    } catch (error) {
      this.logger.error(`Token count calculation failed: ${error.message}`);
      return Math.ceil(text.length / 4);
    }
  }

  getAvailableModels(): AIModel[] {
    return [AIModel.CLAUDE_3_OPUS, AIModel.CLAUDE_3_SONNET, AIModel.CLAUDE_3_HAIKU];
  }

  async validateCredentials(): Promise<boolean> {
    try {
      // Test with a simple request
      const response = await axios.post(
        `${this.baseUrl}/messages`,
        {
          model: AIModel.CLAUDE_3_HAIKU,
          max_tokens: 10,
          messages: [{ role: 'user', content: 'test' }],
        },
        {
          headers: {
            'x-api-key': this.apiKey,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json',
          },
          timeout: 5000,
        },
      );

      this.isAvailable = response.status === 200;
      return this.isAvailable;
    } catch (error) {
      this.logger.warn(`Claude credentials validation failed: ${error.message}`);
      this.isAvailable = false;
      return false;
    }
  }
}

/**
 * Local Model Provider Implementation (Ollama)
 * Handles integration with local models via Ollama
 */

import { Injectable, Logger } from '@nestjs/common';
import axios from 'axios';
import { BaseAIProvider } from './base.provider';
import {
  AIRequest,
  AIResponse,
  ImageGenerationRequest,
  ImageGenerationResponse,
  AIModel,
  AIProvider as AIProviderEnum,
} from '../types/ai.types';

@Injectable()
export class LocalModelProvider extends BaseAIProvider {
  name = 'Local (Ollama)';
  isAvailable = true;
  private readonly logger = new Logger(LocalModelProvider.name);
  private readonly baseUrl = process.env.OLLAMA_BASE_URL || 'http://localhost:11434';

  // Local models have $0 cost
  private modelConfigs = {
    [AIModel.OLLAMA_LLAMA2]: { inputCost: 0, outputCost: 0 },
    [AIModel.OLLAMA_MISTRAL]: { inputCost: 0, outputCost: 0 },
  };

  async generateText(request: AIRequest): Promise<AIResponse> {
    try {
      this.logger.log(`Generating text with local model: ${request.model}`);

      const response = await axios.post(
        `${this.baseUrl}/api/generate`,
        {
          model: request.model.replace('ollama:', ''),
          prompt: request.prompt,
          stream: false,
          temperature: request.temperature ?? 0.7,
          top_p: request.topP ?? 1,
        },
        { timeout: 60000 }, // Local models might take longer
      );

      const { response: text, eval_count, prompt_eval_count } = response.data;

      const cost = this.calculateCost(
        prompt_eval_count || 0,
        eval_count || 0,
        0,
        0,
      );

      return {
        id: this.generateId(),
        text: text.trim(),
        model: request.model,
        provider: AIProviderEnum.LOCAL,
        tokens: {
          prompt: prompt_eval_count || 0,
          completion: eval_count || 0,
          total: (prompt_eval_count || 0) + (eval_count || 0),
        },
        cost,
        cached: false,
        generatedAt: new Date(),
      };
    } catch (error) {
      this.logger.error(`Local model generation failed: ${error.message}`);
      throw error;
    }
  }

  async generateImage(request: ImageGenerationRequest): Promise<ImageGenerationResponse> {
    // Local models typically don't support image generation
    throw new Error('Local models do not support image generation. Use OpenAI or another provider.');
  }

  async getTokenCount(text: string): Promise<number> {
    try {
      // For local models, use estimation
      return Math.ceil(text.length / 4);
    } catch (error) {
      this.logger.error(`Token count calculation failed: ${error.message}`);
      return Math.ceil(text.length / 4);
    }
  }

  getAvailableModels(): AIModel[] {
    return [AIModel.OLLAMA_LLAMA2, AIModel.OLLAMA_MISTRAL];
  }

  async validateCredentials(): Promise<boolean> {
    try {
      const response = await axios.get(`${this.baseUrl}/api/tags`, { timeout: 5000 });
      this.isAvailable = response.status === 200;
      return this.isAvailable;
    } catch (error) {
      this.logger.warn(`Local model validation failed: ${error.message}`);
      this.isAvailable = false;
      return false;
    }
  }

  /**
   * Pull a model from Ollama registry
   */
  async pullModel(modelName: string): Promise<void> {
    try {
      await axios.post(
        `${this.baseUrl}/api/pull`,
        { name: modelName },
        { timeout: 300000 }, // Can take a while to download
      );
      this.logger.log(`Model pulled successfully: ${modelName}`);
    } catch (error) {
      this.logger.error(`Failed to pull model: ${error.message}`);
      throw error;
    }
  }
}

/**
 * OpenAI Provider Implementation
 * Handles integration with OpenAI's API (GPT-4, GPT-3.5)
 */

import { Injectable, Logger } from '@nestjs/common';
import axios from 'axios';
import { BaseAIProvider } from './base.provider';
import {
  AIRequest,
  AIResponse,
  ImageGenerationRequest,
  ImageGenerationResponse,
  AIModel,
  AIProvider as AIProviderEnum,
  AICapability,
} from '../types/ai.types';

@Injectable()
export class OpenAIProvider extends BaseAIProvider {
  name = 'OpenAI';
  isAvailable = true;
  private readonly logger = new Logger(OpenAIProvider.name);
  private readonly apiKey = process.env.OPENAI_API_KEY;
  private readonly baseUrl = 'https://api.openai.com/v1';

  // Model configurations with costs (per 1k tokens)
  private modelConfigs: Partial<Record<AIModel, { inputCost: number; outputCost: number }>> = {
    [AIModel.GPT_4_TURBO]: { inputCost: 0.01, outputCost: 0.03 },
    [AIModel.GPT_4]: { inputCost: 0.03, outputCost: 0.06 },
    [AIModel.GPT_3_5_TURBO]: { inputCost: 0.0015, outputCost: 0.002 },
    [AIModel.GPT_3_5]: { inputCost: 0.0015, outputCost: 0.002 },
  };

  async generateText(request: AIRequest): Promise<AIResponse> {
    try {
      this.logger.log(`Generating text with OpenAI model: ${request.model}`);

      const response = await axios.post(
        `${this.baseUrl}/chat/completions`,
        {
          model: request.model,
          messages: [{ role: 'user', content: request.prompt }],
          max_tokens: request.maxTokens || 1000,
          temperature: request.temperature ?? 0.7,
          top_p: request.topP ?? 1,
          frequency_penalty: request.frequencyPenalty ?? 0,
          presence_penalty: request.presencePenalty ?? 0,
          stop: request.stop,
        },
        {
          headers: {
            Authorization: `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
        },
      );

      const { choices, usage } = response.data;
      const config =
        this.modelConfigs[request.model as AIModel] ??
        this.modelConfigs[AIModel.GPT_4_TURBO]!;

      const cost = this.calculateCost(
        usage.prompt_tokens,
        usage.completion_tokens,
        config.inputCost,
        config.outputCost,
      );

      return {
        id: this.generateId(),
        text: choices[0].message.content,
        model: request.model as AIModel,
        provider: AIProviderEnum.OPENAI,
        tokens: {
          prompt: usage.prompt_tokens,
          completion: usage.completion_tokens,
          total: usage.total_tokens,
        },
        cost,
        cached: false,
        generatedAt: new Date(),
      };
    } catch (error) {
      this.logger.error(`OpenAI text generation failed: ${error.message}`);
      throw error;
    }
  }

  async generateImage(request: ImageGenerationRequest): Promise<ImageGenerationResponse> {
    try {
      this.logger.log(`Generating image with OpenAI: ${request.prompt.substring(0, 50)}...`);

      const response = await axios.post(
        `${this.baseUrl}/images/generations`,
        {
          prompt: request.prompt,
          model: request.model || 'dall-e-3',
          n: request.quantity || 1,
          size: request.size || '1024x1024',
          quality: request.quality || 'standard',
        },
        {
          headers: {
            Authorization: `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
        },
      );

      // OpenAI DALL-E pricing: $0.04 for 1024x1024
      const cost = (request.quantity || 1) * 0.04;

      return {
        id: this.generateId(),
        urls: response.data.data.map((img: any) => img.url),
        model: request.model,
        provider: AIProviderEnum.OPENAI,
        cost,
        generatedAt: new Date(),
      };
    } catch (error) {
      this.logger.error(`OpenAI image generation failed: ${error.message}`);
      throw error;
    }
  }

  async getTokenCount(text: string): Promise<number> {
    try {
      // Using a simple estimation: ~4 chars = 1 token
      // For accurate counting, you'd need to use OpenAI's tokenizer library
      return Math.ceil(text.length / 4);
    } catch (error) {
      this.logger.error(`Token count calculation failed: ${error.message}`);
      return Math.ceil(text.length / 4);
    }
  }

  getAvailableModels(): AIModel[] {
    return [AIModel.GPT_4_TURBO, AIModel.GPT_4, AIModel.GPT_3_5_TURBO, AIModel.GPT_3_5];
  }

  async validateCredentials(): Promise<boolean> {
    try {
      const response = await axios.get(`${this.baseUrl}/models`, {
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
        },
        timeout: 5000,
      });

      this.isAvailable = response.status === 200;
      return this.isAvailable;
    } catch (error) {
      this.logger.warn(`OpenAI credentials validation failed: ${error.message}`);
      this.isAvailable = false;
      return false;
    }
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '../../database/prisma.service';
import * as crypto from 'crypto';

export interface AIMetrics {
  requestId: string;
  organizationId: string;
  userId: string;
  model: string;
  provider: string;
  contentType: string;
  inputTokens: number;
  outputTokens: number;
  totalTokens: number;
  cost: number;
  cacheUsed: boolean;
  responseTime: number;
  success: boolean;
  errorMessage?: string;
  timestamp: Date;
}

export interface AIAlert {
  level: 'info' | 'warning' | 'error' | 'critical';
  title: string;
  message: string;
  organizationId: string;
  userId?: string;
  metadata?: Record<string, any>;
  timestamp: Date;
}

@Injectable()
export class AIMonitoringService {
  private readonly logger = new Logger(AIMonitoringService.name);

  constructor(private prisma: PrismaService) {}

  /**
   * Log AI generation metrics
   */
  async logMetrics(metrics: AIMetrics): Promise<void> {
    try {
      const duration = Date.now() - metrics.timestamp.getTime();

      this.logger.log(
        `[${metrics.model}] ${metrics.contentType} | ` +
          `Tokens: ${metrics.totalTokens} | ` +
          `Cost: $${metrics.cost.toFixed(4)} | ` +
          `Time: ${duration}ms | ` +
          `Cache: ${metrics.cacheUsed ? 'HIT' : 'MISS'}`,
      );

      // Alert on expensive operations
      if (metrics.cost > 1.0) {
        this.logAlert({
          level: 'warning',
          title: 'Expensive Generation',
          message: `Generation cost $${metrics.cost.toFixed(4)} using ${metrics.model}`,
          organizationId: metrics.organizationId,
          userId: metrics.userId,
          metadata: {
            model: metrics.model,
            tokens: metrics.totalTokens,
            cost: metrics.cost,
          },
          timestamp: new Date(),
        });
      }

      // Alert on slow operations
      if (metrics.responseTime > 30000) {
        this.logAlert({
          level: 'warning',
          title: 'Slow Generation',
          message: `Generation took ${(metrics.responseTime / 1000).toFixed(2)}s`,
          organizationId: metrics.organizationId,
          userId: metrics.userId,
          metadata: {
            responseTime: metrics.responseTime,
            model: metrics.model,
          },
          timestamp: new Date(),
        });
      }
    } catch (error) {
      this.logger.error(`Failed to log metrics: ${error.message}`);
    }
  }

  /**
   * Log alert or notification
   */
  async logAlert(alert: AIAlert): Promise<void> {
    try {
      this.logger.warn(
        `[${alert.level.toUpperCase()}] ${alert.title}: ${alert.message}`,
      );

      // Store in database for admin dashboard
      // This could be expanded with a dedicated Alerts table

      // Send to monitoring service (Sentry, DataDog, etc.)
      if (alert.level === 'critical' || alert.level === 'error') {
        this.sendToMonitoringService(alert);
      }
    } catch (error) {
      this.logger.error(`Failed to log alert: ${error.message}`);
    }
  }

  /**
   * Check for cost anomalies
   */
  async checkCostAnomalies(organizationId: string): Promise<void> {
    try {
      const now = new Date();
      const dayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

      // Get usage from last 24 hours
      const usage24h = await this.prisma.aIUsage.aggregate({
        where: {
          organizationId,
          createdAt: { gte: dayAgo },
        },
        _sum: { cost: true },
      });

      const cost24h = usage24h._sum.cost || 0;

      // Get average daily cost from last 30 days
      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      const usage30d = await this.prisma.aIUsage.aggregate({
        where: {
          organizationId,
          createdAt: { gte: thirtyDaysAgo },
        },
        _sum: { cost: true },
      });

      const avgDaily = (usage30d._sum.cost || 0) / 30;

      // Alert if today's usage is 3x above average
      if (cost24h > avgDaily * 3) {
        this.logAlert({
          level: 'warning',
          title: 'Unusual AI Spending',
          message: `Today's spending ($${cost24h.toFixed(2)}) is 3x above average ($${avgDaily.toFixed(2)}/day)`,
          organizationId,
          metadata: {
            cost24h,
            avgDaily,
            ratio: (cost24h / avgDaily).toFixed(1),
          },
          timestamp: now,
        });
      }
    } catch (error) {
      this.logger.error(`Failed to check cost anomalies: ${error.message}`);
    }
  }

  /**
   * Monitor provider health and availability
   */
  async monitorProviderHealth(): Promise<Map<string, boolean>> {
    const health = new Map<string, boolean>();

    try {
      // Check OpenAI
      try {
        const response = await fetch('https://api.openai.com/v1/models', {
          headers: {
            Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
          },
        });
        health.set('openai', response.ok);
      } catch (error) {
        health.set('openai', false);
      }

      // Check Anthropic
      try {
        const headers: Record<string, string> = {};
        if (process.env.ANTHROPIC_API_KEY) {
          headers['x-api-key'] = process.env.ANTHROPIC_API_KEY;
        }

        const response = await fetch('https://api.anthropic.com/v1/models', {
          headers,
        });
        health.set('anthropic', response.ok);
      } catch (error) {
        health.set('anthropic', false);
      }

      // Check Ollama
      try {
        const response = await fetch(
          `${process.env.OLLAMA_BASE_URL}/api/tags`,
        );
        health.set('ollama', response.ok);
      } catch (error) {
        health.set('ollama', false);
      }

      // Log alerts for down providers
      health.forEach((status, provider) => {
        if (!status) {
          this.logAlert({
            level: 'error',
            title: 'Provider Health Check Failed',
            message: `${provider} provider is not responding`,
            organizationId: 'system',
            metadata: { provider },
            timestamp: new Date(),
          });
        }
      });

      return health;
    } catch (error) {
      this.logger.error(`Failed to monitor provider health: ${error.message}`);
      return health;
    }
  }

  /**
   * Generate usage report
   */
  async generateUsageReport(organizationId: string, days: number = 30) {
    try {
      const startDate = new Date(Date.now() - days * 24 * 60 * 60 * 1000);

      const usageData = await this.prisma.aIUsage.findMany({
        where: {
          organizationId,
          createdAt: { gte: startDate },
        },
        select: {
          createdAt: true,
          model: true,
          provider: true,
          totalTokens: true,
          cost: true,
          contentType: true,
          success: true,
        },
      });

      // Aggregate by date
      const byDate = new Map<string, any>();
      usageData.forEach((record) => {
        const date = record.createdAt.toISOString().split('T')[0];
        if (!byDate.has(date)) {
          byDate.set(date, {
            requests: 0,
            tokens: 0,
            cost: 0,
            byModel: {},
            byContentType: {},
          });
        }

        const dayData = byDate.get(date);
        dayData.requests++;
        dayData.tokens += record.totalTokens;
        dayData.cost += record.cost;

        // Track by model
        if (!dayData.byModel[record.model]) {
          dayData.byModel[record.model] = {
            requests: 0,
            cost: 0,
          };
        }
        dayData.byModel[record.model].requests++;
        dayData.byModel[record.model].cost += record.cost;

        // Track by content type
        const contentType = record.contentType ?? 'unknown';
        if (!dayData.byContentType[contentType]) {
          dayData.byContentType[contentType] = {
            requests: 0,
            cost: 0,
          };
        }
        dayData.byContentType[contentType].requests++;
        dayData.byContentType[contentType].cost += record.cost;
      });

      return {
        organizationId,
        period: { days, startDate, endDate: new Date() },
        summary: {
          totalRequests: usageData.length,
          totalTokens: usageData.reduce((sum, r) => sum + r.totalTokens, 0),
          totalCost: usageData.reduce((sum, r) => sum + r.cost, 0),
          successRate:
            (usageData.filter((r) => r.success).length / usageData.length) *
            100,
        },
        byDate: Object.fromEntries(byDate),
      };
    } catch (error) {
      this.logger.error(`Failed to generate usage report: ${error.message}`);
      throw error;
    }
  }

  /**
   * Estimate costs for the month
   */
  async estimateMonthlySpending(
    organizationId: string,
  ): Promise<{ estimated: number; projected: number }> {
    try {
      const now = new Date();
      const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
      const daysIntoMonth = now.getDate();
      const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();

      const thisMonthUsage = await this.prisma.aIUsage.aggregate({
        where: {
          organizationId,
          createdAt: { gte: monthStart },
        },
        _sum: { cost: true },
      });

      const costSoFar = thisMonthUsage._sum.cost || 0;
      const dailyAverage = costSoFar / daysIntoMonth;
      const projected = dailyAverage * daysInMonth;

      return {
        estimated: costSoFar,
        projected: Math.ceil(projected * 100) / 100,
      };
    } catch (error) {
      this.logger.error(`Failed to estimate spending: ${error.message}`);
      return { estimated: 0, projected: 0 };
    }
  }

  /**
   * Send alert to external monitoring service
   */
  private sendToMonitoringService(alert: AIAlert): void {
    try {
      const sentryDsn = process.env.SENTRY_DSN;
      if (!sentryDsn) return;

      // Would integrate with Sentry or similar service
      // This is a placeholder for the actual implementation
      this.logger.debug(
        `Sending alert to monitoring service: ${alert.title}`,
      );
    } catch (error) {
      this.logger.error(
        `Failed to send alert to monitoring service: ${error.message}`,
      );
    }
  }

  /**
   * Generate request ID with hash
   */
  generateRequestId(): string {
    return crypto.randomUUID();
  }

  /**
   * Create hash of request for deduplication
   */
  hashRequest(prompt: string, model: string): string {
    return crypto
      .createHash('sha256')
      .update(`${prompt}:${model}`)
      .digest('hex');
  }
}

/**
 * Content Generation Services
 * Specialized services for different content types
 */

import { Injectable, Logger, BadRequestException } from '@nestjs/common';
import { AIService } from '../ai.service';
import { PromptTemplateService } from './prompt-template.service';
import { AIRequest, AIModel, ImageGenerationRequest, RoutingStrategy } from '../types/ai.types';

@Injectable()
export class ContentGenerationService {
  private readonly logger = new Logger(ContentGenerationService.name);

  constructor(
    private aiService: AIService,
    private promptService: PromptTemplateService,
  ) {}

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : 'Unknown error';
  }

  /**
   * Generate blog post
   */
  async generateBlogPost(
    organizationId: string,
    userId: string,
    options: {
      topic: string;
      tone?: string;
      audience?: string;
      wordCount?: number;
      keywords?: string;
      model?: AIModel;
      useCache?: boolean;
    },
  ) {
    try {
      const template = await this.promptService.getBuiltInTemplate('blog_post');
      if (!template) throw new BadRequestException('Template not found');

      const variables = {
        topic: options.topic,
        tone: options.tone || 'professional',
        audience: options.audience || 'general',
        wordCount: (options.wordCount || 2000).toString(),
        keywords: options.keywords || '',
      };

      const validation = this.promptService.validateTemplateVariables(
        template,
        variables,
      );
      if (!validation.valid) {
        throw new BadRequestException(
          `Missing variables: ${validation.missing.join(', ')}`,
        );
      }

      const prompt = this.promptService.renderTemplate(template.template, variables);

      const response = await this.aiService.generateText(
        {
          prompt,
          model: options.model || template.suggestedModel,
          temperature: template.defaultTemperature,
          maxTokens: 4000,
        },
        organizationId,
        userId,
        { type: 'cheapest' },
        options.useCache !== false,
      );

      return {
        content: response.text,
        metadata: {
          model: response.model,
          provider: response.provider,
          tokens: response.tokens,
          cost: response.cost,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Blog post generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Generate social media post
   */
  async generateSocialPost(
    organizationId: string,
    userId: string,
    options: {
      platform: 'twitter' | 'instagram' | 'linkedin' | 'facebook' | 'tiktok';
      topic: string;
      tone?: string;
      hashtags?: boolean;
      includeEmojis?: boolean;
      model?: AIModel;
    },
  ) {
    try {
      const template = await this.promptService.getBuiltInTemplate('social_post');
      if (!template) throw new BadRequestException('Template not found');

      const platformLimits: Record<string, number> = {
        twitter: 280,
        instagram: 2200,
        linkedin: 3000,
        facebook: 63206,
        tiktok: 2200,
      };

      const variables = {
        platform: options.platform,
        topic: options.topic,
        tone: options.tone || 'engaging',
        hashtags: options.hashtags ? 'yes' : 'no',
        includeEmojis: options.includeEmojis ? 'yes' : 'no',
        length: platformLimits[options.platform].toString(),
      };

      const prompt = this.promptService.renderTemplate(template.template, variables);

      const response = await this.aiService.generateText(
        {
          prompt,
          model: options.model || template.suggestedModel,
          temperature: 0.8,
          maxTokens: 500,
        },
        organizationId,
        userId,
        { type: 'cheapest' },
        true,
      );

      return {
        content: response.text,
        platform: options.platform,
        metadata: {
          cost: response.cost,
          tokens: response.tokens,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Social post generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Generate video script
   */
  async generateVideoScript(
    organizationId: string,
    userId: string,
    options: {
      topic: string;
      videoDuration: number; // in seconds
      videoType: 'tutorial' | 'promotional' | 'educational' | 'comedy' | 'story';
      audience?: string;
      keyMessages?: string;
      cta?: string;
      model?: AIModel;
    },
  ) {
    try {
      const template = await this.promptService.getBuiltInTemplate('video_script');
      if (!template) throw new BadRequestException('Template not found');

      const variables = {
        videoDuration: options.videoDuration.toString(),
        videoType: options.videoType,
        topic: options.topic,
        audience: options.audience || 'general viewers',
        keyMessages: options.keyMessages || 'main points about the topic',
        cta: options.cta || 'Subscribe for more content',
      };

      const prompt = this.promptService.renderTemplate(template.template, variables);

      // Longer timeout for video scripts
      const response = await this.aiService.generateText(
        {
          prompt,
          model: options.model || template.suggestedModel,
          temperature: template.defaultTemperature,
          maxTokens: 3000,
        },
        organizationId,
        userId,
        { type: 'best_quality' },
        true,
      );

      return {
        script: response.text,
        duration: options.videoDuration,
        type: options.videoType,
        metadata: {
          model: response.model,
          cost: response.cost,
          tokens: response.tokens,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Video script generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Generate ad copy
   */
  async generateAdCopy(
    organizationId: string,
    userId: string,
    options: {
      product: string;
      audience?: string;
      benefits?: string;
      cta?: string;
      tone?: string;
      medium: 'google' | 'facebook' | 'linkedin' | 'instagram' | 'email';
      quantity?: number;
      model?: AIModel;
    },
  ) {
    try {
      const template = await this.promptService.getBuiltInTemplate('ad_copy');
      if (!template) throw new BadRequestException('Template not found');

      const variables = {
        medium: options.medium,
        product: options.product,
        audience: options.audience || 'target customers',
        benefits: options.benefits || 'key benefits',
        cta: options.cta || 'Buy Now',
        tone: options.tone || 'persuasive',
      };

      const prompt = this.promptService.renderTemplate(template.template, variables);
      const quantity = options.quantity || 1;
      const fullPrompt =
        quantity > 1
          ? `${prompt}\n\nGenerate ${quantity} different variations of ad copy.`
          : prompt;

      const response = await this.aiService.generateText(
        {
          prompt: fullPrompt,
          model: options.model || template.suggestedModel,
          temperature: 0.8,
          maxTokens: 2000,
        },
        organizationId,
        userId,
        { type: 'best_quality' },
        true,
      );

      return {
        copies: this.parseAdCopies(response.text, quantity),
        product: options.product,
        medium: options.medium,
        metadata: {
          count: quantity,
          cost: response.cost,
          tokens: response.tokens,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Ad copy generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

