      return {
        email: response.text,
        type: options.emailType,
        metadata: {
          cost: response.cost,
          tokens: response.tokens,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Email campaign generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Generate image
   */
  async generateImage(
    organizationId: string,
    userId: string,
    options: {
      prompt: string;
      size?: string;
      quantity?: number;
      style?: string;
      quality?: 'standard' | 'hd';
    },
  ) {
    try {
      const response = await this.aiService.generateImage(
        {
          prompt: options.prompt,
          model: AIModel.DALL_E_3,
          size: options.size || '1024x1024',
          quantity: options.quantity || 1,
          style: options.style,
          quality: options.quality || 'standard',
        },
        organizationId,
        userId,
        { type: 'best_quality' },
      );

      return {
        images: response.urls,
        prompt: options.prompt,
        metadata: {
          model: response.model,
          provider: response.provider,
          cost: response.cost,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Image generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  /**
   * Generate multiple headlines
   */
  async generateHeadlines(
    organizationId: string,
    userId: string,
    options: {
      contentType: string;
      topic: string;
      audience?: string;
      count?: number;
      model?: AIModel;
    },
  ) {
    try {
      const template = await this.promptService.getBuiltInTemplate('title_generator');
      if (!template) throw new BadRequestException('Template not found');

      const variables = {
        count: (options.count || 5).toString(),
        contentType: options.contentType,
        topic: options.topic,
        tone: 'compelling',
        audience: options.audience || 'general readers',
        angle: 'unique perspective',
      };

      const prompt = this.promptService.renderTemplate(template.template, variables);

      const response = await this.aiService.generateText(
        {
          prompt,
          model: options.model || template.suggestedModel,
          temperature: 0.9,
          maxTokens: 1000,
        },
        organizationId,
        userId,
        { type: 'cheapest' },
        true,
      );

      return {
        headlines: this.parseHeadlines(response.text),
        topic: options.topic,
        metadata: {
          cost: response.cost,
          tokens: response.tokens,
          generatedAt: response.generatedAt,
        },
      };
    } catch (error) {
      this.logger.error(`Headline generation failed: ${this.getErrorMessage(error)}`);
      throw error;
    }
  }

  // Helper functions
  private parseAdCopies(text: string, count: number): string[] {
    const lines = text
      .split('\n')
      .filter(line => line.trim().length > 0);
    return lines.slice(0, count);
  }

  private parseHeadlines(text: string): string[] {
    return text
      .split('\n')
      .filter(line => line.trim().length > 0)
      .map(line => line.replace(/^\d+\.\s*/, '').trim());
  }
}

