/**
 * Authentication Service (canonical)
 * Production-grade: login, register, 2FA, sessions, password, email verification.
 *
 * Flow summary
 * ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
 * Login:
 *   1. Rate-limit by (email, IP) ÔåÆ check LoginAttempt table
 *   2. Look up user, verify bcrypt password
 *   3. Check account status (BANNED ÔåÆ reject)
 *   4. If 2FA enabled ÔåÆ return { requiresTwoFactor: true, twoFactorToken }
 *   5. Otherwise ÔåÆ create Session, issue access + refresh tokens
 *
 * 2FA completion:
 *   1. Verify twoFactorToken (short-lived JWT with type='2fa_pending')
 *   2. Verify TOTP code or backup code
 *   3. Create Session, issue full tokens
 *
 * Refresh:
 *   1. Hash incoming refresh token ÔåÆ look up Session
 *   2. Check not revoked + not expired
 *   3. Revoke old session (rotation)
 *   4. Create new session, issue new token pair
 *
 * Logout:
 *   1. Revoke current session by sessionId (from JWT claim)
 */

import {
  Injectable,
  BadRequestException,
  UnauthorizedException,
  ConflictException,
  NotFoundException,
  HttpException,
  HttpStatus,
  Logger,
} from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { PasswordService } from './services/password.service';
import { JwtTokenService } from './services/jwt.service';
import { TwoFactorService } from './services/two-factor.service';
import { SessionService } from './services/session.service';
import { RegisterDto, LoginDto } from './dto/auth.dto';
// User shape ÔÇö matches Prisma model; replaced by @prisma/client after `prisma generate`
interface User {
  id: string;
  email: string;
  passwordHash: string;
  firstName: string | null;
  lastName: string | null;
  avatar: string | null;
  phoneNumber: string | null;
  timezone: string;
  preferredLanguage: string;
  status: string;
  lastLogin: Date | null;
  emailVerified: Date | null;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
}
import * as crypto from 'crypto';

// ÔöÇÔöÇÔöÇ Local types ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

interface TokenResponse {
  accessToken: string;
  refreshToken: string;
  expiresIn: number;  // seconds
}

interface AuthResponse extends TokenResponse {
  user: SafeUser;
}

interface TwoFactorPendingResponse {
  requiresTwoFactor: true;
  twoFactorToken: string;
  user: SafeUser;
}

type SafeUser = Omit<User, 'passwordHash'>;

interface RequestMeta {
  ipAddress?: string;
  userAgent?: string;
}

const MAX_LOGIN_ATTEMPTS = 5;
const LOGIN_WINDOW_MS    = 15 * 60 * 1000; // 15 min

// ÔöÇÔöÇÔöÇ Service ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

@Injectable()
export class AuthService {
  private readonly logger = new Logger(AuthService.name);

  constructor(
    private readonly prisma:        PrismaService,
    private readonly passwords:     PasswordService,
    private readonly jwt:           JwtTokenService,
    private readonly twoFactor:     TwoFactorService,
    private readonly sessions:      SessionService,
  ) {}

  // ÔöÇÔöÇ Registration ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async register(dto: RegisterDto, meta: RequestMeta = {}): Promise<AuthResponse> {
    const email = dto.email.toLowerCase().trim();

    const exists = await this.prisma.user.findUnique({ where: { email } });
    if (exists) throw new ConflictException('Email already registered');

    // Password strength
    const check = this.passwords.meetsRequirements(dto.password, [email, dto.firstName ?? '', dto.lastName ?? '']);
    if (!check.meets) {
      throw new BadRequestException({ message: 'Weak password', feedback: check.feedback });
    }

    const passwordHash = await this.passwords.hashPassword(dto.password);


    const { user, org } = await this.prisma.$transaction(async (tx: any) => {
      const newUser = await tx.user.create({
        data: {
          email,
          passwordHash,
          firstName: dto.firstName,
          lastName: dto.lastName,
          status: 'PENDING_VERIFICATION',
        },
      });

      const orgName  = dto.organizationName ?? `${dto.firstName ?? email.split('@')[0]}'s Workspace`;
      const orgSlug  = this.generateSlug(orgName);

      const newOrg = await tx.organization.create({
        data: {
          name: orgName,
          slug: orgSlug,
          email,
          status: 'ACTIVE',
          tier: 'FREE',
          isActive: true,
        },
      });

      // Admin role + full permissions
      const adminRole = await tx.role.create({
        data: { organizationId: newOrg.id, name: 'Admin', isSystem: true },
      });

      const defaultPerms = [
        'create:content', 'read:content', 'update:content', 'delete:content',
        'manage:users', 'manage:organization', 'manage:billing', 'manage:integrations',
        'manage:ai', 'manage:automation', 'read:analytics',
      ];

      await tx.permission.createMany({
        data: defaultPerms.map((p) => ({
          roleId: adminRole.id,
          action: p.split(':')[0],
          resource: p.split(':')[1],
        })),
      });

      // Viewer role (read-only)
      const viewerRole = await tx.role.create({
        data: { organizationId: newOrg.id, name: 'Viewer', isSystem: false },
      });
      await tx.permission.create({
        data: { roleId: viewerRole.id, action: 'read', resource: 'content' },
      });

      // Team Member role
      const memberRole = await tx.role.create({
        data: { organizationId: newOrg.id, name: 'Team Member', isSystem: false },
      });
      await tx.permission.createMany({
        data: [
          { roleId: memberRole.id, action: 'create', resource: 'content' },
          { roleId: memberRole.id, action: 'read', resource: 'content' },
          { roleId: memberRole.id, action: 'update', resource: 'content' },
        ],
      });

      await tx.organizationMember.create({
        data: {
          organizationId: newOrg.id,
          userId: newUser.id,
          roleId: adminRole.id,
          status: 'ACTIVE',
          roleName: 'Admin',
          permissions: defaultPerms,
        },
      });

      // Onboarding + rate-limit quotas via tenant service (created implicitly by TenantService)
      await tx.tenantOnboarding.create({
        data: { organizationId: newOrg.id },
      });

      await tx.tenantRateLimitQuota.create({
        data: {
          organizationId: newOrg.id,
          apiRequestsPerMinute: 60,
          apiRequestsPerHour: 5000,
          aiTokensPerDay: 100000,
        },
      });

      return { user: newUser, org: newOrg };
    });

    // Email verification token (fire-and-forget)
    await this.generateEmailVerificationToken(user.id, email).catch((err) =>
      this.logger.warn(`Email verification token creation failed: ${err.message}`),
    );

    await this.recordLoginAttempt(email, true, undefined, meta.ipAddress);

    const permissions = await this.getUserPermissions(user.id, org.id);
    return this.issueTokens(user, org.id, permissions, meta);
  }

  // ÔöÇÔöÇ Login ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async login(dto: LoginDto, meta: RequestMeta = {}): Promise<AuthResponse | TwoFactorPendingResponse> {
    const email = dto.email.toLowerCase().trim();

    // 1. Rate limiting by email+IP
    await this.enforceLoginRateLimit(email, meta.ipAddress ?? 'unknown');

    // 2. Find user
    const user = await this.prisma.user.findUnique({ where: { email } });

    if (!user) {
      await this.recordLoginAttempt(email, false, 'user_not_found', meta.ipAddress);
      throw new UnauthorizedException('Invalid credentials');
    }

    // 3. Check status before verifying password (still record attempt)
    if (user.status === 'BANNED') {
      await this.recordLoginAttempt(email, false, 'account_banned', meta.ipAddress);
      throw new UnauthorizedException('Account is disabled');
    }

    // 4. Verify password
    const valid = await this.passwords.comparePasswords(dto.password, user.passwordHash);
    if (!valid) {
      await this.recordLoginAttempt(email, false, 'invalid_password', meta.ipAddress);
      throw new UnauthorizedException('Invalid credentials');
    }

    await this.recordLoginAttempt(email, true, undefined, meta.ipAddress);

    // 5. 2FA gate
    const has2fa = await this.twoFactor.isTwoFactorEnabled(user.id);
    if (has2fa) {
      const twoFactorToken = this.jwt.generate2faPendingToken(user.id, user.email);
      return { requiresTwoFactor: true, twoFactorToken, user: this.sanitize(user) };
    }

    // 6. Load org + permissions
    const orgId = await this.getPrimaryOrgId(user.id);
    if (!orgId) throw new UnauthorizedException('User has no organization');

    const permissions = await this.getUserPermissions(user.id, orgId);
    await this.prisma.user.update({ where: { id: user.id }, data: { lastLogin: new Date() } });

    return this.issueTokens(user, orgId, permissions, meta);
  }

  // ÔöÇÔöÇ 2FA completion ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async completeTwoFactorLogin(
    twoFactorToken: string,
    code: string,
    meta: RequestMeta = {},
  ): Promise<AuthResponse> {
    // Verify the 2FA pending JWT
    let payload: { sub: string; email: string };
    try {
      payload = this.jwt.verifyAccessToken(twoFactorToken) as any;
    } catch {
      throw new UnauthorizedException('Invalid or expired 2FA token');
    }

    const user = await this.prisma.user.findUnique({ where: { id: payload.sub } });
    if (!user) throw new UnauthorizedException('User not found');

    // Accept TOTP code OR backup code
    const totpResult   = await this.twoFactor.verifyTOTPLogin(user.id, code);
    const backupResult = totpResult.verified
      ? totpResult
      : await this.twoFactor.verifyBackupCode(user.id, code);

    if (!backupResult.verified) {
      throw new UnauthorizedException('Invalid 2FA code');
    }

    const orgId = await this.getPrimaryOrgId(user.id);
    if (!orgId) throw new UnauthorizedException('User has no organization');

    const permissions = await this.getUserPermissions(user.id, orgId);
    await this.prisma.user.update({ where: { id: user.id }, data: { lastLogin: new Date() } });

    return this.issueTokens(user, orgId, permissions, meta);
  }

  // ÔöÇÔöÇ Token refresh (rotation) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async refreshToken(rawRefreshToken: string, meta: RequestMeta = {}): Promise<TokenResponse & { user?: SafeUser }> {
    // 1. Validate JWT signature + type (throws if invalid/expired)
    this.jwt.verifyRefreshToken(rawRefreshToken);

    // 2. Validate against Session (detects revoked / replayed tokens)
    const { userId, organizationId } = await this.sessions.validateAndConsumeRefreshToken(rawRefreshToken);

    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!user || user.status === 'BANNED') {
      throw new UnauthorizedException('User unavailable');
    }

    const permissions = await this.getUserPermissions(userId, organizationId);

    // 3. Issue new token pair + create new session (rotation)
    return this.issueTokens(user, organizationId, permissions, meta);
  }

  // ÔöÇÔöÇ Logout ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async logout(sessionId: string): Promise<void> {
    await this.sessions.revokeSession(sessionId, 'logout');
  }

  async logoutAll(userId: string): Promise<void> {
    await this.sessions.revokeAllSessions(userId, 'logout_all');
  }

  // ÔöÇÔöÇ Password management ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async requestPasswordReset(email: string): Promise<void> {
    const user = await this.prisma.user.findUnique({ where: { email: email.toLowerCase() } });
    // Silent no-op for non-existent emails (prevent enumeration)
    if (!user) return;

    // Invalidate previous tokens
    await this.prisma.passwordResetToken.updateMany({
      where: { userId: user.id, usedAt: null },
      data: { usedAt: new Date() },
    });

    const token     = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000);

    await this.prisma.passwordResetToken.create({
      data: { userId: user.id, token, expiresAt },
    });

    // TODO: inject EmailService and send email with link
    this.logger.log(`Password reset token issued for ${user.email} ÔÇö send to email`);
  }

  async resetPassword(token: string, newPassword: string): Promise<void> {
    const resetToken = await this.prisma.passwordResetToken.findUnique({ where: { token } });

    if (!resetToken || resetToken.usedAt || new Date() > resetToken.expiresAt) {
      throw new BadRequestException('Invalid or expired reset token');
    }

    const check = this.passwords.meetsRequirements(newPassword);
    if (!check.meets) {
      throw new BadRequestException({ message: 'Weak password', feedback: check.feedback });
    }

    const user = await this.prisma.user.findUnique({ where: { id: resetToken.userId } });
    if (!user) throw new NotFoundException('User not found');

    // Check password history (last 5)
    await this.assertNotPasswordHistory(user.id, newPassword);

    const hash = await this.passwords.hashPassword(newPassword);

    await this.prisma.$transaction([
      this.prisma.user.update({ where: { id: user.id }, data: { passwordHash: hash } }),
      this.prisma.passwordResetToken.update({
        where: { id: resetToken.id },
        data: { usedAt: new Date() },
      }),
      this.prisma.passwordHistory.create({ data: { userId: user.id, passwordHash: hash } }),
    ]);

    // Revoke all sessions for security
    await this.sessions.revokeAllSessions(user.id, 'password_reset');
    this.logger.log(`Password reset: ${user.email}`);
  }

  async changePassword(userId: string, oldPassword: string, newPassword: string): Promise<void> {
    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!user) throw new NotFoundException('User not found');

    const valid = await this.passwords.comparePasswords(oldPassword, user.passwordHash);
    if (!valid) throw new UnauthorizedException('Current password is incorrect');

    const check = this.passwords.meetsRequirements(newPassword, [user.email]);
    if (!check.meets) {
      throw new BadRequestException({ message: 'Weak password', feedback: check.feedback });
    }

    await this.assertNotPasswordHistory(user.id, newPassword);

    const hash = await this.passwords.hashPassword(newPassword);

    await this.prisma.$transaction([
      this.prisma.user.update({ where: { id: userId }, data: { passwordHash: hash } }),
      this.prisma.passwordHistory.create({ data: { userId, passwordHash: hash } }),
    ]);

    await this.sessions.revokeAllSessions(userId, 'password_change');
    this.logger.log(`Password changed: ${user.email}`);
  }

  // ÔöÇÔöÇ Email verification ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async sendEmailVerification(userId: string): Promise<void> {
    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!user) throw new NotFoundException('User not found');
    if (user.emailVerified) return; // already verified

    await this.generateEmailVerificationToken(user.id, user.email);
    this.logger.log(`Email verification resent for ${user.email}`);
  }

  async verifyEmail(token: string): Promise<void> {
    const record = await this.prisma.emailVerificationToken.findUnique({ where: { token } });

    if (!record || record.verifiedAt || new Date() > record.expiresAt) {
      throw new BadRequestException('Invalid or expired verification token');
    }

    await this.prisma.$transaction([
      this.prisma.user.update({
        where: { id: record.userId },
        data: { emailVerified: new Date(), status: 'ACTIVE' },
      }),
      this.prisma.emailVerificationToken.update({
        where: { id: record.id },
        data: { verifiedAt: new Date() },
      }),
    ]);

    this.logger.log(`Email verified for user ${record.userId}`);
  }

  // ÔöÇÔöÇ Session management (delegated) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async listSessions(userId: string, currentSessionId?: string) {
    return this.sessions.listActiveSessions(userId, currentSessionId);
  }

  async revokeSession(sessionId: string, requestingUserId: string): Promise<void> {
    const session = await this.prisma.session.findUnique({ where: { id: sessionId } });
    if (!session || session.userId !== requestingUserId) {
      throw new NotFoundException('Session not found');
    }
    await this.sessions.revokeSession(sessionId);
  }

  // ÔöÇÔöÇ Private helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async issueTokens(
    user: User,
    orgId: string,
    permissions: string[],
    meta: RequestMeta,
  ): Promise<AuthResponse> {
    const refreshExpiry = 7 * 24 * 60 * 60 * 1000;
    const expiresAt     = new Date(Date.now() + refreshExpiry);

    const tokens = this.jwt.generateTokenPair({ sub: user.id, email: user.email, orgId, permissions });

    const sessionId = await this.sessions.createSession({
      userId: user.id,
      organizationId: orgId,
      rawRefreshToken: tokens.refreshToken,
      expiresAt,
      ipAddress: meta.ipAddress,
      userAgent: meta.userAgent,
    });

    // Embed sessionId in access token (for logout without full token)
    const accessToken = this.jwt.generateAccessToken({
      sub: user.id, email: user.email, orgId, permissions, sessionId,
    });

    return {
      accessToken,
      refreshToken: tokens.refreshToken,
      expiresIn: 15 * 60,
      user: this.sanitize(user),
    };
  }

  private async getPrimaryOrgId(userId: string): Promise<string | null> {
    const member = await this.prisma.organizationMember.findFirst({
      where: { userId, status: 'ACTIVE' },
      orderBy: { joinedAt: 'asc' },
      select: { organizationId: true },
    });
    return member?.organizationId ?? null;
  }

  async getUserPermissions(userId: string, organizationId: string): Promise<string[]> {
    const member = await this.prisma.organizationMember.findUnique({
      where: { organizationId_userId: { organizationId, userId } },
      include: { role: { include: { permissions: true } } },
    });
    return member?.role?.permissions?.map((p: { action: string; resource: string }) => `${p.action}:${p.resource}`) ?? [];
  }

  private async enforceLoginRateLimit(email: string, ipAddress: string): Promise<void> {
    const windowStart = new Date(Date.now() - LOGIN_WINDOW_MS);
    const count = await this.prisma.loginAttempt.count({
      where: { email, ipAddress, success: false, timestamp: { gte: windowStart } },
    });
    if (count >= MAX_LOGIN_ATTEMPTS) {
      throw new HttpException(
        'Too many login attempts. Try again in 15 minutes.',
        HttpStatus.TOO_MANY_REQUESTS,
      );
    }
  }

  private async recordLoginAttempt(
    email: string,
    success: boolean,
    reason?: string,
    ipAddress?: string,
  ): Promise<void> {
    await this.prisma.loginAttempt
      .create({ data: { email, ipAddress: ipAddress ?? 'unknown', success, reason } })
      .catch((err: Error) => this.logger.warn(`Login attempt log failed: ${err.message}`));
  }

  private async generateEmailVerificationToken(userId: string, email: string): Promise<void> {
    const token     = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000);

    await this.prisma.emailVerificationToken.create({
      data: { userId, email, token, expiresAt },
    });
    // TODO: send email with link /auth/verify-email?token={token}
  }

  private async assertNotPasswordHistory(userId: string, newPassword: string): Promise<void> {
    const history = await this.prisma.passwordHistory.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      take: 5,
    });
    for (const h of history) {
      const reused = await this.passwords.comparePasswords(newPassword, h.passwordHash);
      if (reused) {
        throw new BadRequestException('Password was used recently. Choose a different password.');
      }
    }
  }

  private sanitize(user: User): SafeUser {
    const { passwordHash, ...safe } = user;
    return safe;
  }

  private generateSlug(name: string): string {
    const base = name.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '').substring(0, 60);
    return `${base}-${Date.now().toString(36)}`;
  }
}

/**
 * OAuth Service
 * Handles OAuth provider integration (Google, Apple, Facebook)
 */

import { Injectable, Logger, BadRequestException, ConflictException } from '@nestjs/common';
import { PrismaService } from '../../database/prisma.service';
import { JwtTokenService } from './jwt.service';
import { SessionService } from './session.service';
import { OAuthProvider, User } from '@prisma/client';

export interface OAuthProfile {
  id: string;
  email: string;
  displayName?: string;
  avatar?: string;
  provider: OAuthProvider;
  accessToken?: string;
  refreshToken?: string;
  expiresAt?: Date;
  ipAddress?: string;
  userAgent?: string;
}

export interface OAuthLoginResponse {
  accessToken: string;
  refreshToken: string;
  user: Partial<User>;
  isNewUser: boolean;
}

@Injectable()
export class OAuthService {
  private readonly logger = new Logger(OAuthService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly jwtService: JwtTokenService,
    private readonly sessions: SessionService,
  ) {}

  /**
   * Authenticate or create user via OAuth
   */
  async authenticateOAuth(profile: OAuthProfile): Promise<OAuthLoginResponse> {
    try {
      let user: User;
      let isNewUser = false;

      // Find by provider ID
      const existingOAuth = await this.prisma.oAuthAccount.findFirst({
        where: {
          provider: profile.provider,
          providerUserId: profile.id,
        },
        include: { user: true },
      });

      if (existingOAuth) {
        // OAuth account exists, update tokens
        user = existingOAuth.user;
        await this.prisma.oAuthAccount.update({
          where: { id: existingOAuth.id },
          data: {
            accessToken: profile.accessToken,
            refreshToken: profile.refreshToken,
            expiresAt: profile.expiresAt,
            displayName: profile.displayName,
            avatar: profile.avatar,
          },
        });
      } else {
        // Check if user exists by email
        const existingUser = await this.prisma.user.findUnique({
          where: { email: profile.email.toLowerCase() },
        });
        user = existingUser as User;

        if (user) {
          // User exists, create OAuth link
          await this.prisma.oAuthAccount.create({
            data: {
              userId: user.id,
              provider: profile.provider,
              providerUserId: profile.id,
              email: profile.email,
              displayName: profile.displayName,
              avatar: profile.avatar,
              accessToken: profile.accessToken,
              refreshToken: profile.refreshToken,
              expiresAt: profile.expiresAt,
            },
          });
        } else {
          // Create new user and OAuth link
          isNewUser = true;

          const newUser = await this.prisma.user.create({
            data: {
              email: profile.email.toLowerCase(),
              firstName: profile.displayName?.split(' ')[0],
              lastName: profile.displayName?.split(' ').slice(1).join(' '),
              avatar: profile.avatar,
              emailVerified: new Date(), // OAuth providers verify email
              status: 'ACTIVE',
              // Don't set passwordHash since this is OAuth-only account
              passwordHash: this.generatePlaceholderHash(),
            },
          });

          // Create OAuth link
          await this.prisma.oAuthAccount.create({
            data: {
              userId: newUser.id,
              provider: profile.provider,
              providerUserId: profile.id,
              email: profile.email,
              displayName: profile.displayName,
              avatar: profile.avatar,
              accessToken: profile.accessToken,
              refreshToken: profile.refreshToken,
              expiresAt: profile.expiresAt,
            },
          });

          user = newUser;
        }
      }

      // Update last login
      await this.prisma.user.update({
        where: { id: user.id },
        data: { lastLogin: new Date() },
      });

      // Load org + permissions
      const member = await this.prisma.organizationMember.findFirst({
        where: { userId: user.id, status: 'ACTIVE' },
        orderBy: { joinedAt: 'asc' },
        include: { role: { include: { permissions: true } } },
      });
      const orgId = member?.organizationId ?? '';
      const permissions = member?.role?.permissions?.map((p: { action: string; resource: string }) => `${p.action}:${p.resource}`) ?? [];

      // Create session + issue tokens
      const refreshExpiry = 7 * 24 * 60 * 60 * 1000;
      const expiresAt = new Date(Date.now() + refreshExpiry);
      const { refreshToken } = this.jwtService.generateTokenPair({ sub: user.id, email: user.email, orgId, permissions });

      const sessionId = await this.sessions.createSession({
        userId: user.id,
        organizationId: orgId,
        rawRefreshToken: refreshToken,
        expiresAt,
        ipAddress: profile.ipAddress,
        userAgent: profile.userAgent,
      });

      const accessToken = this.jwtService.generateAccessToken({
        sub: user.id, email: user.email, orgId, permissions, sessionId,
      });

      this.logger.log(`OAuth login: ${profile.provider} - ${user.email}`);

      return {
        accessToken,
        refreshToken,
        user: this.sanitizeUser(user),
        isNewUser,
      };
    } catch (error: unknown) {
      this.logger.error(`OAuth authentication failed: ${(error as Error).message}`, (error as Error).stack);
      throw error;
    }
  }

  /**
   * Link OAuth account to existing user
   */
  async linkOAuthAccount(userId: string, profile: OAuthProfile): Promise<void> {
    try {
      const user = await this.prisma.user.findUnique({
        where: { id: userId },
      });

      if (!user) {
        throw new BadRequestException('User not found');
      }

      // Check if OAuth account already linked
      const existing = await this.prisma.oAuthAccount.findFirst({
        where: {
          provider: profile.provider,
          providerUserId: profile.id,
        },
      });

      if (existing) {
        throw new ConflictException(`${profile.provider} account already linked`);
      }

      // Create OAuth link
      await this.prisma.oAuthAccount.create({
        data: {
          userId,
          provider: profile.provider,
          providerUserId: profile.id,
          email: profile.email,
          displayName: profile.displayName,
          avatar: profile.avatar,
          accessToken: profile.accessToken,
          refreshToken: profile.refreshToken,
          expiresAt: profile.expiresAt,
        },
      });

      this.logger.log(`OAuth account linked: ${profile.provider} - ${userId}`);
    } catch (error: unknown) {
      this.logger.error(`OAuth link failed: ${(error as Error).message}`, (error as Error).stack);
      throw error;
    }
  }

  /**
   * Unlink OAuth account
   */
  async unlinkOAuthAccount(userId: string, provider: OAuthProvider): Promise<void> {
    try {
      const user = await this.prisma.user.findUnique({
        where: { id: userId },
        include: { oauthAccounts: true },
      });

      if (!user) {
        throw new BadRequestException('User not found');
      }

      // Check if user has other auth methods
      const hasPassword = !!user.passwordHash || user.passwordHash !== this.generatePlaceholderHash();
      const otherOAuthAccounts = user.oauthAccounts.filter(oa => oa.provider !== provider);

      if (!hasPassword && otherOAuthAccounts.length === 0) {
        throw new BadRequestException(
          'Cannot unlink last authentication method. Set a password first.',
        );
      }

      // Delete OAuth account
      await this.prisma.oAuthAccount.deleteMany({
        where: {
          userId,
          provider,
        },
      });

      this.logger.log(`OAuth account unlinked: ${provider} - ${userId}`);
    } catch (error: unknown) {
      this.logger.error(`OAuth unlink failed: ${(error as Error).message}`, (error as Error).stack);
      throw error;
    }
  }

  /**
   * Get connected OAuth accounts for user
   */
  async getConnectedOAuthAccounts(userId: string) {
    try {
      const accounts = await this.prisma.oAuthAccount.findMany({
        where: { userId },
        select: {
          provider: true,
          displayName: true,
          avatar: true,
          email: true,
          createdAt: true,
        },
      });

      return accounts;
    } catch (error: unknown) {
      this.logger.error(`Failed to get OAuth accounts: ${(error as Error).message}`, (error as Error).stack);
      return [];
    }
  }

  /**
   * Refresh OAuth token
   */
  async refreshOAuthToken(userId: string, provider: OAuthProvider): Promise<string> {
    try {
      const oauthAccount = await this.prisma.oAuthAccount.findFirst({
        where: {
          userId,
          provider,
        },
      });

      if (!oauthAccount?.refreshToken) {
        throw new BadRequestException('No refresh token available');
      }

      // In production, call provider's token endpoint to refresh
      // For now, return existing accessToken
      return oauthAccount.accessToken ?? '';
    } catch (error: unknown) {
      this.logger.error(`OAuth token refresh failed: ${(error as Error).message}`, (error as Error).stack);
      throw error;
    }
  }

  /**
   * Generate placeholder hash for OAuth-only accounts
   */
  private generatePlaceholderHash(): string {
    return 'oauth_account'; // No password set
  }

  /**
   * Sanitize user object
   */
  private sanitizeUser(user: User): Partial<User> {
    const { passwordHash, ...sanitized } = user;
    return sanitized;
  }
}

import {
  ExecutionContext,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { AuthGuard as PassportAuthGuard } from '@nestjs/passport';

/**
 * JWT Authentication Guard
 * Validates JWT tokens on protected routes
 */
@Injectable()
export class JwtAuthGuard extends PassportAuthGuard('jwt') {
  canActivate(context: ExecutionContext) {
    return super.canActivate(context);
  }

  handleRequest<TUser = any>(
    err: any,
    user: TUser,
    _info: any,
    _context: ExecutionContext,
    _status?: any,
  ): TUser {
    if (err || !user) {
      throw err || new UnauthorizedException('Invalid or missing JWT token');
    }
    return user;
  }
}

import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  UseGuards,
  Query,
  HttpCode,
} from '@nestjs/common';
import { ContentService } from './content.service';
import { JwtAuthGuard } from '../common/guards/jwt.guard';
import { TenantGuard } from '../common/guards/tenant.guard';
import { CurrentUser } from '../common/decorators/user.decorator';
import { Tenant } from '../common/decorators/tenant.decorator';
import { CreateContentDto, UpdateContentDto } from './dto/content.dto';

@Controller('api/content')
@UseGuards(JwtAuthGuard)
export class ContentController {
  constructor(private contentService: ContentService) {}

  /**
   * POST /api/content
   * Create new content
   */
  @Post()
  async create(
    @Tenant() organizationId: string,
    @CurrentUser('sub') userId: string,
    @Body() createDto: CreateContentDto,
  ) {
    return this.contentService.createContent(organizationId, userId, createDto);
  }

  /**
   * GET /api/content
   * List content
   */
  @Get()
  async list(
    @Tenant() organizationId: string,
    @CurrentUser('sub') userId: string,
    @Query('page') page: number = 1,
    @Query('limit') limit: number = 10,
    @Query('status') status?: string,
    @Query('type') type?: string,
  ) {
    return this.contentService.listContent(organizationId, userId, page, limit, {
      status,
      type,
    });
  }

  /**
   * GET /api/content/:contentId
   * Get content by ID
   */
  @Get(':contentId')
  async get(
    @Tenant() organizationId: string,
    @Param('contentId') contentId: string,
  ) {
    return this.contentService.getContent(contentId, organizationId);
  }

  /**
   * PUT /api/content/:contentId
   * Update content
   */
  @Put(':contentId')
  async update(
    @Tenant() organizationId: string,
    @Param('contentId') contentId: string,
    @CurrentUser('sub') userId: string,
    @Body() updateDto: UpdateContentDto,
  ) {
    return this.contentService.updateContent(
      contentId,
      organizationId,
      userId,
      updateDto,
    );
  }

  /**
   * DELETE /api/content/:contentId
   * Delete content
   */
  @Delete(':contentId')
  @HttpCode(204)
  async delete(
    @Tenant() organizationId: string,
    @Param('contentId') contentId: string,
    @CurrentUser('sub') userId: string,
  ) {
    return this.contentService.deleteContent(contentId, organizationId, userId);
  }

  /**
   * POST /api/content/:contentId/publish
   * Publish content
   */
  @Post(':contentId/publish')
  @HttpCode(200)
  async publish(
    @Tenant() organizationId: string,
    @Param('contentId') contentId: string,
    @CurrentUser('sub') userId: string,
  ) {
    return this.contentService.publishContent(contentId, organizationId, userId);
  }

  /**
   * POST /api/content/:contentId/schedule
   * Schedule content
   */
  @Post(':contentId/schedule')
  @HttpCode(200)
  async schedule(
    @Tenant() organizationId: string,
    @Param('contentId') contentId: string,
    @CurrentUser('sub') userId: string,
    @Body() body: { scheduledAt: string },
  ) {
    return this.contentService.scheduleContent(
      contentId,
      organizationId,
      userId,
      new Date(body.scheduledAt),
    );
  }
}

/**
 * Postmark Email Provider
 * Implements IEmailService for Postmark integration
 */

import { Injectable, Logger } from '@nestjs/common';
import axios, { AxiosInstance } from 'axios';
import {
  EmailSendOptions,
  EmailResponse,
  EmailStatus,
  IEmailService,
} from '../interfaces/email.service.interface';
import { PrismaService } from '../../database/prisma.service';
import { v4 as uuid } from 'uuid';

@Injectable()
export class PostmarkProvider implements IEmailService {
  private readonly logger = new Logger(PostmarkProvider.name);
  private readonly client: AxiosInstance;
  private readonly apiKey: string;

  constructor(private readonly prisma: PrismaService) {
    this.apiKey = process.env.POSTMARK_API_KEY || '';

    this.client = axios.create({
      baseURL: 'https://api.postmarkapp.com',
      headers: {
        'X-Postmark-Server-Token': this.apiKey,
        'Content-Type': 'application/json',
      },
    });
  }

  /**
   * Send single email
   */
  async send(options: EmailSendOptions): Promise<EmailResponse> {
    try {
      if (!this.apiKey) {
        throw new Error('Postmark API key not configured');
      }

      const payload: any = {
        From: `${process.env.EMAIL_FROM_NAME || 'Belsuite'} <${process.env.EMAIL_FROM || 'noreply@belsuite.com'}>`,
        To: Array.isArray(options.to) ? options.to.join(',') : options.to,
        Subject: options.subject,
        ReplyTo: options.replyTo,
      };

      // HTML and text content
      if (options.html) {
        payload.HtmlBody = options.html;
      }

      if (options.text) {
        payload.TextBody = options.text;
      }

      // CC and BCC
      if (options.cc) {
        payload.Cc = Array.isArray(options.cc) ? options.cc.join(',') : options.cc;
      }

      if (options.bcc) {
        payload.Bcc = Array.isArray(options.bcc) ? options.bcc.join(',') : options.bcc;
      }

      // Custom metadata
      if (options.metadata) {
        payload.Metadata = options.metadata;
      }

      // Tags
      if (options.tags && options.tags.length > 0) {
        payload.Tag = options.tags.join(', ');
      }

      // Priority (Postmark uses TrackOpens and TrackLinks)
      payload.TrackOpens = true;
      payload.TrackLinks = 'HtmlAndText';

      // Attachments
      if (options.attachments && options.attachments.length > 0) {
        payload.Attachments = options.attachments.map((att) => ({
          Name: att.filename,
          Content: Buffer.isBuffer(att.content)
            ? att.content.toString('base64')
            : Buffer.from(att.content).toString('base64'),
          ContentType: att.contentType || 'application/octet-stream',
          ContentId: att.cid,
        }));
      }

      const response = await this.client.post('/email', payload);
      const messageId = response.data.MessageID;

      this.logger.log(`Email sent via Postmark: ${messageId}`);

      return {
        success: true,
        messageId,
        provider: 'postmark',
        timestamp: new Date(),
      };
    } catch (error) {
      this.logger.error(`Failed to send email: ${error.message}`, error.stack);

      return {
        success: false,
        error: error.message,
        provider: 'postmark',
        timestamp: new Date(),
        retryable: this.isRetryable(error),
      };
    }
  }

  /**
   * Send batch emails
   */
  async sendBatch(emails: EmailSendOptions[]): Promise<EmailResponse[]> {
    try {
      if (!this.apiKey) {
        throw new Error('Postmark API key not configured');
      }

      // Postmark batch API
      const messages = emails.map((email) => ({
        From: `${process.env.EMAIL_FROM_NAME || 'Belsuite'} <${process.env.EMAIL_FROM || 'noreply@belsuite.com'}>`,
        To: Array.isArray(email.to) ? email.to.join(',') : email.to,
        Subject: email.subject,
        HtmlBody: email.html,
        TextBody: email.text,
        Cc: email.cc
          ? Array.isArray(email.cc)
            ? email.cc.join(',')
            : email.cc
          : undefined,
        Bcc: email.bcc
          ? Array.isArray(email.bcc)
            ? email.bcc.join(',')
            : email.bcc
          : undefined,
        ReplyTo: email.replyTo,
        Metadata: email.metadata,
        Tag: email.tags?.join(', '),
        TrackOpens: true,
        TrackLinks: 'HtmlAndText',
      }));

      const response = await this.client.post('/email/batch', {
        Messages: messages,
      });

      return response.data.map((result: any) => ({
        success: result.ErrorCode === 0,
        messageId: result.MessageID,
        error: result.Message,
        provider: 'postmark',
        timestamp: new Date(),
      }));
    } catch (error) {
      this.logger.error(`Batch send failed: ${error.message}`);

      return emails.map(() => ({
        success: false,
        error: error.message,
        provider: 'postmark',
        timestamp: new Date(),
        retryable: this.isRetryable(error),
      }));
    }
  }

  /**
   * Get email status
   */
  async getStatus(messageId: string): Promise<EmailStatus | null> {
    try {
      const email = await this.prisma.email.findFirst({
        where: {
          externalEmailId: messageId,
          provider: 'POSTMARK',
        },
      });

      if (!email) {
        return null;
      }

      let status: EmailStatus['status'] = 'pending';
      if (email.bouncedAt) status = 'bounced';
      else if (email.spamReportedAt) status = 'failed';
      else if (email.clickedAt) status = 'clicked';
      else if (email.openedAt) status = 'opened';
      else if (email.deliveredAt) status = 'delivered';
      else if (email.sentAt) status = 'sent';

      return {
        messageId,
        status,
        timestamp: email.updatedAt,
        metadata: {
          email: email.toEmail,
          provider: 'postmark',
        },
      };
    } catch (error) {
      this.logger.error(`Failed to get status: ${error.message}`);
      return null;
    }
  }

  /**
   * Check provider health
   */
  async health(): Promise<{ healthy: boolean; provider: string; timestamp: Date }> {
    try {
      if (!this.apiKey) {
        return {
          healthy: false,
          provider: 'postmark',
          timestamp: new Date(),
        };
      }

      // Make a simple API call to verify credentials
      await this.client.get('/deliverystats');

      return {
        healthy: true,
        provider: 'postmark',
        timestamp: new Date(),
      };
    } catch (error) {
      this.logger.error(`Health check failed: ${error.message}`);
      return {
        healthy: false,
        provider: 'postmark',
        timestamp: new Date(),
      };
    }
  }

  /**
   * Verify domain
   */
  async verifyDomain(domain: string): Promise<boolean> {
    try {
      const response = await this.client.get(`/senders?domain=${domain}`);
      return response.data.Senders && response.data.Senders.length > 0;
    } catch (error) {
      this.logger.error(`Domain verification failed: ${error.message}`);
      return false;
    }
  }

  // ============================================================================
  // PRIVATE HELPERS
  // ============================================================================

  /**
   * Determine if error is retryable
   */
  private isRetryable(error: any): boolean {
    if (error.response?.status) {
      const status = error.response.status;
      // 5xx errors and 429 (rate limit) are retryable
      return status >= 500 || status === 429;
    }

    // Postmark specific error codes
    const retryableErrors = ['InvalidSenderSignature', 'InactiveRecipient'];
    if (error.response?.data?.Name && retryableErrors.includes(error.response.data.Name)) {
      return true;
    }

    return true;
  }
}

/**
 * SendGrid Email Provider Implementation
 * https://sendgrid.com/docs/API/
 */

import { Injectable } from '@nestjs/common';
import * as sgMail from '@sendgrid/mail';
import { IEmailProvider } from '../interfaces/email-provider.interface';
import {
  EmailProvider,
  EmailStatus,
  SendEmailRequest,
  SendEmailResponse,
  BulkSendEmailRequest,
  EmailEventPayload,
  EmailTemplateRequest,
  EmailTemplate,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
  EmailCategory,
} from '../types/email.types';
import * as crypto from 'crypto';
import { v4 as uuid } from 'uuid';

@Injectable()
export class SendGridProvider implements IEmailProvider {
  private apiKey: string;
  private webhookSecret: string;
  private fromEmail: string;
  private fromName: string;

  constructor() {
    this.apiKey = process.env.SENDGRID_API_KEY || '';
    this.webhookSecret = process.env.SENDGRID_WEBHOOK_SECRET || '';
    this.fromEmail = process.env.SENDGRID_FROM_EMAIL || 'noreply@belsuite.com';
    this.fromName = process.env.SENDGRID_FROM_NAME || 'Belsuite';

    sgMail.setApiKey(this.apiKey);
  }

  getProvider(): EmailProvider {
    return EmailProvider.SENDGRID;
  }

  async sendEmail(request: SendEmailRequest): Promise<SendEmailResponse> {
    try {
      const emailId = `sendgrid_${uuid()}`;

      const message: any = {
        to: {
          email: request.to.email,
          name: request.to.name,
        },
        from: {
          email: request.from?.email || this.fromEmail,
          name: request.from?.name || this.fromName,
        },
        subject: request.subject,
        html: request.htmlContent,
        text: request.textContent,
        replyTo: request.replyTo,
        customArgs: {
          emailId,
          organizationId: request.metadata?.organizationId,
          ...request.metadata,
        },
      };

      // Add tags if provided
      if (request.tags && request.tags.length > 0) {
        message.categories = request.tags;
      }

      // Add unsubscribe link if provided
      if (request.unsubscribeUrl) {
        message.mailSettings = {
          sandbox_mode: {
            enable: false,
          },
          footer: {
            enable: true,
            text: `Unsubscribe: ${request.unsubscribeUrl}`,
            html: `<a href="${request.unsubscribeUrl}">Unsubscribe</a>`,
          },
        };
      }

      const response = await sgMail.send(message);

      const externalEmailId = response[0].headers['x-message-id'] || emailId;

      return {
        id: emailId,
        externalEmailId,
        status: EmailStatus.SENT,
        provider: EmailProvider.SENDGRID,
        sentAt: new Date(),
      };
    } catch (error) {
      throw new Error(`SendGrid email send failed: ${error.message}`);
    }
  }

  async sendBulkEmails(
    request: BulkSendEmailRequest,
  ): Promise<SendEmailResponse[]> {
    try {
      const results: SendEmailResponse[] = [];

      for (const personalization of request.personalization) {
        for (const recipient of personalization.to) {
          let htmlContent = request.htmlContent;
          let textContent = request.textContent;

          // Replace variables
          if (personalization.variables) {
            for (const [key, value] of Object.entries(
              personalization.variables,
            )) {
              const placeholder = `{{${key}}}`;
              htmlContent = htmlContent?.replace(
                new RegExp(placeholder, 'g'),
                value,
              );
              textContent = textContent?.replace(
                new RegExp(placeholder, 'g'),
                value,
              );
            }
          }

          const result = await this.sendEmail({
            to: recipient,
            from: request.from,
            subject: personalization.subject ?? request.subject ?? 'Belsuite Notification',
            htmlContent,
            textContent,
            metadata: personalization.variables,
          });

          results.push(result);
        }
      }

      return results;
    } catch (error) {
      throw new Error(`SendGrid bulk send failed: ${error.message}`);
    }
  }

  async getEmailStatus(externalEmailId: string): Promise<EmailStatus> {
    // SendGrid doesn't provide a direct API to check email status
    // Use webhooks for status tracking instead
    return EmailStatus.SENT;
  }

  async createTemplate(
    request: EmailTemplateRequest,
  ): Promise<EmailTemplate> {
    try {
      // Generate template ID if not provided
      const templateId = `tmpl_${uuid()}`;

      // In production, you would create the template in SendGrid
      // For now, return a simulated response
      return {
        id: templateId,
        organizationId: '',
        name: request.name,
        subject: request.subject,
        htmlTemplate: request.htmlTemplate,
        textTemplate: request.textTemplate,
        variables: request.variables || [],
        category: (request.category as EmailCategory) || EmailCategory.NOTIFICATION,
        isActive: true,
        isSystem: false,
        usageCount: 0,
        createdAt: new Date(),
      };
    } catch (error) {
      throw new Error(`SendGrid template creation failed: ${error.message}`);
    }
  }

  async deleteTemplate(templateId: string): Promise<void> {
    try {
      // In production, delete from SendGrid API
    } catch (error) {
      throw new Error(`SendGrid template deletion failed: ${error.message}`);
    }
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    try {
      // SendGrid uses HMAC-SHA256
      const timestamp = request.signature.split('=')[0];
      const signature = request.signature.split('=')[1];

      const hash = crypto
        .createHmac('sha256', this.webhookSecret)
        .update(timestamp + request.payload)
        .digest('base64');

      const isValid = hash === signature;

      return {
        isValid,
        provider: EmailProvider.SENDGRID,
      };
    } catch (error) {
      return {
        isValid: false,
        provider: EmailProvider.SENDGRID,
      };
    }
  }

  async parseWebhookEvent(payload: any): Promise<EmailEventPayload> {
    const event = payload[0];

    let eventType: 'sent' | 'delivered' | 'open' | 'click' | 'bounce' | 'spam' | 'failed' =
      'sent';

    switch (event.event) {
      case 'delivered':
        eventType = 'delivered';
        break;
      case 'open':
        eventType = 'open';
        break;
      case 'click':
        eventType = 'click';
        break;
      case 'bounce':
        eventType = 'bounce';
        break;
      case 'spamreport':
        eventType = 'spam';
        break;
      case 'dropped':
      case 'failed':
        eventType = 'failed';
        break;
    }

    return {
      provider: EmailProvider.SENDGRID,
      externalEmailId: event.sg_message_id,
      eventType,
      timestamp: new Date(event.timestamp * 1000),
      metadata: {
        email: event.email,
        reason: event.reason,
        status: event.status,
      },
    };
  }

  getWebhookSecret(): string {
    return this.webhookSecret;
  }

  async healthCheck(): Promise<boolean> {
    try {
      // Verify API key by making a simple request
      const response = await sgMail.send({
        to: 'test@example.com',
        from: this.fromEmail,
        subject: 'Health Check',
        text: 'This is a health check email.',
        sendAt: Math.floor(Date.now() / 1000) + 1, // Send 1 second in future to avoid actual send
      });

      return response.length > 0;
    } catch (error) {
      // May fail due to invalid recipient, but API is working
      return this.apiKey !== '';
    }
  }
}

/**
 * Amazon SES Email Provider
 * Implements IEmailService for AWS SES integration
 */

import { Injectable, Logger } from '@nestjs/common';
import {
  SESClient,
  SendEmailCommand,
  SendBulkTemplatedEmailCommand,
  GetAccountSendingEnabledCommand,
} from '@aws-sdk/client-ses';
import {
  EmailSendOptions,
  EmailResponse,
  EmailStatus,
  IEmailService,
} from '../interfaces/email.service.interface';
import { PrismaService } from '../../database/prisma.service';
import { v4 as uuid } from 'uuid';

@Injectable()
export class SESProvider implements IEmailService {
  private readonly logger = new Logger(SESProvider.name);
  private readonly client: SESClient;
  private readonly fromEmail: string;
  private readonly fromName: string;

  constructor(private readonly prisma: PrismaService) {
    this.fromEmail = process.env.EMAIL_FROM || 'noreply@belsuite.com';
    this.fromName = process.env.EMAIL_FROM_NAME || 'Belsuite';

    this.client = new SESClient({
      region: process.env.AWS_REGION || 'us-east-1',
      credentials: {
        accessKeyId: process.env.AWS_ACCESS_KEY_ID || '',
        secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY || '',
      },
    });
  }

  /**
   * Send single email
   */
  async send(options: EmailSendOptions): Promise<EmailResponse> {
    try {
      const messageId = `ses_${uuid()}`;

      const destination: any = {
        ToAddresses: Array.isArray(options.to) ? options.to : [options.to],
      };

      if (options.cc) {
        destination.CcAddresses = Array.isArray(options.cc) ? options.cc : [options.cc];
      }

      if (options.bcc) {
        destination.BccAddresses = Array.isArray(options.bcc) ? options.bcc : [options.bcc];
      }

      const message: any = {
        Subject: {
          Data: options.subject,
          Charset: 'UTF-8',
        },
      };

      if (options.html) {
        message.Body = message.Body || {};
        message.Body.Html = {
          Data: options.html,
          Charset: 'UTF-8',
        };
      }

      if (options.text) {
        message.Body = message.Body || {};
        message.Body.Text = {
          Data: options.text,
          Charset: 'UTF-8',
        };
      }

      // Note: SES doesn't support attachments through the standard SendEmailCommand
      // For attachments, you would need to use a library like nodemailer with SES transport
      if (options.attachments && options.attachments.length > 0) {
        this.logger.warn('SES does not support attachments via this API');
      }

      const command = new SendEmailCommand({
        Source: `${this.fromName} <${this.fromEmail}>`,
        Destination: destination,
        Message: message,
        ReplyToAddresses: options.replyTo ? [options.replyTo] : undefined,
        Tags: options.tags?.map((tag) => ({
          Name: 'category',
          Value: tag,
        })),
      });

      await this.client.send(command);

      this.logger.log(`Email sent via AWS SES: ${messageId}`);

      return {
        success: true,
        messageId,
        provider: 'ses',
        timestamp: new Date(),
      };
    } catch (error) {
      this.logger.error(`Failed to send email: ${error.message}`, error.stack);

      return {
        success: false,
        error: error.message,
        provider: 'ses',
        timestamp: new Date(),
        retryable: this.isRetryable(error),
      };
    }
  }

  /**
   * Send batch emails
   */
  async sendBatch(emails: EmailSendOptions[]): Promise<EmailResponse[]> {
    const results: EmailResponse[] = [];

    for (const email of emails) {
      const result = await this.send(email);
      results.push(result);
    }

    return results;
  }

  /**
   * Get email status
   */
  async getStatus(messageId: string): Promise<EmailStatus | null> {
    try {
      const email = await this.prisma.email.findFirst({
        where: {
          externalEmailId: messageId,
          provider: 'SES',
        },
      });

      if (!email) {
        return null;
      }

      let status: EmailStatus['status'] = 'pending';
      if (email.bouncedAt) status = 'bounced';
      else if (email.spamReportedAt) status = 'failed';
      else if (email.clickedAt) status = 'clicked';
      else if (email.openedAt) status = 'opened';
      else if (email.deliveredAt) status = 'delivered';
      else if (email.sentAt) status = 'sent';

      return {
        messageId,
        status,
        timestamp: email.updatedAt,
        metadata: {
          email: email.toEmail,
          provider: 'ses',
        },
      };
    } catch (error) {
      this.logger.error(`Failed to get status: ${error.message}`);
      return null;
    }
  }

  /**
   * Check provider health
   */
  async health(): Promise<{ healthy: boolean; provider: string; timestamp: Date }> {
    try {
      if (!process.env.AWS_ACCESS_KEY_ID || !process.env.AWS_SECRET_ACCESS_KEY) {
        return {
          healthy: false,
          provider: 'ses',
          timestamp: new Date(),
        };
      }

      const command = new GetAccountSendingEnabledCommand({});
      await this.client.send(command);

      return {
        healthy: true,
        provider: 'ses',
        timestamp: new Date(),
      };
    } catch (error) {
      this.logger.error(`Health check failed: ${error.message}`);
      return {
        healthy: false,
        provider: 'ses',
        timestamp: new Date(),
      };
    }
  }

  /**
   * Verify domain (not implemented for SES)
   */
  async verifyDomain(domain: string): Promise<boolean> {
    this.logger.warn('Domain verification must be done through AWS Console');
    return true;
  }

  // ============================================================================
  // PRIVATE HELPERS
  // ============================================================================

  /**
   * Determine if error is retryable
   */
  private isRetryable(error: any): boolean {
    const retryableErrors = [
      'MessageRejected',
      'MailFromDomainNotVerified',
      'ThrottlingMaximumSendingRateExceeded',
    ];

    if (error.name && retryableErrors.includes(error.name)) {
      return true;
    }

    return false;
  }
}

/**
 * SMTP Email Provider
 * Implements IEmailService using NodeMailer for generic SMTP connections
 */

import { Injectable, Logger } from '@nestjs/common';
import * as nodemailer from 'nodemailer';
import { Transporter } from 'nodemailer';
import {
  EmailSendOptions,
  EmailResponse,
  EmailStatus,
  IEmailService,
} from '../interfaces/email.service.interface';
import { PrismaService } from '../../database/prisma.service';
import { v4 as uuid } from 'uuid';

@Injectable()
export class SmtpProvider implements IEmailService {
  private readonly logger = new Logger(SmtpProvider.name);
  private transporter: Transporter | null = null;

  constructor(private readonly prisma: PrismaService) {
    this.initializeTransporter();
  }

  /**
   * Initialize SMTP transporter
   */
  private initializeTransporter(): void {
    try {
      const host = process.env.SMTP_HOST || 'localhost';
      const port = parseInt(process.env.SMTP_PORT || '587', 10);
      const secure = process.env.SMTP_SECURE === 'true'; // true for 465, false for other ports
      const user = process.env.SMTP_USER;
      const pass = process.env.SMTP_PASSWORD;

      const config: any = {
        host,
        port,
        secure,
        logger: false,
        debug: process.env.NODE_ENV === 'development',
      };

      // Add authentication if credentials are provided
      if (user && pass) {
        config.auth = {
          user,
          pass,
        };
      }

      this.transporter = nodemailer.createTransport(config);

      this.logger.log(`SMTP Provider initialized: ${host}:${port}`);
    } catch (error) {
      this.logger.error(`Failed to initialize SMTP transporter: ${error.message}`);
      this.transporter = null;
    }
  }

  /**
   * Send single email
   */
  async send(options: EmailSendOptions): Promise<EmailResponse> {
    try {
      if (!this.transporter) {
        throw new Error('SMTP transporter not initialized');
      }

      const messageId = `smtp_${uuid()}`;
      const fromEmail = process.env.EMAIL_FROM || 'noreply@belsuite.com';
      const fromName = process.env.EMAIL_FROM_NAME || 'Belsuite';

      // Prepare recipients
      const recipients = Array.isArray(options.to) ? options.to.join(', ') : options.to;

      // Prepare attachments if any
      const attachments = options.attachments
        ? options.attachments.map((att) => ({
            filename: att.filename,
            content: att.content,
            contentType: att.contentType,
            cid: att.cid,
          }))
        : undefined;

      // Send email
      const info = await this.transporter.sendMail({
        from: `"${fromName}" <${fromEmail}>`,
        to: recipients,
        cc: options.cc
          ? Array.isArray(options.cc)
            ? options.cc.join(', ')
            : options.cc
          : undefined,
        bcc: options.bcc
          ? Array.isArray(options.bcc)
            ? options.bcc.join(', ')
            : options.bcc
          : undefined,
        replyTo: options.replyTo,
        subject: options.subject,
        text: options.text,
        html: options.html,
        attachments,
        headers: {
          'X-Message-ID': messageId,
          'X-Priority': options.priority === 'high' ? '1' : options.priority === 'low' ? '5' : '3',
          ...(options.headers || {}),
        },
      });

      this.logger.log(`Email sent via SMTP: ${messageId}, response: ${info.response}`);

      const organizationId =
        typeof options.metadata?.organizationId === 'string'
          ? options.metadata.organizationId
          : null;

      if (organizationId) {
        await this.prisma.email.create({
          data: {
            organizationId,
            externalEmailId: info.messageId || messageId,
            provider: 'SMTP',
            toEmail: recipients,
            subject: options.subject,
            sentAt: new Date(),
          },
        });
      }

      return {
        success: true,
        messageId: info.messageId || messageId,
        provider: 'smtp',
        timestamp: new Date(),
      };
    } catch (error) {
      this.logger.error(`Failed to send email: ${error.message}`, error.stack);

      return {
        success: false,
        error: error.message,
        provider: 'smtp',
        timestamp: new Date(),
        retryable: this.isRetryable(error),
      };
    }
  }

  /**
   * Send batch emails
   */
  async sendBatch(emails: EmailSendOptions[]): Promise<EmailResponse[]> {
    try {
      const results: EmailResponse[] = [];

      // Process emails sequentially to avoid connection issues
      for (const email of emails) {
        const result = await this.send(email);
        results.push(result);

        // Add small delay between emails to prevent connection saturation
        await new Promise((resolve) => setTimeout(resolve, 10));
      }

      return results;
    } catch (error) {
      this.logger.error(`Batch send failed: ${error.message}`);

      return emails.map(() => ({
        success: false,
        error: error.message,
        provider: 'smtp',
        timestamp: new Date(),
        retryable: this.isRetryable(error),
      }));
    }
  }

  /**
   * Get email status
   */
  async getStatus(messageId: string): Promise<EmailStatus | null> {
    try {
      const email = await this.prisma.email.findFirst({
        where: {
          externalEmailId: messageId,
          provider: 'SMTP',
        },
      });

      if (!email) {
        return null;
      }

      let status: EmailStatus['status'] = 'pending';
      if (email.bouncedAt) status = 'bounced';
      else if (email.spamReportedAt) status = 'failed';
      else if (email.clickedAt) status = 'clicked';
      else if (email.openedAt) status = 'opened';
      else if (email.deliveredAt) status = 'delivered';
      else if (email.sentAt) status = 'sent';

      return {
        messageId,
        status,
        timestamp: email.updatedAt,
        metadata: {
          email: email.toEmail,
          provider: 'smtp',
        },
      };
    } catch (error) {
      this.logger.error(`Failed to get status: ${error.message}`);
      return null;
    }
  }

  /**
   * Check provider health
   */
  async health(): Promise<{ healthy: boolean; provider: string; timestamp: Date }> {
    try {
      if (!this.transporter) {
        return {
          healthy: false,
          provider: 'smtp',
          timestamp: new Date(),
        };
      }

      // Verify connection
      await this.transporter.verify();

      return {
        healthy: true,
        provider: 'smtp',
        timestamp: new Date(),
      };
    } catch (error) {
      this.logger.error(`Health check failed: ${error.message}`);

      // Attempt to reinitialize on failure
      this.initializeTransporter();

      return {
        healthy: false,
        provider: 'smtp',
        timestamp: new Date(),
      };
    }
  }

  /**
   * Verify domain
   */
  async verifyDomain(domain: string): Promise<boolean> {
    try {
      // SMTP doesn't have built-in domain verification
      // We can verify by checking if we have proper SMTP credentials configured
      const host = process.env.SMTP_HOST;
      const user = process.env.SMTP_USER;

      if (!host || !user) {
        return false;
      }

      // Check if transporter is healthy
      const healthCheck = await this.health();
      return healthCheck.healthy;
    } catch (error) {
      this.logger.error(`Domain verification failed: ${error.message}`);
      return false;
    }
  }

  // ============================================================================
  // PRIVATE HELPERS
  // ============================================================================

  /**
   * Determine if error is retryable
   */
  private isRetryable(error: any): boolean {
    const message = error.message || '';
    const code = error.code || '';

    // Transient failures
    const retryablePatterns = [
      'ECONNREFUSED',
      'ENOTFOUND',
      'ENETUNREACH',
      'ETIMEDOUT',
      'EHOSTUNREACH',
      'timeout',
      'temporarily unavailable',
      'service not available',
      '421',
      '450',
      '451',
      '452',
    ];

    return retryablePatterns.some(
      (pattern) =>
        message.toLowerCase().includes(pattern.toLowerCase()) ||
        code.includes(pattern),
    );
  }
}

import {
  NestFactory,
  HttpAdapterHost,
} from '@nestjs/core';
import { ValidationPipe, ClassSerializerInterceptor, VersioningType } from '@nestjs/common';
import { SwaggerModule, DocumentBuilder } from '@nestjs/swagger';
import { AppModule } from './app.module';
import { HttpExceptionFilter, AllExceptionsFilter } from './common/filters/http-exception.filter';
import * as helmet from 'helmet';
import { rateLimit } from 'express-rate-limit';

async function bootstrap() {
  const app = await NestFactory.create(AppModule, {
    rawBody: true,
    cors: {
      origin: process.env.CORS_ORIGINS?.split(',') || ['http://localhost:3000'],
      methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
      credentials: true,
    },
  });

  // Versioning
  app.enableVersioning({
    type: VersioningType.URI,
    prefix: 'v',
  });

  // Security middleware
  app.use(helmet.default());
  app.use(
    rateLimit({
      windowMs: 15 * 60 * 1000, // 15 minutes
      max: 100, // Limit each IP to 100 requests per windowMs
      message: 'Too many requests, please try again later.',
    }),
  );

  // Validation
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
      transformOptions: {
        enableImplicitConversion: true,
      },
    }),
  );

  // Exception handlers
  app.useGlobalFilters(
    new AllExceptionsFilter(),
    new HttpExceptionFilter(),
  );

  // Serialization
  app.useGlobalInterceptors(new ClassSerializerInterceptor(app.get('Reflector')));

  // Swagger documentation
  const config = new DocumentBuilder()
    .setTitle('Belsuite API')
    .setDescription('Production-ready multi-tenant SaaS platform API')
    .setVersion('1.0.0')
    .addBearerAuth()
    .build();

  const document = SwaggerModule.createDocument(app, config);
  SwaggerModule.setup('api/docs', app, document);

  const port = process.env.PORT || 3001;
  await app.listen(port);

  console.log(`Ô£ô Belsuite backend running on http://localhost:${port}`);
  console.log(`Ô£ô API documentation available at http://localhost:${port}/api/docs`);
}

bootstrap().catch((error) => {
  console.error('Failed to start application:', error);
  process.exit(1);
});

