      ],
    };

    const formatTips: Partial<Record<AdFormatEnum, string>> = {
      [AdFormatEnum.CAROUSEL]: 'Put best performing product/feature on card 1',
      [AdFormatEnum.VIDEO]: 'Aim for 15-30 second video for best completion rates',
