/**
 * Tenant Onboarding Service
 * Manages the onboarding flow for new tenants (state machine)
 */

import {
  Injectable,
  BadRequestException,
  NotFoundException,
  ConflictException,
  Logger,
} from '@nestjs/common';
import { PrismaService } from '../../database/prisma.service';
import { OnboardingStep } from '@prisma/client';

export interface OnboardingStepData {
  companyName?: string;
  website?: string;
  logo?: string;
  industry?: string;
  subdomainChosen?: string;
  customDomainChosen?: string;
  defaultLanguage?: string;
  defaultTimezone?: string;
  teamMembersEmails?: string[];
  paymentMethodId?: string;
  featurePreferences?: Record<string, boolean>;
}

export interface OnboardingStatus {
  step: string;
  completed: boolean;
  completionPercentage: number;
  remainingSteps: string[];
  currentStepData: any;
}

@Injectable()
export class TenantOnboardingService {
  private readonly logger = new Logger(TenantOnboardingService.name);

  // Define onboarding flow
  private readonly onboardingFlow = [
    OnboardingStep.WELCOME,
    OnboardingStep.COMPANY_INFO,
    OnboardingStep.DOMAIN_SETUP,
    OnboardingStep.TEAM_SETUP,
    OnboardingStep.PAYMENT_SETUP,
    OnboardingStep.FEATURE_SELECTION,
    OnboardingStep.COMPLETED,
  ];

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Get onboarding status for tenant
   */
  async getOnboardingStatus(organizationId: string): Promise<OnboardingStatus> {
    const onboarding = await this.getOnboarding(organizationId);

    const currentStepIndex = this.onboardingFlow.indexOf(
      onboarding.step as OnboardingStep,
    );
    const completedSteps = currentStepIndex + (onboarding.completed ? 1 : 0);
    const completionPercentage = Math.round(
      (completedSteps / this.onboardingFlow.length) * 100,
    );

    return {
      step: onboarding.step,
      completed: onboarding.completed,
      completionPercentage,
      remainingSteps: this.onboardingFlow.slice(currentStepIndex + 1).map(s => s.toString()),
      currentStepData: {
        companyName: onboarding.companyName,
        website: onboarding.companyWebsite,
        industry: onboarding.industry,
        subdomainChosen: onboarding.subdomainChosen,
        customDomainChosen: onboarding.customDomainChosen,
        defaultLanguage: onboarding.defaultLanguage,
        defaultTimezone: onboarding.defaultTimezone,
        invitedMembersCount: onboarding.invitedMembersCount,
        paymentMethodId: onboarding.paymentMethodId,
        featurePreferences: onboarding.featurePreferences,
      },
    };
  }

  /**
   * Complete current step and move to next
   */
  async completeStep(
    organizationId: string,
    currentStep: string,
    stepData: OnboardingStepData,
  ): Promise<OnboardingStatus> {
    const onboarding = await this.getOnboarding(organizationId);

    // Verify current step matches
    if (onboarding.step !== currentStep) {
      throw new BadRequestException(
        `Invalid step. Current step is ${onboarding.step}, not ${currentStep}`,
      );
    }

    try {
      // Update with step data and mark as completed
      await this.prisma.tenantOnboarding.update({
        where: { organizationId },
        data: {
          ...this.mapStepData(currentStep, stepData),
          completed: true,
          completedAt: new Date(),
        },
      });

      // Move to next step
      const nextStep = this.getNextStep(currentStep);
      const updated = await this.prisma.tenantOnboarding.update({
        where: { organizationId },
        data: {
          step: nextStep ?? OnboardingStep.COMPLETED,
          completed: false,
        },
      });

      this.logger.log(
        `Onboarding step completed: ${currentStep} ÔåÆ ${nextStep} for tenant ${organizationId}`,
      );

      // Return new status
      return this.getOnboardingStatus(organizationId);
    } catch (error) {
      this.logger.error(
        `Failed to complete onboarding step: ${error.message}`,
        error.stack,
      );
      throw error;
    }
  }

  /**
   * Skip optional step
   */
  async skipStep(organizationId: string, currentStep: string): Promise<OnboardingStatus> {
    const skippableSteps: OnboardingStep[] = [
      OnboardingStep.TEAM_SETUP,
      OnboardingStep.PAYMENT_SETUP,
      OnboardingStep.FEATURE_SELECTION,
    ];

    if (!skippableSteps.includes(currentStep as OnboardingStep)) {
      throw new BadRequestException(`Step "${currentStep}" cannot be skipped`);
    }

    const onboarding = await this.getOnboarding(organizationId);

    if (onboarding.step !== currentStep) {
      throw new BadRequestException(
        `Invalid step. Current step is ${onboarding.step}, not ${currentStep}`,
      );
    }

    // Move to next step
    const nextStep = this.getNextStep(currentStep);

    await this.prisma.tenantOnboarding.update({
      where: { organizationId },
      data: {
        step: nextStep ?? OnboardingStep.COMPLETED,
      },
    });

    this.logger.log(
      `Onboarding step skipped: ${currentStep} ÔåÆ ${nextStep} for tenant ${organizationId}`,
    );

    return this.getOnboardingStatus(organizationId);
  }

  /**
   * Complete entire onboarding
   */
  async completeOnboarding(organizationId: string): Promise<void> {
    await this.prisma.tenantOnboarding.update({
      where: { organizationId },
      data: {
        step: OnboardingStep.COMPLETED,
        completed: true,
        completedAt: new Date(),
      },
    });

    // Update organization
    await this.prisma.organization.update({
      where: { id: organizationId },
      data: {
        onboardingCompletedAt: new Date(),
      },
    });

    this.logger.log(`Onboarding completed for tenant ${organizationId}`);
  }

  /**
   * Mark as abandoned
   */
  async markAbandoned(organizationId: string): Promise<void> {
    await this.prisma.tenantOnboarding.update({
      where: { organizationId },
      data: {
        abandonedAt: new Date(),
      },
    });

    this.logger.log(`Onboarding marked as abandoned for tenant ${organizationId}`);
  }

  /**
   * Reset onboarding to beginning
   */
  async resetOnboarding(organizationId: string): Promise<OnboardingStatus> {
    await this.prisma.tenantOnboarding.update({
      where: { organizationId },
      data: {
        step: OnboardingStep.WELCOME,
        completed: false,
        completedAt: null,
        abandonedAt: null,
      },
    });

    this.logger.log(`Onboarding reset for tenant ${organizationId}`);

    return this.getOnboardingStatus(organizationId);
  }

  /**
   * Get step description and requirements
   */
  getStepInfo(step: string): any {
    const stepInfo: Record<string, any> = {
      [OnboardingStep.WELCOME]: {
        title: 'Welcome to BelSuite',
        description: "Welcome! Let's get your account set up.",
        duration: '2 minutes',
        required: ['organizationCreated'],
        optional: [],
      },
      [OnboardingStep.COMPANY_INFO]: {
        title: 'Company Information',
        description: 'Tell us about your company',
        duration: '5 minutes',
        required: ['companyName', 'website'],
        optional: ['logo', 'industry'],
      },
      [OnboardingStep.DOMAIN_SETUP]: {
        title: 'Domain Setup',
        description: 'Choose your subdomain or custom domain',
        duration: '10 minutes',
        required: ['subdomain or customDomain'],
        optional: [],
      },
      [OnboardingStep.TEAM_SETUP]: {
        title: 'Invite Team Members',
        description: 'Invite your team to collaborate',
        duration: '5 minutes',
        required: [],
        optional: ['teamMembersEmails'],
        skippable: true,
      },
      [OnboardingStep.PAYMENT_SETUP]: {
        title: 'Payment Method',
        description: 'Add a payment method for your subscription',
        duration: '5 minutes',
        required: ['paymentMethodId'],
        optional: [],
        skippable: true,
      },
      [OnboardingStep.FEATURE_SELECTION]: {
        title: 'Feature Preferences',
        description: 'Choose which features to enable',
        duration: '3 minutes',
        required: [],
        optional: ['featurePreferences'],
        skippable: true,
      },
      [OnboardingStep.COMPLETED]: {
        title: 'All Set!',
        description: "You're ready to use BelSuite",
        duration: '0 minutes',
        required: [],
        optional: [],
      },
    };

    return stepInfo[step] || null;
  }

  /**
   * Get all onboarding analytics
   */
  async getOnboardingAnalytics(): Promise<any> {
    const onboardings = await this.prisma.tenantOnboarding.findMany({
      select: {
        step: true,
        completed: true,
        completedAt: true,
        abandonedAt: true,
        createdAt: true,
      },
    });

    const total = onboardings.length;
    const completed = onboardings.filter(o => o.completed).length;
    const abandoned = onboardings.filter(o => o.abandonedAt).length;
    const inProgress = total - completed - abandoned;

    // Group by last step
    const byStep = this.onboardingFlow.reduce(
      (acc, step) => {
        acc[step] = onboardings.filter(o => o.step === step).length;
        return acc;
      },
      {} as Record<string, number>,
    );

    // Average time to complete
    const completedWithTime = onboardings.filter(
      o => o.completed && o.completedAt && o.createdAt,
    );
    const avgCompletionTime =
      completedWithTime.length > 0
        ? completedWithTime.reduce(
            (acc, o) =>
              acc + (o.completedAt!.getTime() - o.createdAt.getTime()),
            0,
          ) / completedWithTime.length
        : 0;

    return {
      total,
      completed,
      inProgress,
      abandoned,
      completionRate: `${Math.round((completed / total) * 100)}%`,
      abandonmentRate: `${Math.round((abandoned / total) * 100)}%`,
      avgCompletionTimeMinutes: Math.round(avgCompletionTime / 60000),
      byStep,
    };
  }

  /**
   * Helper: Get onboarding record
   */
  private async getOnboarding(organizationId: string): Promise<any> {
    const onboarding = await this.prisma.tenantOnboarding.findUnique({
      where: { organizationId },
    });

    if (!onboarding) {
      throw new NotFoundException(
        `Onboarding not found for tenant: ${organizationId}`,
      );
    }

    return onboarding;
  }

  /**
   * Helper: Get next step in flow
   */
  private getNextStep(currentStep: string): OnboardingStep | null {
    const currentIndex = this.onboardingFlow.findIndex(s => s === currentStep);

    if (currentIndex === -1 || currentIndex === this.onboardingFlow.length - 1) {
      return null;
    }

    return this.onboardingFlow[currentIndex + 1];
  }

  /**
   * Helper: Map step data to database fields
   */
  private mapStepData(step: string, data: OnboardingStepData): Record<string, any> {
    switch (step) {
      case OnboardingStep.COMPANY_INFO:
        return {
          companyName: data.companyName,
          companyWebsite: data.website,
          industry: data.industry,
        };

      case OnboardingStep.DOMAIN_SETUP:
        return {
          subdomainChosen: data.subdomainChosen,
          customDomainChosen: data.customDomainChosen,
        };

      case OnboardingStep.TEAM_SETUP:
        return {
          teamMembersInvited: (data.teamMembersEmails || []).length > 0,
          invitedMembersCount: data.teamMembersEmails?.length || 0,
        };

      case OnboardingStep.PAYMENT_SETUP:
        return {
          billingMethodAdded: !!data.paymentMethodId,
          paymentMethodId: data.paymentMethodId,
        };

      case OnboardingStep.FEATURE_SELECTION:
        return {
          featurePreferences: data.featurePreferences,
        };

      default:
        return {};
    }
  }
}

/**
 * Tenant Service
 * Core business logic for tenant operations: creation, updates, domain management
 */

import { Injectable, BadRequestException, NotFoundException, ConflictException, Logger } from '@nestjs/common';
import { PrismaService } from '../../database/prisma.service';
import { OnboardingStep, SubscriptionTier } from '@prisma/client';
import * as crypto from 'crypto';

export interface CreateTenantDto {
  name: string;
  slug: string;
  email: string;
  tier?: string;
  companyName?: string;
  website?: string;
  industry?: string;
}

export interface UpdateTenantDto {
  name?: string;
  tier?: string;
  metadata?: Record<string, any>;
}

@Injectable()
export class TenantService {
  private readonly logger = new Logger(TenantService.name);

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Create a new tenant (organization)
   */
  async createTenant(dto: CreateTenantDto, creatorId?: string): Promise<any> {
    // Validate slug format
    if (!this.isValidSlug(dto.slug)) {
      throw new BadRequestException('Invalid slug format. Use lowercase letters, numbers, and hyphens.');
    }

    // Check if slug already taken
    const existing = await this.prisma.organization.findUnique({
      where: { slug: dto.slug },
    });

    if (existing) {
      throw new ConflictException(`Slug "${dto.slug}" is already taken.`);
    }

    try {
      // Create organization with onboarding
      const organization = await this.prisma.organization.create({
        data: {
          name: dto.name,
          slug: dto.slug,
          email: dto.email,
          tier: (dto.tier?.toUpperCase() as SubscriptionTier) || SubscriptionTier.STARTER,
          encryptionKey: this.generateEncryptionKey(),
          tenantOnboarding: {
            create: {
              step: OnboardingStep.WELCOME,
              companyName: dto.companyName,
              companyWebsite: dto.website,
              industry: dto.industry,
            },
          },
          tenantRateLimits: {
            create: {
              apiRequestsPerMinute: 60,
              apiRequestsPerHour: 5000,
              apiRequestsPerDay: 100000,
              emailsPerMinute: 10,
              emailsPerHour: 500,
              emailsPerDay: 5000,
              aiTokensPerMinute: 100000,
              aiTokensPerHour: 10000000,
              aiTokensPerDay: 100000000,
              maxStorageGB: 10,
              maxConcurrentRequests: 10,
              maxConcurrentUploads: 5,
              enforceRateLimits: true,
            },
          },
        },
        include: {
          tenantOnboarding: true,
          tenantRateLimits: true,
        },
      });

      // Create auto-generated subdomain mapping (full domain = slug.belsuite.com)
      const baseDomain = process.env.BELSUITE_BASE_DOMAIN || 'belsuite.com';
      await this.prisma.domainMapping.create({
        data: {
          organizationId: organization.id,
          subdomain: dto.slug,
          domain: `${dto.slug}.${baseDomain}`,
          domainType: 'SUBDOMAIN',
          isPrimary: true,
          isActive: true,
        },
      });

      this.logger.log(`Tenant created: ${organization.slug} (${organization.id})`);

      return organization;
    } catch (error) {
      this.logger.error(`Failed to create tenant: ${error.message}`, error.stack);
      throw error;
    }
  }

  /**
   * Get tenant by ID
   */
  async getTenant(organizationId: string): Promise<any> {
    const tenant = await this.prisma.organization.findUnique({
      where: { id: organizationId },
      include: {
        tenantOnboarding: true,
        tenantRateLimits: true,
        tenantDomains: {
          where: { isActive: true },
        },
      },
    });

    if (!tenant) {
      throw new NotFoundException(`Tenant not found: ${organizationId}`);
    }

    return tenant;
  }

  /**
   * Get tenant by slug
   */
  async getTenantBySlug(slug: string): Promise<any> {
    const tenant = await this.prisma.organization.findUnique({
      where: { slug },
      include: {
        tenantOnboarding: true,
        tenantRateLimits: true,
        tenantDomains: {
          where: { isActive: true },
        },
      },
    });

    if (!tenant) {
      throw new NotFoundException(`Tenant not found: ${slug}`);
    }

    return tenant;
  }

  /**
   * List all tenants (admin only)
   */
  async listTenants(skip: number = 0, take: number = 20): Promise<any> {
    const [tenants, total] = await Promise.all([
      this.prisma.organization.findMany({
        skip,
        take,
        include: {
          tenantOnboarding: true,
          tenantRateLimits: true,
        },
        orderBy: { createdAt: 'desc' },
      }),
      this.prisma.organization.count(),
    ]);

    return { tenants, total, skip, take };
  }

  /**
   * Update tenant
   */
  async updateTenant(organizationId: string, dto: UpdateTenantDto): Promise<any> {
    const tenant = await this.prisma.organization.update({
      where: { id: organizationId },
      data: {
        ...(dto.name && { name: dto.name }),
        ...(dto.tier && { tier: dto.tier.toUpperCase() as SubscriptionTier }),
        ...(dto.metadata && { metadata: dto.metadata }),
      },
      include: {
        tenantOnboarding: true,
        tenantRateLimits: true,
      },
    });

    this.logger.log(`Tenant updated: ${organizationId}`);

    return tenant;
  }

  /**
   * Delete tenant (soft delete)
   */
  async deleteTenant(organizationId: string): Promise<void> {
    await this.prisma.organization.update({
      where: { id: organizationId },
      data: {
        isActive: false,
        deletedAt: new Date(),
      },
    });

    this.logger.log(`Tenant deleted: ${organizationId}`);
  }

  /**
   * Get tenant usage metrics
   */
  async getTenantUsage(organizationId: string, month?: string): Promise<any> {
    const targetMonth = month || this.getCurrentMonth();

    const usage = await this.prisma.tenantUsage.findUnique({
      where: {
        organizationId_period: {
          organizationId,
          period: targetMonth,
        },
      },
    });

    if (!usage) {
      // Return zero usage if not tracked yet
      return {
        month: targetMonth,
        aiTokensUsed: 0,
        aiRequestsCount: 0,
        storageUsedBytes: 0,
        apiCallsCount: 0,
        emailsSent: 0,
        emailsDelivered: 0,
        emailsBounced: 0,
        emailsOpened: 0,
        emailsClicked: 0,
        contentCount: 0,
        activeUsers: 0,
        estimatedCost: 0,
      };
    }

    return usage;
  }

  /**
   * Get tenant usage history (last 12 months)
   */
  async getTenantUsageHistory(organizationId: string): Promise<any[]> {
    const startMonth = this.getMonthsAgo(12);

    const usage = await this.prisma.tenantUsage.findMany({
      where: {
        organizationId,
        period: {
          gte: startMonth,
        },
      },
      orderBy: { period: 'desc' },
      take: 12,
    });

    return usage;
  }

  /**
   * Validate slug format
   */
  private isValidSlug(slug: string): boolean {
    const slugRegex = /^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/;
    return (
      slugRegex.test(slug) &&
      slug.length >= 3 &&
      slug.length <= 63 &&
      !slug.startsWith('-') &&
      !slug.endsWith('-')
    );
  }

  /**
   * Generate encryption key for tenant
   */
  private generateEncryptionKey(): string {
    return crypto.randomBytes(32).toString('hex');
  }

  /**
   * Get current month in YYYY-MM format
   */
  private getCurrentMonth(): string {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  }

  /**
   * Get month N months ago
   */
  private getMonthsAgo(months: number): string {
    const date = new Date();
    date.setMonth(date.getMonth() - months);
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
  }
}

/**
 * Usage Tracking Service
 * Tracks per-tenant consumption metrics for billing and usage reports
 */

import { Injectable, Logger } from '@nestjs/common';
import { PrismaService } from '../../database/prisma.service';
import { Cron, CronExpression } from '@nestjs/schedule';

export interface UsageMetrics {
  month: string;
  aiTokensUsed: number;
  aiRequestsCount: number;
  storageUsedBytes: number;
  apiCallsCount: number;
  emailsSent: number;
  emailsDelivered: number;
  emailsBounced: number;
  emailsOpened: number;
  emailsClicked: number;
  contentCount: number;
  activeUsers: number;
  estimatedCost: number;
}

export interface UsageAlert {
  type: 'WARNING' | 'CRITICAL' | 'EXCEEDED';
  metric: string;
  current: number;
  limit: number;
  percentageOfLimit: number;
  message: string;
}

@Injectable()
export class UsageTrackingService {
  private readonly logger = new Logger(UsageTrackingService.name);

  // Pricing per unit
  private readonly pricing = {
    aiTokens: 0.0001, // $0.0001 per 1000 tokens
    apiCalls: 0.001, // $0.001 per 1000 calls
    storageGB: 0.1, // $0.10 per GB per month
    emailSent: 0.001, // $0.001 per email
  };

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Record AI token usage
   */
  async recordAiTokens(organizationId: string, tokens: number): Promise<void> {
    await this.recordMetric(organizationId, 'aiTokensUsed', tokens);
  }

  /**
   * Record AI request
   */
  async recordAiRequest(organizationId: string): Promise<void> {
    await this.recordMetric(organizationId, 'aiRequestsCount', 1);
  }

  /**
   * Record API call
   */
  async recordApiCall(organizationId: string): Promise<void> {
    await this.recordMetric(organizationId, 'apiCallsCount', 1);
  }

  /**
   * Record email sent
   */
  async recordEmailSent(organizationId: string): Promise<void> {
    await this.recordMetric(organizationId, 'emailsSent', 1);
  }

  /**
   * Record email event
   */
  async recordEmailEvent(
    organizationId: string,
    eventType: 'DELIVERED' | 'BOUNCED' | 'OPENED' | 'CLICKED',
  ): Promise<void> {
    const fieldMap = {
      DELIVERED: 'emailsDelivered',
      BOUNCED: 'emailsBounced',
      OPENED: 'emailsOpened',
      CLICKED: 'emailsClicked',
    };

    await this.recordMetric(organizationId, fieldMap[eventType], 1);
  }

  /**
   * Record storage usage
   */
  async recordStorageUsage(organizationId: string, bytes: number): Promise<void> {
    // Convert to GB and record
    const gb = bytes / (1024 * 1024 * 1024);
    await this.recordMetric(organizationId, 'storageUsedBytes', bytes);
  }

  /**
   * Record content creation
   */
  async recordContentCreated(organizationId: string): Promise<void> {
    await this.recordMetric(organizationId, 'contentCount', 1);
  }

  /**
   * Record active user
   */
  async recordActiveUser(organizationId: string): Promise<void> {
    // This is more complex - would need to dedup users
    // For now just record
    await this.recordMetric(organizationId, 'activeUsers', 1);
  }

  /**
   * Get usage for current month
   */
  async getCurrentMonthUsage(organizationId: string): Promise<UsageMetrics> {
    const month = this.getCurrentMonth();
    return this.getMonthUsage(organizationId, month);
  }

  /**
   * Get usage for specific month
   */
  async getMonthUsage(organizationId: string, month: string): Promise<UsageMetrics> {
    const usage = await this.prisma.tenantUsage.findUnique({
      where: {
        organizationId_period: {
          organizationId,
          period: month,
        },
      },
    });

    if (!usage) {
      return this.getEmptyUsage(month);
    }

    // Calculate estimated cost
    const estimatedCost = this.calculateCost(usage);

    return {
      month: usage.period,
      aiTokensUsed: usage.aiTokensUsed || 0,
      aiRequestsCount: usage.aiRequestsCount || 0,
      storageUsedBytes: Number(usage.storageUsedBytes || 0),
      apiCallsCount: usage.apiCallsCount || 0,
      emailsSent: usage.emailsSent || 0,
      emailsDelivered: usage.emailsDelivered || 0,
      emailsBounced: usage.emailsBounced || 0,
      emailsOpened: usage.emailsOpened || 0,
      emailsClicked: usage.emailsClicked || 0,
      contentCount: usage.contentCount || 0,
      activeUsers: usage.activeUsers || 0,
      estimatedCost,
    };
  }

  /**
   * Get usage history
   */
  async getUsageHistory(
    organizationId: string,
    months: number = 12,
  ): Promise<UsageMetrics[]> {
    const startMonth = this.getMonthsAgo(months);

    const usage = await this.prisma.tenantUsage.findMany({
      where: {
        organizationId,
        period: {
          gte: startMonth,
        },
      },
      orderBy: { period: 'desc' },
      take: months,
    });

    return usage.map(u => ({
      month: u.period,
      aiTokensUsed: u.aiTokensUsed || 0,
      aiRequestsCount: u.aiRequestsCount || 0,
      storageUsedBytes: Number(u.storageUsedBytes || 0),
      apiCallsCount: u.apiCallsCount || 0,
      emailsSent: u.emailsSent || 0,
      emailsDelivered: u.emailsDelivered || 0,
      emailsBounced: u.emailsBounced || 0,
      emailsOpened: u.emailsOpened || 0,
      emailsClicked: u.emailsClicked || 0,
      contentCount: u.contentCount || 0,
      activeUsers: u.activeUsers || 0,
      estimatedCost: this.calculateCost(u),
    }));
  }

  /**
   * Get usage alerts for tenant
   */
  async getUsageAlerts(organizationId: string): Promise<UsageAlert[]> {
    const usage = await this.getCurrentMonthUsage(organizationId);
    const quotas = await this.prisma.tenantRateLimitQuota.findUnique({
      where: { organizationId },
    });

    if (!quotas) {
      return [];
    }

    const alerts: UsageAlert[] = [];

    // Check storage
    const storageGB = usage.storageUsedBytes / (1024 * 1024 * 1024);
    const storagePercentage = (storageGB / quotas.maxStorageGB) * 100;

    if (storagePercentage >= 100) {
      alerts.push({
        type: 'EXCEEDED',
        metric: 'Storage',
        current: storageGB,
        limit: quotas.maxStorageGB,
        percentageOfLimit: storagePercentage,
        message: `Storage limit exceeded: ${storageGB.toFixed(2)}GB / ${quotas.maxStorageGB}GB`,
      });
    } else if (storagePercentage >= 90) {
      alerts.push({
        type: 'CRITICAL',
        metric: 'Storage',
        current: storageGB,
        limit: quotas.maxStorageGB,
        percentageOfLimit: storagePercentage,
        message: `Storage usage critical: ${storageGB.toFixed(2)}GB / ${quotas.maxStorageGB}GB (90%)`,
      });
    } else if (storagePercentage >= 75) {
      alerts.push({
        type: 'WARNING',
        metric: 'Storage',
        current: storageGB,
        limit: quotas.maxStorageGB,
        percentageOfLimit: storagePercentage,
        message: `Approaching storage limit: ${storageGB.toFixed(2)}GB / ${quotas.maxStorageGB}GB (75%)`,
      });
    }

    // Check AI tokens
    if (quotas.aiTokensPerDay) {
      const aiTokenPercentage = (usage.aiTokensUsed / quotas.aiTokensPerDay) * 100;

      if (aiTokenPercentage >= 100) {
        alerts.push({
          type: 'EXCEEDED',
          metric: 'AI Tokens',
          current: usage.aiTokensUsed,
          limit: quotas.aiTokensPerDay,
          percentageOfLimit: aiTokenPercentage,
          message: `Daily AI token limit exceeded`,
        });
      } else if (aiTokenPercentage >= 90) {
        alerts.push({
          type: 'CRITICAL',
          metric: 'AI Tokens',
          current: usage.aiTokensUsed,
          limit: quotas.aiTokensPerDay,
          percentageOfLimit: aiTokenPercentage,
          message: `Daily AI token usage critical (90%)`,
        });
      }
    }

    return alerts;
  }

  /**
   * Export usage report
   */
  async exportUsageReport(organizationId: string, format: 'csv' | 'json' = 'json'): Promise<any> {
    const history = await this.getUsageHistory(organizationId, 12);

    if (format === 'csv') {
      return this.convertToCsv(history);
    }

    return history;
  }

  /**
   * Get usage summary by plan
   */
  async getUsageSummary(organizationId: string): Promise<any> {
    const current = await this.getCurrentMonthUsage(organizationId);
    const history = await this.getUsageHistory(organizationId, 12);

    const avgMonthlyUsage = {
      aiTokens: Math.round(
        history.reduce((sum, m) => sum + m.aiTokensUsed, 0) / history.length,
      ),
      apiCalls: Math.round(
        history.reduce((sum, m) => sum + m.apiCallsCount, 0) / history.length,
      ),
      emails: Math.round(
        history.reduce((sum, m) => sum + m.emailsSent, 0) / history.length,
      ),
      storageGB: Math.round(
        (history.reduce((sum, m) => sum + m.storageUsedBytes, 0) / history.length) /
          (1024 * 1024 * 1024),
      ),
    };

    const monthlyTrend =
      history.length > 1
        ? (
            (history[0].estimatedCost - history[1].estimatedCost) /
            history[1].estimatedCost
          ) * 100
        : 0;

    return {
      current,
      avgMonthlyUsage,
      monthlyTrend: `${monthlyTrend.toFixed(1)}%`,
      thirtyDayEstimatedCost: history
        .slice(0, Math.min(30, history.length))
        .reduce((sum, m) => sum + m.estimatedCost, 0),
    };
  }

  /**
   * Record a generic metric
   */
  private async recordMetric(
    organizationId: string,
    field: string,
    increment: number,
  ): Promise<void> {
    try {
      const month = this.getCurrentMonth();

      await this.prisma.tenantUsage.upsert({
        where: {
          organizationId_period: {
            organizationId,
            period: month,
          },
        },
        update: {
          [field]: {
            increment,
          },
        },
        create: {
          organizationId,
          period: month,
          startDate: new Date(),
          endDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // 30 days from now
          [field]: increment,
          aiTokensUsed: 0,
          aiRequestsCount: 0,
          storageUsedBytes: 0,
          apiCallsCount: 0,
          emailsSent: 0,
          emailsDelivered: 0,
          emailsBounced: 0,
          emailsOpened: 0,
          emailsClicked: 0,
          contentCount: 0,
          activeUsers: 0,
          estimatedCost: 0,
        },
      });
    } catch (error) {
      this.logger.error(`Failed to record metric: ${error.message}`, error.stack);
      // Don't throw - usage tracking shouldn't break the app
    }
  }

  /**
   * Calculate estimated cost
   */
  private calculateCost(usage: any): number {
    let cost = 0;

    cost += (usage.aiTokensUsed || 0) * (this.pricing.aiTokens / 1000);
    cost += (usage.apiCallsCount || 0) * (this.pricing.apiCalls / 1000);
    cost += ((usage.storageUsedBytes || 0) / (1024 * 1024 * 1024)) * this.pricing.storageGB;
    cost += (usage.emailsSent || 0) * this.pricing.emailSent;

    return Math.round(cost * 100) / 100; // Round to 2 decimals
  }

  /**
   * Get current month in YYYY-MM format
   */
  private getCurrentMonth(): string {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  }

  /**
   * Get month N months ago
   */
  private getMonthsAgo(months: number): string {
    const date = new Date();
    date.setMonth(date.getMonth() - months);
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
  }

  /**
   * Get empty usage object
   */
  private getEmptyUsage(month: string): UsageMetrics {
    return {
      month,
      aiTokensUsed: 0,
      aiRequestsCount: 0,
      storageUsedBytes: 0,
      apiCallsCount: 0,
      emailsSent: 0,
      emailsDelivered: 0,
      emailsBounced: 0,
      emailsOpened: 0,
      emailsClicked: 0,
      contentCount: 0,
      activeUsers: 0,
      estimatedCost: 0,
    };
  }

  /**
   * Convert to CSV
   */
  private convertToCsv(data: UsageMetrics[]): string {
    const headers = Object.keys(data[0]).join(',');
    const rows = data.map(item => Object.values(item).join(',')).join('\n');
    return `${headers}\n${rows}`;
  }

  /**
   * Cleanup old records (runs monthly)
   */
  @Cron(CronExpression.EVERY_1ST_DAY_OF_MONTH_AT_MIDNIGHT)
  async cleanupOldRecords(): Promise<void> {
    const twoYearsAgo = new Date();
    twoYearsAgo.setFullYear(twoYearsAgo.getFullYear() - 2);

    const result = await this.prisma.tenantUsage.deleteMany({
      where: {
        startDate: {
          lt: twoYearsAgo,
        },
      },
    });

    this.logger.log(`Cleaned up ${result.count} old usage records`);
  }
}

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
} from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { CreateOrganizationDto, UpdateOrganizationDto, InviteMemberDto, UpdateMemberRoleDto } from './dto/organization.dto';
import { PaginationUtil } from '../common/utils/pagination.util';
import { v4 as uuidv4 } from 'uuid';

@Injectable()
export class OrganizationsService {
  constructor(private prisma: PrismaService) {}

  /**
   * Create new organization
   */
  async createOrganization(
    userId: string,
    createDto: CreateOrganizationDto,
  ) {
    const org = await this.prisma.$transaction(async (tx) => {
      // Create organization
      const organization = await tx.organization.create({
        data: {
          name: createDto.name,
          slug: this.generateSlug(createDto.name),
          description: createDto.description,
          website: createDto.website,
          status: 'ACTIVE',
          tier: 'FREE',
        },
      });

      // Create admin role
      const adminRole = await tx.role.create({
        data: {
          organizationId: organization.id,
          name: 'Admin',
          isSystem: true,
        },
      });

      // Create permissions
      const permissions = [
        'create:content',
        'read:content',
        'update:content',
        'delete:content',
        'manage:users',
        'manage:organization',
        'manage:billing',
      ];

      await Promise.all(
        permissions.map((action) =>
          tx.permission.create({
            data: {
              roleId: adminRole.id,
              action: action.split(':')[0],
              resource: action.split(':')[1],
            },
          }),
        ),
      );

      // Add creator as admin
      await tx.organizationMember.create({
        data: {
          organizationId: organization.id,
          userId,
          roleId: adminRole.id,
          status: 'ACTIVE',
          roleName: 'Admin',
          permissions,
        },
      });

      return organization;
    });

    return org;
  }

  /**
   * Get organization details
   */
  async getOrganization(organizationId: string, userId: string) {
    // Verify user belongs to organization
    const member = await this.prisma.organizationMember.findUnique({
      where: {
        organizationId_userId: { organizationId, userId },
      },
    });

    if (!member) {
      throw new ForbiddenException('Access denied');
    }

    const org = await this.prisma.organization.findUnique({
      where: { id: organizationId },
      select: {
        id: true,
        name: true,
        slug: true,
        description: true,
        logo: true,
        website: true,
        tier: true,
        maxMembers: true,
        maxProjects: true,
        maxStorageGB: true,
        usedStorageGB: true,
        createdAt: true,
      },
    });

    if (!org) {
      throw new NotFoundException('Organization not found');
    }

    return org;
  }

  /**
   * Update organization
   */
  async updateOrganization(
    organizationId: string,
    userId: string,
    updateDto: UpdateOrganizationDto,
  ) {
    // Verify user is admin
    await this.verifyOrgAdmin(organizationId, userId);

    const org = await this.prisma.organization.update({
      where: { id: organizationId },
      data: updateDto,
      select: {
        id: true,
        name: true,
        slug: true,
        description: true,
        logo: true,
        website: true,
        tier: true,
      },
    });

    return org;
  }

  /**
   * Invite member to organization
   */
  async inviteMember(
    organizationId: string,
    userId: string,
    inviteDto: InviteMemberDto,
  ) {
    // Verify user is admin
    await this.verifyOrgAdmin(organizationId, userId);

    // Check if user already exists
    const existingMember = await this.prisma.organizationMember.findUnique({
      where: {
        organizationId_userId: {
          organizationId,
          userId: inviteDto.email, // This won't work, need to find by email first
        },
      },
    });

    // Check if already invited
    const existingInvitation = await this.prisma.invitation.findUnique({
      where: {
        organizationId_invitedEmail: {
          organizationId,
          invitedEmail: inviteDto.email,
        },
      },
    });

    if (existingInvitation && existingInvitation.status === 'PENDING') {
      throw new BadRequestException('User already invited');
    }

    const user = await this.prisma.user.findUnique({
      where: { email: inviteDto.email },
    });

    if (user) {
      // User exists, add directly
      const roleId = inviteDto.roleId || (await this.getDefaultRoleId(organizationId));

      await this.prisma.organizationMember.create({
        data: {
          organizationId,
          userId: user.id,
          roleId,
          status: 'ACTIVE',
        },
      });

      return { invitationSent: false, memberAdded: true };
    }

    // User doesn't exist, send invitation
    const roleId = inviteDto.roleId || (await this.getDefaultRoleId(organizationId));
    const token = uuidv4();
    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); // 7 days

    await this.prisma.invitation.create({
      data: {
        organizationId,
        invitedEmail: inviteDto.email,
        roleId,
        invitedBy: userId,
        status: 'PENDING',
        token,
        expiresAt,
      },
    });

    // TODO: Send invitation email with token

    return { invitationSent: true, studentId: token };
  }

  /**
   * Accept invitation
   */
  async acceptInvitation(token: string, userId: string) {
    const invitation = await this.prisma.invitation.findUnique({
      where: { token },
    });

    if (!invitation) {
      throw new NotFoundException('Invalid invitation');
    }

    if (invitation.status !== 'PENDING') {
      throw new BadRequestException('Invitation already used or expired');
    }

    if (invitation.expiresAt < new Date()) {
      throw new BadRequestException('Invitation expired');
    }

    const user = await this.prisma.user.findUnique({
      where: { id: userId },
    });

    if (user?.email !== invitation.invitedEmail) {
      throw new ForbiddenException('Invitation email does not match');
    }

    // Add user to organization
    const member = await this.prisma.organizationMember.create({
      data: {
        organizationId: invitation.organizationId,
        userId,
        roleId: invitation.roleId,
        status: 'ACTIVE',
      },
    });

    // Mark invitation as accepted
    await this.prisma.invitation.update({
      where: { id: invitation.id },
      data: {
        status: 'ACCEPTED',
        acceptedAt: new Date(),
        acceptedByUserId: userId,
      },
    });

    return member;
  }

  /**
   * Update member role
   */
  async updateMemberRole(
    organizationId: string,
    userId: string,
    targetUserId: string,
    updateDto: UpdateMemberRoleDto,
  ) {
    // Verify user is admin
    await this.verifyOrgAdmin(organizationId, userId);

    // Prevent changing own role
    if (userId === targetUserId) {
      throw new ForbiddenException('Cannot change own role');
    }

    const member = await this.prisma.organizationMember.update({
      where: {
        organizationId_userId: { organizationId, userId: targetUserId },
      },
      data: { roleId: updateDto.roleId },
      include: { role: true },
    });

    return member;
  }

  /**
   * Verify user is organization admin
   */
  private async verifyOrgAdmin(organizationId: string, userId: string) {
    const member = await this.prisma.organizationMember.findUnique({
      where: {
        organizationId_userId: { organizationId, userId },
      },
      include: { role: true },
    });

    if (!member || !member.role.isSystem) {
      throw new ForbiddenException('Only admins can perform this action');
    }
  }

  /**
   * Get default role for organization
   */
  private async getDefaultRoleId(organizationId: string): Promise<string> {
    const roles = await this.prisma.role.findMany({
      where: { organizationId },
      select: { id: true },
      take: 1,
    });

    if (roles.length === 0) {
      throw new NotFoundException('No roles found for organization');
    }

    return roles[0].id;
  }

  /**
   * Generate slug from name
   */
  private generateSlug(name: string): string {
    const base = name
      .toLowerCase()
      .replace(/[^a-z0-9]/g, '-')
      .replace(/-+/g, '-')
      .replace(/^-|-$/g, '');
    const timestamp = Date.now().toString(36);
    return `${base}-${timestamp}`;
  }
}

/**
 * Payment API Controller
 * Exposes payment endpoints with multi-provider support
 */

import {
  Controller,
  Post,
  Get,
  Body,
  Param,
  Headers,
  Query,
  UseGuards,
  BadRequestException,
  Logger,
  RawBody,
  Req,
} from '@nestjs/common';
import { Request } from 'express';
import { PaymentService } from './payment.service';
import { WebhookHandlers } from './webhooks/webhook.handlers';
import { JwtAuthGuard } from '../common/guards/jwt.guard';
import { TenantGuard } from '../common/guards/tenant.guard';
import { Tenant } from '../common/decorators/tenant.decorator';
import { CurrentUser } from '../common/decorators/user.decorator';
import {
  CreatePaymentDto,
  RefundPaymentDto,
  CreateCustomerDto,
  AddPaymentMethodDto,
  CreateSubscriptionDto,
  CancelSubscriptionDto,
  VerifyPaymentDto,
} from './dto/payment.dto';
import { PaymentProvider } from './types/payment.types';

@Controller('api/v1/payments')
export class PaymentController {
  private readonly logger = new Logger(PaymentController.name);

  constructor(
    private paymentService: PaymentService,
    private webhookHandlers: WebhookHandlers,
  ) {}

  /**
   * Get available payment providers
   */
  @Get('providers')
  getAvailableProviders() {
    return {
      providers: this.paymentService.getAvailableProviders(),
      message: 'Available payment providers',
    };
  }

  /**
   * Create a payment with specified provider
   */
  @Post('create')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async createPayment(
    @Tenant() organizationId: string,
    @CurrentUser('sub') userId: string,
    @Body() dto: CreatePaymentDto,
  ) {
    if (!dto.provider || !Object.values(PaymentProvider).includes(dto.provider)) {
      throw new BadRequestException('Invalid payment provider');
    }

    if (!dto.subscriptionId || !dto.amount) {
      throw new BadRequestException('Missing required fields');
    }

    this.logger.log(
      `Creating payment with ${dto.provider} for org ${organizationId}`,
    );

    try {
      const payment = await this.paymentService.createPayment(dto.provider, {
        organizationId,
        subscriptionId: dto.subscriptionId,
        amount: dto.amount,
        currency: dto.currency || 'USD',
        metadata: {
          ...dto.metadata,
          userId,
        },
      });

      return {
        success: true,
        data: payment,
      };
    } catch (error) {
      this.logger.error(`Payment creation failed: ${error.message}`);
      throw new BadRequestException(`Payment creation failed: ${error.message}`);
    }
  }

  /**
   * Verify payment status
   */
  @Post('verify')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async verifyPayment(
    @Tenant() _organizationId: string,
    @Body() dto: VerifyPaymentDto,
  ) {
    try {
      const payment = await this.paymentService.getPayment(
        dto.provider,
        dto.paymentId,
      );

      return {
        success: true,
        data: payment,
      };
    } catch (error) {
      throw new BadRequestException(
        `Payment verification failed: ${error.message}`,
      );
    }
  }

  /**
   * Refund a payment
   */
  @Post('refund')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async refundPayment(
    @Tenant() _organizationId: string,
    @Body() dto: RefundPaymentDto,
  ) {
    if (!dto.paymentId) {
      throw new BadRequestException('Payment ID is required');
    }

    try {
      const refund = await this.paymentService.refundPayment(
        PaymentProvider.STRIPE,
        {
          paymentId: dto.paymentId,
          amount: dto.amount,
          reason: dto.reason,
        },
      );

      return {
        success: true,
        data: refund,
      };
    } catch (error) {
      throw new BadRequestException(`Refund failed: ${error.message}`);
    }
  }

  /**
   * Create a customer
   */
  @Post('customers/create')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async createCustomer(
    @Tenant() organizationId: string,
    @Body() dto: CreateCustomerDto,
  ) {
    if (!dto.provider || !dto.email || !dto.name) {
      throw new BadRequestException('Missing required fields');
    }

    try {
      // Get provider
      const provider = dto.provider;

      const customer = await this.paymentService.getProvider(provider)
        .createCustomer({
        organizationId,
        email: dto.email,
        name: dto.name,
        description: dto.description,
      });

      return {
        success: true,
        data: customer,
      };
    } catch (error) {
      throw new BadRequestException(
        `Customer creation failed: ${error.message}`,
      );
    }
  }

  /**
   * Add payment method to customer
   */
  @Post('payment-methods/add')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async addPaymentMethod(
    @Tenant() _organizationId: string,
    @Body() dto: AddPaymentMethodDto,
  ) {
    if (
      !dto.customerId ||
      !dto.provider ||
      !dto.type ||
      !dto.billingEmail ||
      !dto.billingName
    ) {
      throw new BadRequestException('Missing required fields');
    }

    try {
      const provider = dto.provider;

      const paymentMethod = await this.paymentService.getProvider(provider)
        .addPaymentMethod(dto.customerId, {
        provider,
        type: dto.type,
        billingDetails: {
          billingEmail: dto.billingEmail,
          billingName: dto.billingName,
          billingAddress: dto.billingAddress,
          billingCity: dto.billingCity,
          billingState: dto.billingState,
          billingZip: dto.billingZip,
          billingCountry: dto.billingCountry,
        },
      });

      return {
        success: true,
        data: paymentMethod,
      };
    } catch (error) {
      throw new BadRequestException(
        `Payment method creation failed: ${error.message}`,
      );
    }
  }

  /**
   * Create subscription
   */
  @Post('subscriptions/create')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async createSubscription(
    @Tenant() organizationId: string,
    @Body() dto: CreateSubscriptionDto,
  ) {
    if (
      !dto.provider ||
      !dto.customerId ||
      !dto.planId ||
      !dto.paymentMethodId
    ) {
      throw new BadRequestException('Missing required fields');
    }

    try {
      const subscription = await this.paymentService.createSubscription(
        dto.provider,
        organizationId,
        dto.customerId,
        dto.planId,
        dto.paymentMethodId,
        dto.trialDays,
      );

      return {
        success: true,
        data: subscription,
      };
    } catch (error) {
      throw new BadRequestException(
        `Subscription creation failed: ${error.message}`,
      );
    }
  }

  /**
   * Cancel subscription
   */
  @Post('subscriptions/cancel')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async cancelSubscription(
    @Tenant() organizationId: string,
    @Body() dto: CancelSubscriptionDto,
  ) {
    if (!dto.provider || !dto.externalSubscriptionId) {
      throw new BadRequestException('Missing required fields');
    }

    try {
      await this.paymentService.cancelSubscription(
        dto.provider,
        dto.externalSubscriptionId,
        organizationId,
      );

      return {
        success: true,
        message: 'Subscription cancelled successfully',
      };
    } catch (error) {
      throw new BadRequestException(
        `Subscription cancellation failed: ${error.message}`,
      );
    }
  }

  /**
   * Get payment statistics
   */
  @Get('statistics')
  @UseGuards(JwtAuthGuard, TenantGuard)
  async getPaymentStats(@Tenant() organizationId: string) {
    try {
      const stats = await this.paymentService.getPaymentStats(organizationId);

      return {
        success: true,
        data: stats,
      };
    } catch (error) {
      throw new BadRequestException(
        `Failed to retrieve statistics: ${error.message}`,
      );
    }
  }

  /**
   * Health check
   */
  @Get('health')
  async healthCheck() {
    try {
      const health = await this.paymentService.healthCheck();

      return {
        success: true,
        data: health,
      };
    } catch (error) {
      throw new BadRequestException(
        `Health check failed: ${error.message}`,
      );
    }
  }

  // ======================================================================
  // WEBHOOK ENDPOINTS
  // ======================================================================

  /**
   * Stripe webhook endpoint
   */
  @Post('webhooks/stripe')
  async stripeWebhook(
    @Headers('stripe-signature') signature: string,
    @Req() request: Request,
  ) {
    const body = Buffer.isBuffer((request as any).rawBody)
      ? (request as any).rawBody.toString('utf8')
      : ((request as any).rawBody || '');

    try {
      const result = await this.webhookHandlers.handleStripeWebhook(
        signature,
        body,
      );
      return result;
    } catch (error) {
      this.logger.error(`Stripe webhook error: ${error.message}`);
      throw error;
    }
  }

  /**
   * Paystack webhook endpoint
   */
  @Post('webhooks/paystack')
  async paystackWebhook(
    @Headers('x-paystack-signature') signature: string,
    @Body() body: Record<string, any>,
  ) {
    try {
      const result = await this.webhookHandlers.handlePaystackWebhook(
        signature,
        body,
      );
      return result;
    } catch (error) {
      this.logger.error(`Paystack webhook error: ${error.message}`);
      throw error;
    }
  }

  /**
   * Flutterwave webhook endpoint
   */
  @Post('webhooks/flutterwave')
  async flutterwaveWebhook(
    @Headers('verif-hash') signature: string,
    @Body() body: Record<string, any>,
  ) {
    try {
      const result = await this.webhookHandlers.handleFlutterwaveWebhook(
        signature,
        body,
      );
      return result;
    } catch (error) {
      this.logger.error(`Flutterwave webhook error: ${error.message}`);
      throw error;
    }
  }

  /**
   * PayPal webhook endpoint
   */
  @Post('webhooks/paypal')
  async paypalWebhook(
    @Headers('paypal-transmission-id') transmissionId: string,
    @Body() body: Record<string, any>,
  ) {
    try {
      const result = await this.webhookHandlers.handlePayPalWebhook(
        transmissionId,
        body,
      );
      return result;
    } catch (error) {
      this.logger.error(`PayPal webhook error: ${error.message}`);
      throw error;
    }
  }

  /**
   * Sofort webhook endpoint
   */
  @Post('webhooks/sofort')
  async sofortWebhook(
    @Headers('x-signature') signature: string,
    @Body() body: Record<string, any>,
  ) {
    try {
      const result = await this.webhookHandlers.handleSofortWebhook(
        signature,
        body,
      );
      return result;
    } catch (error) {
      this.logger.error(`Sofort webhook error: ${error.message}`);
      throw error;
    }
  }

  /**
   * Crypto webhook endpoint
   */
  @Post('webhooks/crypto')
  async cryptoWebhook(
    @Headers('x-cc-webhook-signature') signature: string,
    @Req() request: Request,
  ) {
    const body = Buffer.isBuffer((request as any).rawBody)
      ? (request as any).rawBody.toString('utf8')
      : ((request as any).rawBody || '');

    try {
      const result = await this.webhookHandlers.handleCryptoWebhook(
        signature,
        body,
      );
      return result;
    } catch (error) {
      this.logger.error(`Crypto webhook error: ${error.message}`);
      throw error;
    }
  }
}

/**
 * Payment Service - Orchestrates all payment providers
 * Routes requests to appropriate provider and manages payment lifecycle
 */

import { Injectable, Logger, BadRequestException } from '@nestjs/common';
import {
  PaymentProvider as PrismaPaymentProvider,
  PaymentStatus as PrismaPaymentStatus,
  RefundStatus as PrismaRefundStatus,
  SubscriptionStatus,
} from '@prisma/client';
import { PrismaService } from '../database/prisma.service';
import { IPaymentProvider } from './interfaces/payment-provider.interface';
import {
  PaymentProvider,
  PaymentStatus,
  RefundStatus,
  CreatePaymentRequest,
  PaymentResponse,
  RefundRequest,
  RefundResponse,
} from './types/payment.types';
import { StripeProvider } from './providers/stripe.provider';
import { PaystackProvider } from './providers/paystack.provider';
import { FlutterwaveProvider } from './providers/flutterwave.provider';
import { SofortProvider } from './providers/sofort.provider';
import { PayPalProvider } from './providers/paypal.provider';
import { CryptoProvider } from './providers/crypto.provider';

@Injectable()
export class PaymentService {
  private readonly logger = new Logger(PaymentService.name);
  private providers: Map<PaymentProvider, IPaymentProvider>;

  constructor(private prisma: PrismaService) {
    // Initialize all payment providers
    this.providers = new Map<PaymentProvider, IPaymentProvider>();
    this.providers.set(PaymentProvider.STRIPE, new StripeProvider());
    this.providers.set(PaymentProvider.PAYSTACK, new PaystackProvider());
    this.providers.set(PaymentProvider.FLUTTERWAVE, new FlutterwaveProvider());
    this.providers.set(PaymentProvider.PAYPAL, new PayPalProvider());
    this.providers.set(PaymentProvider.SOFORT, new SofortProvider());
    this.providers.set(PaymentProvider.CRYPTO, new CryptoProvider());
  }

  private toPrismaProvider(provider: PaymentProvider): PrismaPaymentProvider {
    return provider.toUpperCase() as PrismaPaymentProvider;
  }

  private toPrismaPaymentStatus(status: PaymentStatus): PrismaPaymentStatus {
    return status.toUpperCase() as PrismaPaymentStatus;
  }

  private toPrismaRefundStatus(status: RefundStatus): PrismaRefundStatus {
    return status.toUpperCase() as PrismaRefundStatus;
  }

  private subscriptionIdField(provider: PaymentProvider) {
    const map: Record<PaymentProvider, string | null> = {
      [PaymentProvider.STRIPE]: 'stripeSubscriptionId',
      [PaymentProvider.PAYSTACK]: 'paystackSubscriptionId',
      [PaymentProvider.FLUTTERWAVE]: 'flutterSubscriptionId',
      [PaymentProvider.PAYPAL]: 'paypalSubscriptionId',
      [PaymentProvider.SOFORT]: 'sofortSubscriptionId',
      [PaymentProvider.CRYPTO]: null,
    };

    return map[provider];
  }

  /**
   * Get a payment provider by type
   */
  getProvider(provider: PaymentProvider): IPaymentProvider {
    const paymentProvider = this.providers.get(provider);
    if (!paymentProvider) {
      throw new BadRequestException(
        `Unsupported payment provider: ${provider}`,
      );
    }
    return paymentProvider;
  }

  /**
   * Get all available payment providers
   */
  getAvailableProviders(): PaymentProvider[] {
    return Array.from(this.providers.keys());
  }

  /**
   * Create a payment with specified provider
   */
  async createPayment(
    provider: PaymentProvider,
    request: CreatePaymentRequest,
  ): Promise<PaymentResponse> {
    try {
      this.logger.log(
        `Creating payment with ${provider} for subscription ${request.subscriptionId}`,
      );

      const paymentProvider = this.getProvider(provider);
      const paymentResponse = await paymentProvider.createPayment(request);

      // Store payment in database
      await this.prisma.payment.create({
        data: {
          subscriptionId: request.subscriptionId,
          invoiceId: request.invoiceId,
          provider: this.toPrismaProvider(provider),
          externalPaymentId: paymentResponse.externalPaymentId,
          amount: paymentResponse.amount,
          currency: paymentResponse.currency,
          status: this.toPrismaPaymentStatus(paymentResponse.status),
          providerResponse: JSON.stringify(paymentResponse),
          attemptNumber: 1,
        },
      });

      return paymentResponse;
    } catch (error) {
      this.logger.error(`Payment creation failed: ${error.message}`);
      throw error;
    }
  }

  /**
   * Get payment details
   */
  async getPayment(provider: PaymentProvider, externalPaymentId: string) {
    try {
      const paymentProvider = this.getProvider(provider);
      return await paymentProvider.getPayment(externalPaymentId);
    } catch (error) {
      this.logger.error(`Failed to fetch payment: ${error.message}`);
      throw error;
    }
  }

  /**
   * Refund a payment
   */
  async refundPayment(
    provider: PaymentProvider,
    request: RefundRequest,
  ): Promise<RefundResponse> {
    try {
      this.logger.log(`Refunding payment ${request.paymentId} with ${provider}`);

      // Get payment from database
      const payment = await this.prisma.payment.findUnique({
        where: { id: request.paymentId },
      });

      if (!payment) {
        throw new BadRequestException('Payment not found');
      }

      if (!payment.externalPaymentId) {
        throw new BadRequestException('Payment does not have an external payment identifier');
      }

      const paymentProvider = this.getProvider(provider);
      const refundResponse = await paymentProvider.refundPayment({
        ...request,
        paymentId: payment.externalPaymentId,
      });

      // Store refund in database
      await this.prisma.paymentRefund.create({
        data: {
          paymentId: request.paymentId,
          provider: this.toPrismaProvider(provider),
          externalRefundId: refundResponse.externalRefundId,
          amount: refundResponse.amount,
          currency: refundResponse.currency,
          status: this.toPrismaRefundStatus(refundResponse.status),
          reason: request.reason,
        },
      });

      // Update payment refunded amount
      const currentRefunded =
        payment.refundedAmount + refundResponse.amount;
      await this.prisma.payment.update({
        where: { id: request.paymentId },
        data: {
          refundedAmount: currentRefunded,
          status:
            currentRefunded >= payment.amount
              ? this.toPrismaPaymentStatus(PaymentStatus.REFUNDED)
              : this.toPrismaPaymentStatus(PaymentStatus.PARTIALLY_REFUNDED),
        },
      });

      return refundResponse;
    } catch (error) {
      this.logger.error(`Refund failed: ${error.message}`);
      throw error;
    }
  }

  /**
   * Create a recurring subscription
   */
  async createSubscription(
    provider: PaymentProvider,
    organizationId: string,
    customerId: string,
    planId: string,
    paymentMethodId: string,
    trialDays?: number,
  ) {
    try {
      this.logger.log(
        `Creating subscription with ${provider} for organization ${organizationId}`,
      );

      const paymentProvider = this.getProvider(provider);

      const subscriptionResponse = await paymentProvider.createSubscription({
        organizationId,
        customerId,
        planId,
        paymentMethodId,
        trialDays,
      });

      // Update subscription in database
      const subscription = await this.prisma.subscription.findUnique({
        where: { organizationId },
      });

      if (subscription) {
        const subscriptionIdField = this.subscriptionIdField(provider);
        await this.prisma.subscription.update({
          where: { organizationId },
          data: {
            ...(subscriptionIdField
              ? { [subscriptionIdField]: subscriptionResponse.externalSubscriptionId }
              : {}),
            primaryPaymentMethod: this.toPrismaProvider(provider),
            currentPeriodStart: subscriptionResponse.currentPeriodStart,
            currentPeriodEnd: subscriptionResponse.currentPeriodEnd,
            status:
              trialDays && trialDays > 0
                ? SubscriptionStatus.TRIAL
                : SubscriptionStatus.ACTIVE,
          },
        });
      }

      return subscriptionResponse;
    } catch (error) {
      this.logger.error(`Subscription creation failed: ${error.message}`);
      throw error;
    }
  }

  /**
   * Cancel subscription
   */
  async cancelSubscription(
    provider: PaymentProvider,
    externalSubscriptionId: string,
    organizationId: string,
  ) {
    try {
      this.logger.log(`Cancelling subscription with ${provider}`);

      const paymentProvider = this.getProvider(provider);
      await paymentProvider.cancelSubscription(externalSubscriptionId);

      // Update subscription status in database
      await this.prisma.subscription.update({
        where: { organizationId },
        data: {
          status: SubscriptionStatus.CANCELLED,
          cancelledAt: new Date(),
        },
      });
    } catch (error) {
      this.logger.error(`Subscription cancellation failed: ${error.message}`);
      throw error;
    }
  }

  /**
   * Verify webhook signature
   */
  async verifyWebhookSignature(
    provider: PaymentProvider,
    signature: string,
    payload: string,
  ) {
    try {
      const paymentProvider = this.getProvider(provider);
      return await paymentProvider.verifyWebhookSignature({
        provider,
        signature,
        payload,
      });
    } catch (error) {
      this.logger.error(`Webhook verification failed: ${error.message}`);
      throw error;
    }
  }

  /**
   * Handle webhook event
   */
  async handleWebhookEvent(provider: PaymentProvider, rawPayload: any) {
    try {
      this.logger.log(`Processing webhook from ${provider}`);

      const paymentProvider = this.getProvider(provider);
      const event = await paymentProvider.parseWebhookPayload(rawPayload);

      // Store webhook record
      await this.prisma.paymentWebhook.create({
        data: {
          provider: this.toPrismaProvider(provider),
          externalWebhookId: event.externalWebhookId,
          eventType: event.type,
          paymentId: event.externalPaymentId
            ? (
              await this.prisma.payment.findFirst({
                where: { externalPaymentId: event.externalPaymentId },
              })
            )?.id
            : undefined,
          data: JSON.stringify(event.raw),
          status: 'RECEIVED',
        },
      });

      // Process event based on type
      await this.processPaymentEvent(provider, event);

      return true;
    } catch (error) {
      this.logger.error(`Webhook handling failed: ${error.message}`);
      throw error;
    }
  }

  /**
   * Process payment event from webhook
   */
  private async processPaymentEvent(provider: PaymentProvider, event: any) {
    switch (event.type) {
      case 'charge.success':
      case 'charge.completed':
      case 'charge:confirmed':
      case 'charge:resolved':
      case 'payment_intent.succeeded':
      case 'invoice.paid':
        await this.handlePaymentSuccess(event);
        break;

      case 'charge.failed':
      case 'charge:failed':
      case 'charge:delayed':
      case 'charge:expired':
      case 'payment_intent.payment_failed':
      case 'invoice.payment_failed':
        await this.handlePaymentFailure(event);
        break;

      case 'charge.refunded':
      case 'charge.dispute.created':
        await this.handleRefund(event);
        break;

      case 'customer.subscription.deleted':
      case 'subscription.cancelled':
        await this.handleSubscriptionCancelled(event);
        break;

      default:
        this.logger.debug(`Ignoring webhook event: ${event.type}`);
    }
  }

  /**
   * Handle successful payment
   */
  private async handlePaymentSuccess(event: any) {
    const payment = await this.prisma.payment.findFirst({
      where: { externalPaymentId: event.externalPaymentId },
      include: {
        subscription: {
          include: {
            plan: true,
            organization: true,
          },
        },
      },
    });

    if (payment) {
      await this.prisma.payment.update({
        where: { id: payment.id },
        data: {
          status: this.toPrismaPaymentStatus(PaymentStatus.COMPLETED),
          paidAt: new Date(),
        },
      });

      if (payment.invoiceId) {
        await this.prisma.invoice.updateMany({
          where: { id: payment.invoiceId },
          data: {
            status: 'PAID',
            paidAt: new Date(),
          },
        });
      }

      await this.prisma.subscription.update({
        where: { id: payment.subscriptionId },
        data: {
          status: SubscriptionStatus.ACTIVE,
        },
      });

      if (payment.subscription.plan?.tier) {
        await this.prisma.organization.update({
          where: { id: payment.subscription.organizationId },
          data: {
            tier: payment.subscription.plan.tier,
          },
        });
      }

      this.logger.log(`Payment ${payment.id} completed`);
    }
  }

  /**
   * Handle failed payment
   */
  private async handlePaymentFailure(event: any) {
    const payment = await this.prisma.payment.findFirst({
      where: { externalPaymentId: event.externalPaymentId },
    });

    if (payment && payment.attemptNumber < payment.maxRetries) {
      // Retry payment after 1 hour
      await this.prisma.payment.update({
        where: { id: payment.id },
        data: {
          status: this.toPrismaPaymentStatus(PaymentStatus.FAILED),
          attemptNumber: { increment: 1 },
          nextRetryAt: new Date(Date.now() + 60 * 60 * 1000),
          failureReason: event.failureReason,
        },
      });

      if (payment.invoiceId) {
        await this.prisma.invoice.updateMany({
          where: { id: payment.invoiceId },
          data: {
            status: 'FAILED',
          },
        });
      }

      await this.prisma.subscription.update({
        where: { id: payment.subscriptionId },
        data: {
          status: SubscriptionStatus.PAST_DUE,
        },
      });

      this.logger.log(`Payment ${payment.id} failed, scheduled for retry`);
    } else if (payment) {
      // Max retries exceeded
      await this.prisma.payment.update({
        where: { id: payment.id },
        data: {
          status: this.toPrismaPaymentStatus(PaymentStatus.FAILED),
          failureReason: 'Max retries exceeded',
        },
      });

      if (payment.invoiceId) {
        await this.prisma.invoice.updateMany({
          where: { id: payment.invoiceId },
          data: {
            status: 'FAILED',
          },
        });
      }

      await this.prisma.subscription.update({
        where: { id: payment.subscriptionId },
        data: {
          status: SubscriptionStatus.PAST_DUE,
        },
      });

      this.logger.error(
        `Payment ${payment.id} failed after ${payment.maxRetries} attempts`,
      );
    }
  }

  /**
   * Handle refund
   */
  private async handleRefund(event: any) {
    this.logger.log(`Processing refund event`);
    // Refund handling implemented in refundPayment method
  }

  /**
   * Handle subscription cancellation events
   */
  private async handleSubscriptionCancelled(event: any) {
    const organizationId =
      event.metadata?.organizationId ||
      event.raw?.data?.object?.metadata?.organizationId ||
      event.raw?.resource?.custom_id;

    if (!organizationId) {
      return;
    }

    await this.prisma.subscription.updateMany({
      where: { organizationId },
      data: {
        status: SubscriptionStatus.CANCELLED,
        cancelledAt: new Date(),
      },
    });
  }

  /**
   * Health check all providers
   */
  async healthCheck() {
    const results: Record<PaymentProvider, boolean> = {} as any;

    for (const [provider, paymentProvider] of this.providers) {
      try {
        results[provider] = await paymentProvider.healthCheck();
      } catch (error) {
        this.logger.error(`Health check failed for ${provider}: ${error.message}`);
        results[provider] = false;
      }
    }

    return results;
  }

  /**
   * Get payment statistics
   */
  async getPaymentStats(organizationId: string) {
    const payments = await this.prisma.payment.findMany({
      where: {
        subscription: {
          organizationId,
        },
      },
    });

    const totalAmount = payments.reduce((sum, p) => sum + p.amount, 0);
    const completedStatus = this.toPrismaPaymentStatus(PaymentStatus.COMPLETED);
    const pendingStatus = this.toPrismaPaymentStatus(PaymentStatus.PENDING);
    const failedStatus = this.toPrismaPaymentStatus(PaymentStatus.FAILED);
    const completedAmount = payments
      .filter((p) => p.status === completedStatus)
      .reduce((sum, p) => sum + p.amount, 0);

    return {
      totalPayments: payments.length,
      totalAmount,
      completedAmount,
      pendingAmount: totalAmount - completedAmount,
      byStatus: {
        completed: payments.filter(
          (p) => p.status === completedStatus,
        ).length,
        pending: payments.filter(
          (p) => p.status === pendingStatus,
        ).length,
        failed: payments.filter((p) => p.status === failedStatus)
          .length,
      },
      byProvider: payments.reduce(
        (acc, p) => {
          acc[p.provider] = (acc[p.provider] || 0) + 1;
          return acc;
        },
        {} as Record<string, number>,
      ),
    };
  }
}

/**
 * Crypto Payment Provider Implementation
 * Coinbase Commerce hosted payments + webhooks
 */

import { Injectable } from '@nestjs/common';
import axios, { AxiosInstance } from 'axios';
import * as crypto from 'crypto';
import { v4 as uuid } from 'uuid';
import { IPaymentProvider } from '../interfaces/payment-provider.interface';
import {
  CreateCustomerRequest,
  CreatePaymentRequest,
  CreateSubscriptionRequest,
  CustomerResponse,
  PaymentMethodRequest,
  PaymentMethodResponse,
  PaymentProvider,
  PaymentResponse,
  PaymentStatus,
  PaymentWebhookEvent,
  RefundRequest,
  RefundResponse,
  RefundStatus,
  SubscriptionResponse,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
} from '../types/payment.types';

type CoinbaseCharge = {
  id: string;
  code: string;
  hosted_url?: string;
  pricing?: {
    local?: {
      amount: string;
      currency: string;
    };
  };
  timeline?: Array<{ status: string; time: string }>;
  metadata?: Record<string, any>;
  payments?: Array<Record<string, any>>;
  web3_data?: {
    contract_addresses?: Record<string, string>;
    payment_addresses?: Record<string, string>;
  };
};

@Injectable()
export class CryptoProvider implements IPaymentProvider {
  private readonly client: AxiosInstance;
  private readonly apiKey: string;
  private readonly webhookSecret: string;

  constructor() {
    this.apiKey = process.env.COINBASE_COMMERCE_API_KEY || '';
    this.webhookSecret = process.env.COINBASE_COMMERCE_WEBHOOK_SECRET || '';
    this.client = axios.create({
      baseURL: 'https://api.commerce.coinbase.com',
      headers: {
        'X-CC-Api-Key': this.apiKey,
        'X-CC-Version': '2018-03-22',
        'Content-Type': 'application/json',
      },
      timeout: 10000,
    });
  }

  getProvider(): PaymentProvider {
    return PaymentProvider.CRYPTO;
  }

  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      const response = await this.client.post('/charges', {
        name: 'BelSuite Billing Charge',
        description: `BelSuite billing for subscription ${request.subscriptionId}`,
        pricing_type: 'fixed_price',
        local_price: {
          amount: request.amount.toFixed(2),
          currency: request.currency,
        },
        metadata: {
          organizationId: request.organizationId,
          subscriptionId: request.subscriptionId,
          invoiceId: request.invoiceId,
          ...request.metadata,
        },
        redirect_url: `${process.env.APP_URL || 'http://localhost:3000'}/billing?payment=success`,
        cancel_url: `${process.env.APP_URL || 'http://localhost:3000'}/billing?payment=cancelled`,
      });

      const charge = response.data.data as CoinbaseCharge;
      return {
        id: charge.id,
        externalPaymentId: charge.code || charge.id,
        status: PaymentStatus.PENDING,
        amount: request.amount,
        currency: request.currency,
        provider: PaymentProvider.CRYPTO,
        redirectUrl: charge.hosted_url,
        metadata: {
          ...request.metadata,
          chargeId: charge.id,
          paymentAddresses: charge.web3_data?.payment_addresses,
          contractAddresses: charge.web3_data?.contract_addresses,
        },
      };
    } catch (error) {
      throw new Error(`Crypto payment creation failed: ${error.message}`);
    }
  }

  async getPayment(externalPaymentId: string): Promise<PaymentResponse> {
    try {
      const response = await this.client.get(`/charges/${externalPaymentId}`);
      const charge = response.data.data as CoinbaseCharge;
      const localPricing = charge.pricing?.local;

      return {
        id: charge.id,
        externalPaymentId: charge.code || charge.id,
        status: this.mapChargeStatus(charge),
        amount: Number(localPricing?.amount || 0),
        currency: localPricing?.currency || 'USD',
        provider: PaymentProvider.CRYPTO,
        redirectUrl: charge.hosted_url,
        metadata: {
          ...(charge.metadata || {}),
          paymentAddresses: charge.web3_data?.payment_addresses,
        },
      };
    } catch (error) {
      throw new Error(`Crypto payment fetch failed: ${error.message}`);
    }
  }

  async refundPayment(_request: RefundRequest): Promise<RefundResponse> {
    throw new Error('Crypto refunds require manual treasury handling');
  }

  async createCustomer(request: CreateCustomerRequest): Promise<CustomerResponse> {
    return {
      externalCustomerId: `crypto_${uuid()}`,
      email: request.email,
      provider: PaymentProvider.CRYPTO,
    };
  }

  async addPaymentMethod(
    customerId: string,
    request: PaymentMethodRequest,
  ): Promise<PaymentMethodResponse> {
    return {
      externalPaymentMethodId: request.metadata?.walletAddress?.toString() || `wallet_${customerId}`,
      provider: PaymentProvider.CRYPTO,
      brand: request.metadata?.network?.toString() || 'CRYPTO',
      last4: request.metadata?.walletAddress?.toString().slice(-4),
    };
  }

  async createSubscription(
    request: CreateSubscriptionRequest,
  ): Promise<SubscriptionResponse> {
    const start = new Date();
    const end = new Date(start);

    if (request.trialDays && request.trialDays > 0) {
      end.setDate(end.getDate() + request.trialDays);
      return {
        externalSubscriptionId: `crypto_sub_${uuid()}`,
        status: 'trialing',
        currentPeriodStart: start,
        currentPeriodEnd: end,
        provider: PaymentProvider.CRYPTO,
        nextPaymentDate: end,
      };
    }

    end.setMonth(end.getMonth() + 1);
    return {
      externalSubscriptionId: `crypto_sub_${uuid()}`,
      status: 'pending_payment',
      currentPeriodStart: start,
      currentPeriodEnd: end,
      provider: PaymentProvider.CRYPTO,
      nextPaymentDate: end,
    };
  }

  async cancelSubscription(_externalSubscriptionId: string): Promise<void> {
    return;
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    const expected = crypto
      .createHmac('sha256', this.webhookSecret)
      .update(request.payload)
      .digest('hex');

    const isValid = Boolean(request.signature) && expected === request.signature;
    return {
      isValid,
      provider: PaymentProvider.CRYPTO,
    };
  }

  async parseWebhookPayload(rawPayload: any): Promise<PaymentWebhookEvent> {
    const event = rawPayload.event ?? rawPayload;
    const charge = event.data as CoinbaseCharge;
    const localPricing = charge.pricing?.local;

    return {
      type: event.type,
      provider: PaymentProvider.CRYPTO,
      externalWebhookId: rawPayload.id,
      externalPaymentId: charge.code || charge.id,
      status: this.mapEventStatus(event.type),
      amount: Number(localPricing?.amount || 0),
      currency: localPricing?.currency || 'USD',
      metadata: charge.metadata || {},
      timestamp: new Date(rawPayload.created_at || Date.now()),
      raw: rawPayload,
    };
  }

  getWebhookSecret(): string {
    return this.webhookSecret;
  }

  async healthCheck(): Promise<boolean> {
    return Boolean(this.apiKey);
  }

  private mapChargeStatus(charge: CoinbaseCharge): PaymentStatus {
    const latest = charge.timeline?.[charge.timeline.length - 1]?.status;
    return this.mapEventStatus(latest || 'NEW');
  }

  private mapEventStatus(eventType: string): PaymentStatus {
    const normalized = eventType.toUpperCase();

    if (normalized.includes('CONFIRMED') || normalized.includes('RESOLVED') || normalized.includes('COMPLETED')) {
      return PaymentStatus.COMPLETED;
    }

    if (normalized.includes('FAILED') || normalized.includes('EXPIRED') || normalized.includes('CANCELLED')) {
      return PaymentStatus.FAILED;
    }

    if (normalized.includes('PENDING') || normalized.includes('NEW') || normalized.includes('CREATED')) {
      return PaymentStatus.PENDING;
    }

    return PaymentStatus.PROCESSING;
  }
}

/**
 * Flutterwave Payment Provider Implementation
 * https://docs.flutterwave.com
 */

import { Injectable } from '@nestjs/common';
import axios, { AxiosInstance } from 'axios';
import { IPaymentProvider } from '../interfaces/payment-provider.interface';
import {
  PaymentProvider,
  PaymentStatus,
  RefundStatus,
  CreatePaymentRequest,
  PaymentResponse,
  RefundResponse,
  RefundRequest,
  PaymentWebhookEvent,
  CreateCustomerRequest,
  CustomerResponse,
  PaymentMethodRequest,
  PaymentMethodResponse,
  CreateSubscriptionRequest,
  SubscriptionResponse,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
} from '../types/payment.types';
import * as crypto from 'crypto';
import { v4 as uuid } from 'uuid';

@Injectable()
export class FlutterwaveProvider implements IPaymentProvider {
  private client: AxiosInstance;
  private baseUrl = 'https://api.flutterwave.com/v3';
  private secretKey: string;
  private webhookSecret: string;

  constructor() {
    this.secretKey = process.env.FLUTTERWAVE_SECRET_KEY || '';
    this.webhookSecret = process.env.FLUTTERWAVE_WEBHOOK_SECRET || '';
    this.client = axios.create({
      baseURL: this.baseUrl,
      headers: {
        Authorization: `Bearer ${this.secretKey}`,
        'Content-Type': 'application/json',
      },
      timeout: 10000,
    });
  }

  getProvider(): PaymentProvider {
    return PaymentProvider.FLUTTERWAVE;
  }

  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      const txRef = `belsuite_${uuid()}`;

      const response = await this.client.post('/payments', {
        tx_ref: txRef,
        amount: request.amount,
        currency: request.currency,
        description: `Belsuite subscription - ${request.subscriptionId}`,
        customer: {
          email: request.metadata?.email || 'customer@example.com',
          name: request.metadata?.name || 'Customer',
        },
        customizations: {
          title: 'Belsuite',
          logo: 'https://belsuite.com/logo.png',
        },
        meta: {
          organizationId: request.organizationId,
          subscriptionId: request.subscriptionId,
          ...request.metadata,
        },
        redirect_url: `${process.env.APP_URL}/payments/flutterwave/callback`,
      });

      const data = response.data.data;

      return {
        id: `flutterwave_${data.id}`,
        externalPaymentId: data.id.toString(),
        status: PaymentStatus.PENDING,
        amount: request.amount,
        currency: request.currency,
        provider: PaymentProvider.FLUTTERWAVE,
        redirectUrl: data.link,
        metadata: request.metadata,
      };
    } catch (error) {
      throw new Error(
        `Flutterwave payment creation failed: ${error.message}`,
      );
    }
  }

  async getPayment(externalPaymentId: string): Promise<PaymentResponse> {
    try {
      const response = await this.client.get(
        `/transactions/${externalPaymentId}/verify`,
      );

      const data = response.data.data;
      const status = this.mapFlutterwaveStatus(data.status);

      return {
        id: `flutterwave_${data.id}`,
        externalPaymentId: data.id.toString(),
        status: status,
        amount: data.amount,
        currency: data.currency,
        provider: PaymentProvider.FLUTTERWAVE,
        metadata: data.meta,
      };
    } catch (error) {
      throw new Error(`Flutterwave payment fetch failed: ${error.message}`);
    }
  }

  async refundPayment(request: RefundRequest): Promise<RefundResponse> {
    try {
      const response = await this.client.post(
        `/transactions/${request.paymentId}/refund`,
        {
          amount: request.amount,
        },
      );

      const data = response.data.data;

      return {
        id: `flutterwave_refund_${data.id}`,
        externalRefundId: data.id.toString(),
        status: RefundStatus.PROCESSING,
        amount: request.amount || data.amount,
        currency: data.currency || 'NGN',
        provider: PaymentProvider.FLUTTERWAVE,
      };
    } catch (error) {
      throw new Error(`Flutterwave refund failed: ${error.message}`);
    }
  }

  async createCustomer(
    request: CreateCustomerRequest,
  ): Promise<CustomerResponse> {
    // Flutterwave doesn't have a customer creation endpoint
    // Customers are implicitly created during transactions
    // Return a mock customer response
    return {
      externalCustomerId: `flutterwave_${uuid()}`,
      email: request.email,
      provider: PaymentProvider.FLUTTERWAVE,
    };
  }

  async addPaymentMethod(
    customerId: string,
    request: PaymentMethodRequest,
  ): Promise<PaymentMethodResponse> {
    // Payment methods in Flutterwave are created during transaction
    return {
      externalPaymentMethodId: `flutterwave_pm_${customerId}`,
      provider: PaymentProvider.FLUTTERWAVE,
    };
  }

  async createSubscription(
    request: CreateSubscriptionRequest,
  ): Promise<SubscriptionResponse> {
    try {
      const txRef = `belsuite_sub_${uuid()}`;

      const response = await this.client.post('/subscription/create', {
        tx_ref: txRef,
        amount: request.planId, // In Flutterwave, amount comes from plan
        plan_token: request.paymentMethodId,
        customer: {
          email: request.customerId,
        },
        meta: {
          organizationId: request.customerId,
        },
      });

      const data = response.data.data;

      return {
        externalSubscriptionId: data.id.toString(),
        status: 'active',
        currentPeriodStart: new Date(),
        currentPeriodEnd: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // 30 days
        provider: PaymentProvider.FLUTTERWAVE,
      };
    } catch (error) {
      throw new Error(
        `Flutterwave subscription creation failed: ${error.message}`,
      );
    }
  }

  async cancelSubscription(externalSubscriptionId: string): Promise<void> {
    try {
      await this.client.put(`/subscriptions/${externalSubscriptionId}/cancel`);
    } catch (error) {
      throw new Error(
        `Flutterwave subscription cancellation failed: ${error.message}`,
      );
    }
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    const hash = crypto
      .createHmac('sha256', this.webhookSecret)
      .update(request.payload)
      .digest('hex');

    const isValid = hash === request.signature;

    return {
      isValid,
      provider: PaymentProvider.FLUTTERWAVE,
    };
  }

  async parseWebhookPayload(rawPayload: any): Promise<PaymentWebhookEvent> {
    const { event, data } = rawPayload;

    let status = PaymentStatus.PENDING;
    if (event === 'charge.completed') {
      status = PaymentStatus.COMPLETED;
    } else if (event === 'charge.failed') {
      status = PaymentStatus.FAILED;
    }

    return {
      type: event,
      provider: PaymentProvider.FLUTTERWAVE,
      externalPaymentId: data.id?.toString(),
      status: status,
      amount: data.amount,
      currency: data.currency,
      metadata: data.meta,
      timestamp: new Date(data.created_at),
      raw: rawPayload,
    };
  }

  getWebhookSecret(): string {
    return this.webhookSecret;
  }

  private mapFlutterwaveStatus(status: string): PaymentStatus {
    const statusMap: Record<string, PaymentStatus> = {
      successful: PaymentStatus.COMPLETED,
      pending: PaymentStatus.PENDING,
      failed: PaymentStatus.FAILED,
      cancelled: PaymentStatus.CANCELLED,
    };
    return statusMap[status] || PaymentStatus.PENDING;
  }

  async healthCheck(): Promise<boolean> {
    try {
      const response = await this.client.get('/banks/UG');
      return response.status === 200;
    } catch (error) {
      return false;
    }
  }
}

/**
 * PayPal Payment Provider Implementation
 * https://developer.paypal.com/
 */

import { Injectable } from '@nestjs/common';
import axios, { AxiosInstance } from 'axios';
import { IPaymentProvider } from '../interfaces/payment-provider.interface';
import {
  PaymentProvider,
  PaymentStatus,
  RefundStatus,
  CreatePaymentRequest,
  PaymentResponse,
  RefundResponse,
  RefundRequest,
  PaymentWebhookEvent,
  CreateCustomerRequest,
  CustomerResponse,
  PaymentMethodRequest,
  PaymentMethodResponse,
  CreateSubscriptionRequest,
  SubscriptionResponse,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
} from '../types/payment.types';
import { v4 as uuid } from 'uuid';

@Injectable()
export class PayPalProvider implements IPaymentProvider {
  private client: AxiosInstance;
  private baseUrl: string;
  private clientId: string;
  private clientSecret: string;
  private mode: 'sandbox' | 'live';
  private accessToken: string;

  constructor() {
    this.clientId = process.env.PAYPAL_CLIENT_ID || '';
    this.clientSecret = process.env.PAYPAL_CLIENT_SECRET || '';
    this.mode = (process.env.PAYPAL_MODE as 'sandbox' | 'live') || 'sandbox';
    this.baseUrl =
      this.mode === 'sandbox'
        ? 'https://api-m.sandbox.paypal.com'
        : 'https://api-m.paypal.com';

    this.client = axios.create({
      baseURL: this.baseUrl,
      auth: {
        username: this.clientId,
        password: this.clientSecret,
      },
      timeout: 10000,
    });

    this.accessToken = '';
  }

  getProvider(): PaymentProvider {
    return PaymentProvider.PAYPAL;
  }

  private async getAccessToken(): Promise<string> {
    if (this.accessToken) {
      return this.accessToken;
    }

    try {
      const response = await this.client.post('/v1/oauth2/token', 'grant_type=client_credentials', {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
      });

      this.accessToken = response.data.access_token;
      return this.accessToken;
    } catch (error) {
      throw new Error(`PayPal authentication failed: ${error.message}`);
    }
  }

  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      const token = await this.getAccessToken();

      const response = await axios.post(
        `${this.baseUrl}/v2/checkout/orders`,
        {
          intent: 'CAPTURE',
          payer: {
            email_address: request.metadata?.email,
            name: {
              given_name: request.metadata?.firstName || 'Customer',
              surname: request.metadata?.lastName || 'User',
            },
          },
          purchase_units: [
            {
              reference_id: request.subscriptionId,
              description: `Belsuite subscription - ${request.subscriptionId}`,
              amount: {
                currency_code: request.currency,
                value: request.amount.toString(),
              },
              custom_id: request.organizationId,
            },
          ],
          application_context: {
            return_url: `${process.env.APP_URL}/payments/paypal/success`,
            cancel_url: `${process.env.APP_URL}/payments/paypal/cancel`,
            brand_name: 'Belsuite',
            locale: 'en-US',
            landing_page: 'BILLING',
          },
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        },
      );

      const data = response.data;
      const approveLink = (data.links as Array<{ rel: string; href: string }> | undefined)
        ?.find((link) => link.rel === 'approve');

      return {
        id: `paypal_${data.id}`,
        externalPaymentId: data.id,
        status: PaymentStatus.PENDING,
        amount: request.amount,
        currency: request.currency,
        provider: PaymentProvider.PAYPAL,
        redirectUrl: approveLink?.href,
        clientSecret: data.id,
        metadata: request.metadata,
      };
    } catch (error) {
      throw new Error(`PayPal payment creation failed: ${error.message}`);
    }
  }

  async getPayment(externalPaymentId: string): Promise<PaymentResponse> {
    try {
      const token = await this.getAccessToken();

      const response = await axios.get(
        `${this.baseUrl}/v2/checkout/orders/${externalPaymentId}`,
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        },
      );

      const data = response.data;
      const status = this.mapPayPalStatus(data.status);
      const purchaseUnit = data.purchase_units?.[0];
      const amount = parseFloat(purchaseUnit?.amount?.value || '0');

      return {
        id: `paypal_${data.id}`,
        externalPaymentId: data.id,
        status: status,
        amount: amount,
        currency: purchaseUnit?.amount?.currency_code || 'USD',
        provider: PaymentProvider.PAYPAL,
        metadata: {
          payerEmail: data.payer?.email_address,
        },
      };
    } catch (error) {
      throw new Error(`PayPal payment fetch failed: ${error.message}`);
    }
  }

  async refundPayment(request: RefundRequest): Promise<RefundResponse> {
    try {
      const token = await this.getAccessToken();

      // Get the capture ID first
      const orderResponse = await axios.get(
        `${this.baseUrl}/v2/checkout/orders/${request.paymentId}`,
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        },
      );

      const captureId =
        orderResponse.data.purchase_units?.[0]?.payments?.captures?.[0]?.id;

      if (!captureId) {
        throw new Error('Capture ID not found');
      }

      const response = await axios.post(
        `${this.baseUrl}/v2/payments/captures/${captureId}/refund`,
        {
          amount: {
            currency_code:
              orderResponse.data.purchase_units[0].amount.currency_code,
            value: (request.amount || 0).toString(),
          },
          note_to_payer: request.reason,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        },
      );

      const data = response.data;

      return {
        id: `paypal_refund_${data.id}`,
        externalRefundId: data.id,
        status: RefundStatus.COMPLETED,
        amount: parseFloat(data.amount?.value || '0'),
        currency: data.amount?.currency_code || 'USD',
        provider: PaymentProvider.PAYPAL,
      };
    } catch (error) {
      throw new Error(`PayPal refund failed: ${error.message}`);
    }
  }

  async createCustomer(
    request: CreateCustomerRequest,
  ): Promise<CustomerResponse> {
    // PayPal doesn't have explicit customer creation
    // Customers are created implicitly during transactions
    return {
      externalCustomerId: `paypal_${uuid()}`,
      email: request.email,
      provider: PaymentProvider.PAYPAL,
    };
  }

  async addPaymentMethod(
    customerId: string,
    request: PaymentMethodRequest,
  ): Promise<PaymentMethodResponse> {
    // PayPal uses their vault system through subscription or other means
    return {
      externalPaymentMethodId: `paypal_pm_${customerId}`,
      provider: PaymentProvider.PAYPAL,
    };
  }

  async createSubscription(
    request: CreateSubscriptionRequest,
  ): Promise<SubscriptionResponse> {
    try {
      const token = await this.getAccessToken();

      // First create a billing plan
      const planResponse = await axios.post(
        `${this.baseUrl}/v1/billing/plans`,
        {
          product_id: process.env.PAYPAL_PRODUCT_ID || 'PROD-BELSUITE',
          name: `Belsuite Plan ${request.planId}`,
          description: `Belsuite billing plan`,
          status: 'ACTIVE',
          billing_cycles: [
            {
              frequency: {
                interval_unit: 'MONTH',
                interval_count: 1,
              },
              tenure_type: 'REGULAR',
              sequence: 1,
              total_cycles: 0, // Infinite
              pricing_scheme: {
                fixed_price: {
                  value: '100.00', // Will be overridden by subscription amount
                  currency_code: 'USD',
                },
              },
            },
          ],
          payment_preferences: {
            auto_bill_amount: 'YES',
            payment_failure_threshold: 2,
          },
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        },
      );

      const planId = planResponse.data.id;

      // Then create subscription
      const subscriptionResponse = await axios.post(
        `${this.baseUrl}/v1/billing/subscriptions`,
        {
          plan_id: planId,
          subscriber: {
            email_address: request.customerId,
          },
          custom_id: request.customerId,
          auto_renewal: true,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        },
      );

      const data = subscriptionResponse.data;

      return {
        externalSubscriptionId: data.id,
        status: data.status,
        currentPeriodStart: new Date(data.start_time),
        currentPeriodEnd: new Date(data.next_billing_time),
        provider: PaymentProvider.PAYPAL,
        nextPaymentDate: new Date(data.next_billing_time),
      };
    } catch (error) {
      throw new Error(
        `PayPal subscription creation failed: ${error.message}`,
      );
    }
  }

  async cancelSubscription(externalSubscriptionId: string): Promise<void> {
    try {
      const token = await this.getAccessToken();

      await axios.post(
        `${this.baseUrl}/v1/billing/subscriptions/${externalSubscriptionId}/cancel`,
        {
          reason: 'User requested cancellation',
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        },
      );
    } catch (error) {
      throw new Error(
        `PayPal subscription cancellation failed: ${error.message}`,
      );
    }
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    try {
      const token = await this.getAccessToken();

      const response = await axios.post(
        `${this.baseUrl}/v1/notifications/verify-webhook-signature`,
        {
          transmission_id: request.signature,
          transmission_time: new Date().toISOString(),
          cert_url: '',
          auth_algo: 'SHA256withRSA',
          transmission_sig: request.signature,
          webhook_id: process.env.PAYPAL_WEBHOOK_ID,
          webhook_event: JSON.parse(request.payload),
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        },
      );

      return {
        isValid: response.data.verification_status === 'SUCCESS',
        provider: PaymentProvider.PAYPAL,
      };
    } catch (error) {
      return {
        isValid: false,
        provider: PaymentProvider.PAYPAL,
      };
    }
  }

  async parseWebhookPayload(rawPayload: any): Promise<PaymentWebhookEvent> {
    const eventType = rawPayload.event_type;

    let status = PaymentStatus.PENDING;
    if (eventType === 'CHECKOUT.ORDER.COMPLETED') {
      status = PaymentStatus.COMPLETED;
    } else if (eventType === 'CHECKOUT.ORDER.APPROVED') {
      status = PaymentStatus.PROCESSING;
    }

    return {
      type: eventType,
      provider: PaymentProvider.PAYPAL,
      externalWebhookId: rawPayload.id,
      status: status,
      amount: rawPayload.resource?.purchase_units?.[0]?.amount?.value,
      currency: rawPayload.resource?.purchase_units?.[0]?.amount?.currency_code,
      metadata: {
        orderId: rawPayload.resource?.id,
      },
      timestamp: new Date(rawPayload.create_time),
      raw: rawPayload,
    };
  }

  getWebhookSecret(): string {
    return process.env.PAYPAL_WEBHOOK_ID || '';
  }

  private mapPayPalStatus(status: string): PaymentStatus {
    const statusMap: Record<string, PaymentStatus> = {
      CREATED: PaymentStatus.PENDING,
      SAVED: PaymentStatus.PENDING,
      APPROVED: PaymentStatus.PROCESSING,
      VOIDED: PaymentStatus.CANCELLED,
      COMPLETED: PaymentStatus.COMPLETED,
      PAYER_ACTION_REQUIRED: PaymentStatus.PENDING,
    };
    return statusMap[status] || PaymentStatus.PENDING;
  }

  async healthCheck(): Promise<boolean> {
    try {
      const token = await this.getAccessToken();
      return !!token;
    } catch (error) {
      return false;
    }
  }
}

/**
 * Paystack Payment Provider Implementation
 * https://paystack.com/docs/api
 */

import { Injectable } from '@nestjs/common';
import axios, { AxiosInstance } from 'axios';
import { IPaymentProvider } from '../interfaces/payment-provider.interface';
import {
  PaymentProvider,
  PaymentStatus,
  RefundStatus,
  CreatePaymentRequest,
  PaymentResponse,
  RefundResponse,
  RefundRequest,
  PaymentWebhookEvent,
  CreateCustomerRequest,
  CustomerResponse,
  PaymentMethodRequest,
  PaymentMethodResponse,
  CreateSubscriptionRequest,
  SubscriptionResponse,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
} from '../types/payment.types';
import * as crypto from 'crypto';

@Injectable()
export class PaystackProvider implements IPaymentProvider {
  private client: AxiosInstance;
  private baseUrl = 'https://api.paystack.co';
  private secretKey: string;

  constructor() {
    this.secretKey = process.env.PAYSTACK_SECRET_KEY || '';
    this.client = axios.create({
      baseURL: this.baseUrl,
      headers: {
        Authorization: `Bearer ${this.secretKey}`,
        'Content-Type': 'application/json',
      },
      timeout: 10000,
    });
  }

  getProvider(): PaymentProvider {
    return PaymentProvider.PAYSTACK;
  }

  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      const response = await this.client.post('/transaction/initialize', {
        amount: Math.round(request.amount * 100), // Paystack uses cents
        email: request.metadata?.email || 'customer@example.com',
        currency: request.currency,
        metadata: {
          organizationId: request.organizationId,
          subscriptionId: request.subscriptionId,
          ...request.metadata,
        },
      });

      const data = response.data.data;

      return {
        id: `paystack_${data.reference}`,
        externalPaymentId: data.reference,
        status: PaymentStatus.PENDING,
        amount: request.amount,
        currency: request.currency,
        provider: PaymentProvider.PAYSTACK,
        redirectUrl: data.authorization_url,
        metadata: request.metadata,
      };
    } catch (error) {
      throw new Error(`Paystack payment creation failed: ${error.message}`);
    }
  }

  async getPayment(externalPaymentId: string): Promise<PaymentResponse> {
    try {
      const response = await this.client.get(
        `/transaction/verify/${externalPaymentId}`,
      );

      const data = response.data.data;
      const status = this.mapPaystackStatus(data.status);

      return {
        id: `paystack_${data.reference}`,
        externalPaymentId: data.reference,
        status: status,
        amount: data.amount / 100, // Convert from cents
        currency: data.currency,
        provider: PaymentProvider.PAYSTACK,
        metadata: data.metadata,
      };
    } catch (error) {
      throw new Error(`Paystack payment fetch failed: ${error.message}`);
    }
  }

  async refundPayment(request: RefundRequest): Promise<RefundResponse> {
    try {
      // For Paystack, refunds are initiated via the API
      const response = await this.client.post('/refund', {
        transaction: request.paymentId,
        amount: request.amount ? Math.round(request.amount * 100) : undefined,
      });

      const data = response.data.data;

      return {
        id: `paystack_refund_${data.refund_key}`,
        externalRefundId: data.refund_key,
        status: RefundStatus.PROCESSING,
        amount: (data.amount || 0) / 100,
        currency: 'NGN', // Default to Nigerian Naira
        provider: PaymentProvider.PAYSTACK,
      };
    } catch (error) {
      throw new Error(`Paystack refund failed: ${error.message}`);
    }
  }

  async createCustomer(
    request: CreateCustomerRequest,
  ): Promise<CustomerResponse> {
    try {
      const response = await this.client.post('/customer', {
        email: request.email,
        first_name: request.name.split(' ')[0],
        last_name: request.name.split(' ')[1] || '',
        description: request.description,
      });

      const data = response.data.data;

      return {
        externalCustomerId: data.customer_code,
        email: data.email,
        provider: PaymentProvider.PAYSTACK,
      };
    } catch (error) {
      throw new Error(`Paystack customer creation failed: ${error.message}`);
    }
  }

  async addPaymentMethod(
    customerId: string,
    request: PaymentMethodRequest,
  ): Promise<PaymentMethodResponse> {
    // Paystack doesn't have direct payment method storage like other providers
    // Payment methods are created during transaction initialization
    // Return a placeholder response
    return {
      externalPaymentMethodId: `paystack_pm_${customerId}`,
      provider: PaymentProvider.PAYSTACK,
    };
  }

  async createSubscription(
    request: CreateSubscriptionRequest,
  ): Promise<SubscriptionResponse> {
    try {
      const response = await this.client.post('/subscription/create', {
        customer: request.customerId,
        plan: request.planId,
        authorization: request.paymentMethodId,
      });

      const data = response.data.data;

      return {
        externalSubscriptionId: data.subscription_code,
        status: data.status,
        currentPeriodStart: new Date(data.createdAt),
        currentPeriodEnd: new Date(data.next_payment_date),
        provider: PaymentProvider.PAYSTACK,
        nextPaymentDate: new Date(data.next_payment_date),
      };
    } catch (error) {
      throw new Error(
        `Paystack subscription creation failed: ${error.message}`,
      );
    }
  }

  async cancelSubscription(externalSubscriptionId: string): Promise<void> {
    try {
      await this.client.post(
        `/subscription/${externalSubscriptionId}/disable`,
        { token: externalSubscriptionId },
      );
    } catch (error) {
      throw new Error(`Paystack subscription cancellation failed: ${error.message}`);
    }
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    const hash = crypto
      .createHmac('sha512', this.secretKey)
      .update(request.payload)
      .digest('hex');

    const isValid = hash === request.signature;

    return {
      isValid,
      provider: PaymentProvider.PAYSTACK,
    };
  }

  async parseWebhookPayload(rawPayload: any): Promise<PaymentWebhookEvent> {
    const { event, data } = rawPayload;

    let status = PaymentStatus.PENDING;
    if (event === 'charge.success') {
      status = PaymentStatus.COMPLETED;
    } else if (event === 'charge.failed') {
      status = PaymentStatus.FAILED;
    }

    return {
      type: event,
      provider: PaymentProvider.PAYSTACK,
      externalPaymentId: data.reference,
      status: status,
      amount: data.amount / 100,
      currency: data.currency,
      metadata: data.metadata,
      timestamp: new Date(data.paid_at),
      raw: rawPayload,
    };
  }

  getWebhookSecret(): string {
    return this.secretKey;
  }

  private mapPaystackStatus(status: string): PaymentStatus {
    const statusMap: Record<string, PaymentStatus> = {
      success: PaymentStatus.COMPLETED,
      pending: PaymentStatus.PENDING,
      failed: PaymentStatus.FAILED,
      cancelled: PaymentStatus.CANCELLED,
    };
    return statusMap[status] || PaymentStatus.PENDING;
  }

  async healthCheck(): Promise<boolean> {
    try {
      const response = await this.client.get('/bank');
      return response.status === 200;
    } catch (error) {
      return false;
    }
  }
}

/**
 * Sofort Payment Provider Implementation
 * https://www.klarna.com/sofort/
 */

import { Injectable } from '@nestjs/common';
import axios, { AxiosInstance } from 'axios';
import { IPaymentProvider } from '../interfaces/payment-provider.interface';
import {
  PaymentProvider,
  PaymentStatus,
  RefundStatus,
  CreatePaymentRequest,
  PaymentResponse,
  RefundResponse,
  RefundRequest,
  PaymentWebhookEvent,
  CreateCustomerRequest,
  CustomerResponse,
  PaymentMethodRequest,
  PaymentMethodResponse,
  CreateSubscriptionRequest,
  SubscriptionResponse,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
} from '../types/payment.types';
import * as crypto from 'crypto';
import { v4 as uuid } from 'uuid';

@Injectable()
export class SofortProvider implements IPaymentProvider {
  private client: AxiosInstance;
  private baseUrl = 'https://api.sofort.com';
  private merchantId: string;
  private apiKey: string;

  constructor() {
    this.merchantId = process.env.SOFORT_MERCHANT_ID || '';
    this.apiKey = process.env.SOFORT_API_KEY || '';

    const authString = Buffer.from(`${this.merchantId}:${this.apiKey}`).toString(
      'base64',
    );

    this.client = axios.create({
      baseURL: this.baseUrl,
      headers: {
        Authorization: `Basic ${authString}`,
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
      timeout: 10000,
    });
  }

  getProvider(): PaymentProvider {
    return PaymentProvider.SOFORT;
  }

  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      const transactionId = uuid();

      const response = await this.client.post('/rest/transactions', {
        transaction: {
          amount: Math.round(request.amount * 100), // Sofort uses cents
          currency: request.currency,
          reason1: `Belsuite - ${request.subscriptionId}`,
          reason2: request.organizationId,
          user_id: request.metadata?.userId,
          email: request.metadata?.email,
          phone: request.metadata?.phone,
          country_code: request.metadata?.countryCode || 'DE',
          success_url: `${process.env.APP_URL}/payments/sofort/success?transactionId=${transactionId}`,
          abort_url: `${process.env.APP_URL}/payments/sofort/abort`,
          notification_urls: [
            `${process.env.API_URL}/webhooks/sofort`,
          ],
          interface: 'json',
          version: '220',
        },
      });

      const data = response.data.new_transaction;

      return {
        id: `sofort_${data.transaction_id}`,
        externalPaymentId: data.transaction_id,
        status: PaymentStatus.PENDING,
        amount: request.amount,
        currency: request.currency,
        provider: PaymentProvider.SOFORT,
        redirectUrl: data.payment_url,
        metadata: request.metadata,
      };
    } catch (error) {
      throw new Error(`Sofort payment creation failed: ${error.message}`);
    }
  }

  async getPayment(externalPaymentId: string): Promise<PaymentResponse> {
    try {
      const response = await this.client.get(
        `/rest/transactions/${externalPaymentId}`,
      );

      const data = response.data.transactions[0];
      const status = this.mapSofortStatus(data.status);

      return {
        id: `sofort_${data.transaction_id}`,
        externalPaymentId: data.transaction_id,
        status: status,
        amount: data.amount / 100, // Convert from cents
        currency: data.currency_code,
        provider: PaymentProvider.SOFORT,
      };
    } catch (error) {
      throw new Error(`Sofort payment fetch failed: ${error.message}`);
    }
  }

  async refundPayment(request: RefundRequest): Promise<RefundResponse> {
    try {
      const response = await this.client.post(
        `/rest/transactions/${request.paymentId}/refund`,
        {
          refund: {
            amount: Math.round((request.amount || 0) * 100),
            reason: request.reason || 'Customer requested refund',
          },
        },
      );

      const data = response.data.new_refund;

      return {
        id: `sofort_refund_${data.refund_id}`,
        externalRefundId: data.refund_id,
        status: RefundStatus.PROCESSING,
        amount: (data.amount || 0) / 100,
        currency: 'EUR',
        provider: PaymentProvider.SOFORT,
      };
    } catch (error) {
      throw new Error(`Sofort refund failed: ${error.message}`);
    }
  }

  async createCustomer(
    request: CreateCustomerRequest,
  ): Promise<CustomerResponse> {
    // Sofort doesn't have explicit customer creation
    // Customers are created implicitly during transactions
    return {
      externalCustomerId: `sofort_${uuid()}`,
      email: request.email,
      provider: PaymentProvider.SOFORT,
    };
  }

  async addPaymentMethod(
    customerId: string,
    request: PaymentMethodRequest,
  ): Promise<PaymentMethodResponse> {
    // Sofort bank transfers don't require pre-stored payment methods
    return {
      externalPaymentMethodId: `sofort_pm_${customerId}`,
      provider: PaymentProvider.SOFORT,
    };
  }

  async createSubscription(
    request: CreateSubscriptionRequest,
  ): Promise<SubscriptionResponse> {
    // Sofort doesn't have native subscription support
    // Subscriptions would be managed manually or through a separate system
    throw new Error('Subscriptions not supported by Sofort provider');
  }

  async cancelSubscription(externalSubscriptionId: string): Promise<void> {
    throw new Error('Subscriptions not supported by Sofort provider');
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    // Sofort uses SHA256 HMAC with API key
    const hash = crypto
      .createHmac('sha256', this.apiKey)
      .update(request.payload)
      .digest('hex');

    const isValid = hash === request.signature;

    return {
      isValid,
      provider: PaymentProvider.SOFORT,
    };
  }

  async parseWebhookPayload(rawPayload: any): Promise<PaymentWebhookEvent> {
    let status = PaymentStatus.PENDING;

    if (
      rawPayload.transaction &&
      rawPayload.transaction.status === 'received'
    ) {
      status = PaymentStatus.COMPLETED;
    } else if (
      rawPayload.transaction &&
      rawPayload.transaction.status === 'abort'
    ) {
      status = PaymentStatus.CANCELLED;
    }

    return {
      type: 'transaction.status',
      provider: PaymentProvider.SOFORT,
      externalPaymentId: rawPayload.transaction_id,
      status: status,
      amount: (rawPayload.amount || 0) / 100,
      currency: rawPayload.currency_code,
      timestamp: new Date(),
      raw: rawPayload,
    };
  }

  getWebhookSecret(): string {
    return this.apiKey;
  }

  private mapSofortStatus(status: string): PaymentStatus {
    const statusMap: Record<string, PaymentStatus> = {
      received: PaymentStatus.COMPLETED,
      pending: PaymentStatus.PENDING,
      loss: PaymentStatus.FAILED,
      refunded: PaymentStatus.REFUNDED,
      abort: PaymentStatus.CANCELLED,
    };
    return statusMap[status] || PaymentStatus.PENDING;
  }

  async healthCheck(): Promise<boolean> {
    try {
      // Simple health check by verifying credentials
      const response = await this.client.get('/rest/about');
      return response.status === 200;
    } catch (error) {
      return false;
    }
  }
}

/**
 * Stripe Payment Provider Implementation
 * https://stripe.com/docs/api
 */

import { Injectable } from '@nestjs/common';
import Stripe from 'stripe';
import { IPaymentProvider } from '../interfaces/payment-provider.interface';
import {
  PaymentProvider,
  PaymentStatus,
  RefundStatus,
  CreatePaymentRequest,
  PaymentResponse,
  RefundResponse,
  RefundRequest,
  PaymentWebhookEvent,
  CreateCustomerRequest,
  CustomerResponse,
  PaymentMethodRequest,
  PaymentMethodResponse,
  CreateSubscriptionRequest,
  SubscriptionResponse,
  WebhookVerificationRequest,
  WebhookVerificationResponse,
} from '../types/payment.types';

@Injectable()
export class StripeProvider implements IPaymentProvider {
  private stripe: Stripe;
  private webhookSecret: string;

  constructor() {
    this.stripe = new Stripe(process.env.STRIPE_SECRET_KEY || '', {
      apiVersion: '2023-10-16' as Stripe.LatestApiVersion,
    });
    this.webhookSecret = process.env.STRIPE_WEBHOOK_SECRET || '';
  }

  getProvider(): PaymentProvider {
    return PaymentProvider.STRIPE;
  }

  private getErrorMessage(error: unknown, fallback: string) {
    return error instanceof Error ? error.message : fallback;
  }

  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      const payment = await this.stripe.paymentIntents.create({
        amount: Math.round(request.amount * 100), // Stripe uses cents
        currency: request.currency.toLowerCase(),
        description: `Belsuite subscription - ${request.subscriptionId}`,
        metadata: {
          organizationId: request.organizationId,
          subscriptionId: request.subscriptionId,
          ...request.metadata,
        },
        receipt_email: request.metadata?.email,
      });

      return {
        id: payment.id,
        externalPaymentId: payment.id,
        status: this.mapStripeStatus(payment.status),
        amount: request.amount,
        currency: request.currency,
        provider: PaymentProvider.STRIPE,
        clientSecret: payment.client_secret ?? undefined,
        metadata: request.metadata,
      };
    } catch (error) {
      throw new Error(
        `Stripe payment creation failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async getPayment(externalPaymentId: string): Promise<PaymentResponse> {
    try {
      const payment = await this.stripe.paymentIntents.retrieve(
        externalPaymentId,
      );

      return {
        id: payment.id,
        externalPaymentId: payment.id,
        status: this.mapStripeStatus(payment.status),
        amount: payment.amount / 100,
        currency: payment.currency.toUpperCase(),
        provider: PaymentProvider.STRIPE,
        metadata: payment.metadata,
      };
    } catch (error) {
      throw new Error(
        `Stripe payment fetch failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async refundPayment(request: RefundRequest): Promise<RefundResponse> {
    try {
      const refund = await this.stripe.refunds.create({
        payment_intent: request.paymentId,
        ...(request.amount
          ? { amount: Math.round(request.amount * 100) }
          : {}),
        reason: 'requested_by_customer',
        metadata: {
          reason: request.reason ?? 'Customer requested refund',
        },
      });

      return {
        id: refund.id,
        externalRefundId: refund.id,
        status: this.mapStripeRefundStatus(refund.status ?? 'pending'),
        amount: refund.amount / 100,
        currency: refund.currency.toUpperCase(),
        provider: PaymentProvider.STRIPE,
      };
    } catch (error) {
      throw new Error(
        `Stripe refund failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async createCustomer(
    request: CreateCustomerRequest,
  ): Promise<CustomerResponse> {
    try {
      const customer = await this.stripe.customers.create({
        email: request.email,
        name: request.name,
        description: request.description,
      });

      return {
        externalCustomerId: customer.id,
        email: customer.email ?? request.email,
        provider: PaymentProvider.STRIPE,
      };
    } catch (error) {
      throw new Error(
        `Stripe customer creation failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async addPaymentMethod(
    customerId: string,
    request: PaymentMethodRequest,
  ): Promise<PaymentMethodResponse> {
    try {
      const paymentMethod = await this.stripe.paymentMethods.create({
        type: request.type === 'card' ? 'card' : 'sepa_debit',
        billing_details: {
          email: request.billingDetails.billingEmail,
          name: request.billingDetails.billingName,
          address: {
            line1: request.billingDetails.billingAddress,
            city: request.billingDetails.billingCity,
            state: request.billingDetails.billingState,
            postal_code: request.billingDetails.billingZip,
            country: request.billingDetails.billingCountry,
          },
        },
      });

      // Attach payment method to customer
      await this.stripe.paymentMethods.attach(paymentMethod.id, {
        customer: customerId,
      });

      const cardData = paymentMethod.card;

      return {
        externalPaymentMethodId: paymentMethod.id,
        provider: PaymentProvider.STRIPE,
        last4: cardData?.last4,
        brand: cardData?.brand,
        expiryMonth: cardData?.exp_month,
        expiryYear: cardData?.exp_year,
      };
    } catch (error) {
      throw new Error(
        `Stripe payment method creation failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async createSubscription(
    request: CreateSubscriptionRequest,
  ): Promise<SubscriptionResponse> {
    try {
      const subscription = await this.stripe.subscriptions.create(
        {
          customer: request.customerId,
          items: [
            {
              price: request.planId, // This should be a Stripe price ID
            },
          ],
          default_payment_method: request.paymentMethodId,
          trial_period_days: request.trialDays,
        },
        {
          idempotencyKey: `${request.organizationId}_${request.planId}_${Date.now()}`,
        },
      );

      return {
        externalSubscriptionId: subscription.id,
        status: subscription.status,
        currentPeriodStart: new Date(subscription.current_period_start * 1000),
        currentPeriodEnd: new Date(subscription.current_period_end * 1000),
        provider: PaymentProvider.STRIPE,
        nextPaymentDate:
          subscription.next_pending_invoice_item_invoice != null
            ? new Date(subscription.next_pending_invoice_item_invoice * 1000)
            : new Date(subscription.current_period_end * 1000),
      };
    } catch (error) {
      throw new Error(
        `Stripe subscription creation failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async cancelSubscription(externalSubscriptionId: string): Promise<void> {
    try {
      await this.stripe.subscriptions.cancel(externalSubscriptionId);
    } catch (error) {
      throw new Error(
        `Stripe subscription cancellation failed: ${this.getErrorMessage(error, 'Unknown Stripe error')}`,
      );
    }
  }

  async verifyWebhookSignature(
    request: WebhookVerificationRequest,
  ): Promise<WebhookVerificationResponse> {
    try {
      const event = this.stripe.webhooks.constructEvent(
        request.payload,
        request.signature,
        this.webhookSecret,
      );

      return {
        isValid: !!event,
        provider: PaymentProvider.STRIPE,
      };
    } catch (error) {
      return {
        isValid: false,
        provider: PaymentProvider.STRIPE,
      };
    }
  }

  async parseWebhookPayload(rawPayload: any): Promise<PaymentWebhookEvent> {
    const event = rawPayload as Stripe.Event;
    let status = PaymentStatus.PENDING;

    if (event.type === 'payment_intent.succeeded') {
      status = PaymentStatus.COMPLETED;
    } else if (event.type === 'payment_intent.payment_failed') {
      status = PaymentStatus.FAILED;
    } else if (event.type === 'payment_intent.canceled') {
      status = PaymentStatus.CANCELLED;
    }

    const data = event.data.object as any;

    return {
      type: event.type,
      provider: PaymentProvider.STRIPE,
      externalPaymentId: data.id,
      status: status,
      amount: (data.amount || 0) / 100,
      currency: (data.currency || 'USD').toUpperCase(),
      metadata: data.metadata,
      timestamp: new Date(data.created * 1000),
      raw: event,
    };
  }

  getWebhookSecret(): string {
    return this.webhookSecret;
  }

  private mapStripeStatus(status: string): PaymentStatus {
    const statusMap: Record<string, PaymentStatus> = {
      succeeded: PaymentStatus.COMPLETED,
      processing: PaymentStatus.PROCESSING,
      requires_action: PaymentStatus.PENDING,
      requires_capture: PaymentStatus.PENDING,
      requires_confirmation: PaymentStatus.PENDING,
      requires_payment_method: PaymentStatus.PENDING,
      canceled: PaymentStatus.CANCELLED,
    };
    return statusMap[status] || PaymentStatus.PENDING;
  }

  private mapStripeRefundStatus(status: string): RefundStatus {
    const statusMap: Record<string, RefundStatus> = {
      succeeded: RefundStatus.COMPLETED,
      pending: RefundStatus.PROCESSING,
      failed: RefundStatus.FAILED,
      canceled: RefundStatus.CANCELLED,
    };
    return statusMap[status] || RefundStatus.PROCESSING;
  }

  async healthCheck(): Promise<boolean> {
    try {
      const balance = await this.stripe.balance.retrieve();
      return !!balance;
    } catch (error) {
      return false;
    }
  }
}

/**
 * Social Post Processor (BullMQ Worker)
 * Handles publish, retry, and repost jobs from the social-publishing queue.
 */

import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { InjectQueue } from '@nestjs/bullmq';
import { Job, Queue } from 'bullmq';
import { PostStatus, PublishStatus } from '@prisma/client';
import { PrismaService } from '../../database/prisma.service';
import { SocialAccountService } from '../services/social-account.service';
import { AutoRepostService } from '../services/auto-repost.service';
import { PublishJobPayload } from '../types/social.types';

export const SOCIAL_QUEUE = 'social-publishing';

/** Retry delays in ascending order (ms) */
const RETRY_DELAYS_MS = [
  5 * 60 * 1000,      // 5 min
  15 * 60 * 1000,     // 15 min
  60 * 60 * 1000,     // 1 hr
  3 * 60 * 60 * 1000, // 3 hrs (ceiling)
];

@Processor(SOCIAL_QUEUE, { concurrency: 5 })
export class SocialPostProcessor extends WorkerHost {
  private readonly logger = new Logger(SocialPostProcessor.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly accountService: SocialAccountService,
    private readonly autoRepost: AutoRepostService,
    @InjectQueue(SOCIAL_QUEUE) private readonly queue: Queue,
  ) {
    super();
  }

  async process(job: Job<PublishJobPayload>): Promise<void> {
    this.logger.log(
      `Processing job ${job.id} type=${job.data.type} post=${job.data.postId}`,
    );

    switch (job.data.type) {
      case 'publish':
        await this.handlePublish(job);
        break;
      case 'retry':
        await this.handleRetry(job);
        break;
      case 'repost':
        await this.handleRepost(job);
        break;
      case 'check-reposts':
        await this.autoRepost.checkAndScheduleReposts();
        break;
      default:
        throw new Error(`Unknown job type: ${(job.data as any).type}`);
    }
  }

  // ÔöÇÔöÇ Publish ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handlePublish(job: Job<PublishJobPayload>): Promise<void> {
    const { postId, organizationId } = job.data;

    const post = await this.prisma.scheduledPost.findFirst({
      where: { id: postId, organizationId },
      include: {
        accounts: { include: { account: true } },
        publishResults: true,
      },
    });

    if (!post) {
      this.logger.warn(`Post ${postId} not found, skipping`);
      return;
    }

    if (
      post.status === PostStatus.CANCELLED ||
      post.status === PostStatus.PUBLISHED
    ) {
      this.logger.log(`Post ${postId} is ${post.status}, skipping`);
      return;
    }

    // Mark as publishing
    await this.prisma.scheduledPost.update({
      where: { id: postId },
      data: { status: PostStatus.PUBLISHING },
    });

    let successCount = 0;
    let failCount = 0;

    for (const result of post.publishResults) {
      const join = post.accounts.find((a) => a.accountId === result.accountId);
      const account = join?.account;
      if (!account) continue;

      try {
        // Refresh expired token before publishing
        if (account.tokenExpiresAt && account.tokenExpiresAt <= new Date()) {
          this.logger.log(`Refreshing expired token for account ${account.id}`);
          await this.accountService.refreshAccountToken(account.id);
        }

        const decryptedAccount = await this.accountService.getDecryptedAccount(
          account.id,
        );
        const publisher = this.accountService.getPublisher(account.platform);
        const publishResult = await publisher.publish(decryptedAccount, post);

        if (publishResult.error) {
          throw new Error(publishResult.error);
        }

        await this.prisma.postPublishResult.update({
          where: { id: result.id },
          data: {
            status: PublishStatus.SUCCESS,
            platformPostId: publishResult.platformPostId ?? null,
            platformUrl: publishResult.platformUrl ?? null,
            publishedAt: new Date(),
            attemptCount: { increment: 1 },
          },
        });

        successCount++;
        this.logger.log(
          `Published post ${postId} ÔåÆ ${account.platform}: ${publishResult.platformPostId}`,
        );
      } catch (err) {
        const errMsg = (err as Error).message;
        failCount++;

        const newAttemptCount = result.attemptCount + 1;
        const retryDelayIdx = Math.min(
          newAttemptCount - 1,
          RETRY_DELAYS_MS.length - 1,
        );
        const retryDelay = RETRY_DELAYS_MS[retryDelayIdx];
        const nextRetryAt = new Date(Date.now() + retryDelay);

        await this.prisma.postPublishResult.update({
          where: { id: result.id },
          data: {
            status: PublishStatus.FAILED,
            errorMessage: errMsg,
            attemptCount: { increment: 1 },
            nextRetryAt,
          },
        });

        this.logger.error(
          `Failed to publish post ${postId} ÔåÆ ${account.platform}: ${errMsg}`,
        );

        // Schedule retry
        await this.enqueueRetry(result.id, postId, organizationId, retryDelay);
      }
    }

    // Determine final post status
    const finalStatus =
      successCount > 0 ? PostStatus.PUBLISHED : PostStatus.FAILED;

    await this.prisma.scheduledPost.update({
      where: { id: postId },
      data: {
        status: finalStatus,
        publishedAt: finalStatus === PostStatus.PUBLISHED ? new Date() : null,
      },
    });

    // Schedule first repost if enabled and at least partially published
    if (finalStatus === PostStatus.PUBLISHED && post.autoRepostEnabled) {
      const repostDelay =
        (post.repostIntervalDays ?? 7) * 24 * 60 * 60 * 1000;

      await this.queue.add(
        `repost:${postId}`,
        {
          type: 'repost',
          postId,
          organizationId,
          accountIds: post.accounts.map((a) => a.accountId),
        } satisfies PublishJobPayload,
        { delay: repostDelay, removeOnComplete: 20 },
      );

      this.logger.log(
        `Scheduled first repost for ${postId} in ${post.repostIntervalDays ?? 7} days`,
      );
    }
  }

  // ÔöÇÔöÇ Retry ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handleRetry(job: Job<PublishJobPayload>): Promise<void> {
    const { resultId, postId, organizationId } = job.data;
    if (!resultId) return;

    const result = await this.prisma.postPublishResult.findUnique({
      where: { id: resultId },
      include: { account: true, post: true },
    });

    if (!result) {
      this.logger.warn(`PostPublishResult ${resultId} not found, skipping`);
      return;
    }

    if (result.status === PublishStatus.SUCCESS) {
      this.logger.log(`Result ${resultId} already succeeded`);
      return;
    }

    await this.prisma.postPublishResult.update({
      where: { id: resultId },
      data: { status: PublishStatus.RETRYING },
    });

    try {
      if (
        result.account.tokenExpiresAt &&
        result.account.tokenExpiresAt <= new Date()
      ) {
        await this.accountService.refreshAccountToken(result.account.id);
      }

      const decryptedAccount = await this.accountService.getDecryptedAccount(
        result.account.id,
      );
      const publisher = this.accountService.getPublisher(
        result.account.platform,
      );
      const publishResult = await publisher.publish(decryptedAccount, result.post);

      if (publishResult.error) throw new Error(publishResult.error);

      await this.prisma.postPublishResult.update({
        where: { id: resultId },
        data: {
          status: PublishStatus.SUCCESS,
          platformPostId: publishResult.platformPostId ?? null,
          platformUrl: publishResult.platformUrl ?? null,
          publishedAt: new Date(),
          attemptCount: { increment: 1 },
          nextRetryAt: null,
        },
      });

      // Promote post status if all results now succeeded
      const allResults = await this.prisma.postPublishResult.findMany({
        where: { postId },
      });
      const allSuccess = allResults.every(
        (r) => r.status === PublishStatus.SUCCESS,
      );

      if (allSuccess) {
        await this.prisma.scheduledPost.update({
          where: { id: postId },
          data: { status: PostStatus.PUBLISHED, publishedAt: new Date() },
        });
      }

      this.logger.log(`Retry succeeded for result ${resultId}`);
    } catch (err) {
      const errMsg = (err as Error).message;
      const newCount = result.attemptCount + 1;
      const retryDelayIdx = Math.min(newCount - 1, RETRY_DELAYS_MS.length - 1);
      const retryDelay = RETRY_DELAYS_MS[retryDelayIdx];

      await this.prisma.postPublishResult.update({
        where: { id: resultId },
        data: {
          status: PublishStatus.FAILED,
          errorMessage: errMsg,
          attemptCount: { increment: 1 },
          nextRetryAt: new Date(Date.now() + retryDelay),
        },
      });

      this.logger.error(`Retry failed for result ${resultId}: ${errMsg}`);

      // Only schedule further retries if not at ceiling
      if (newCount < RETRY_DELAYS_MS.length) {
        await this.enqueueRetry(resultId, postId, organizationId, retryDelay);
      }
    }
  }

  // ÔöÇÔöÇ Repost ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handleRepost(job: Job<PublishJobPayload>): Promise<void> {
    await this.autoRepost.scheduleRepost(job.data.postId);
  }

  // ÔöÇÔöÇ Private helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async enqueueRetry(
    resultId: string,
    postId: string,
    organizationId: string,
    delay: number,
  ): Promise<void> {
    const payload: PublishJobPayload = {
      type: 'retry',
      postId,
      organizationId,
      accountIds: [],
      resultId,
    };

    await this.queue.add(`retry:${resultId}`, payload, {
      delay,
      attempts: 1,
      removeOnComplete: 10,
      removeOnFail: 10,
    });

    this.logger.log(
      `Queued retry for result ${resultId} in ${delay / 1000}s`,
    );
  }
}

/**
 * LinkedIn Publisher
 * LinkedIn Marketing API v2 ÔÇö UGC posts with optional media upload.
 */

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { BasePlatformPublisher } from './base.publisher';
import {
  OAuthExchangeResult,
  OAuthTokens,
  PlatformPublishResult,
  LinkedInPostResponse,
  LinkedInRegisterUploadResponse,
} from '../../types/social.types';

const LI_API = 'https://api.linkedin.com/v2';
const LI_OAUTH = 'https://www.linkedin.com/oauth/v2';
const OAUTH_SCOPE = 'w_member_social,r_liteprofile,r_emailaddress';

@Injectable()
export class LinkedInPublisher extends BasePlatformPublisher {
  private readonly logger = new Logger(LinkedInPublisher.name);

  constructor(config: ConfigService) {
    super(config);
  }

  // ÔöÇÔöÇ OAuth ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  getAuthorizationUrl(redirectUri: string, state: string): string {
    const clientId = this.config.get<string>('LINKEDIN_CLIENT_ID') ?? '';
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: clientId,
      redirect_uri: redirectUri,
      scope: OAUTH_SCOPE,
      state,
    });
    return `https://www.linkedin.com/oauth/v2/authorization?${params.toString()}`;
  }

  async exchangeCode(
    code: string,
    redirectUri: string,
  ): Promise<OAuthExchangeResult> {
    const clientId = this.config.get<string>('LINKEDIN_CLIENT_ID') ?? '';
    const clientSecret = this.config.get<string>('LINKEDIN_CLIENT_SECRET') ?? '';

    const tokenRes = await this.fetchJson<{
      access_token: string;
      refresh_token?: string;
      expires_in: number;
      scope: string;
    }>(`${LI_OAUTH}/accessToken`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code,
        redirect_uri: redirectUri,
        client_id: clientId,
        client_secret: clientSecret,
      }).toString(),
    });

    // Get profile info
    const profile = await this.fetchJson<{
      id: string;
      localizedFirstName?: string;
      localizedLastName?: string;
      profilePicture?: {
        'displayImage~'?: {
          elements?: Array<{ identifiers: Array<{ identifier: string }> }>;
        };
      };
    }>(`${LI_API}/me?projection=(id,localizedFirstName,localizedLastName,profilePicture(displayImage~:playableStreams))`, {
      headers: { Authorization: `Bearer ${tokenRes.access_token}` },
    });

    const displayName =
      [profile.localizedFirstName, profile.localizedLastName]
        .filter(Boolean)
        .join(' ') || profile.id;

    const avatar =
      profile.profilePicture?.['displayImage~']?.elements?.[0]?.identifiers?.[0]
        ?.identifier;

    return {
      accessToken: tokenRes.access_token,
      refreshToken: tokenRes.refresh_token,
      expiresAt: new Date(Date.now() + tokenRes.expires_in * 1000),
      scope: tokenRes.scope,
      platformUserId: profile.id,
      displayName,
      avatar,
    };
  }

  // ÔöÇÔöÇ Publish ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async publish(account: any, post: any): Promise<PlatformPublishResult> {
    try {
      const accessToken = this.decryptToken(account.accessToken);
      const authorUrn = `urn:li:person:${account.platformUserId}`;
      const mediaUrls: string[] = post.mediaUrls ?? [];

      let shareMediaCategory = 'NONE';
      const media: any[] = [];

      if (mediaUrls.length > 0) {
        const isVideo = /\.(mp4|mov|avi)$/i.test(mediaUrls[0]);
        shareMediaCategory = isVideo ? 'VIDEO' : 'IMAGE';

        for (const url of mediaUrls) {
          const asset = await this.uploadMedia(
            url,
            accessToken,
            authorUrn,
            isVideo ? 'video' : 'image',
          );
          media.push({
            status: 'READY',
            description: { text: post.content?.substring(0, 200) ?? '' },
            media: asset,
            title: { text: '' },
          });
        }
      } else if (post.link) {
        shareMediaCategory = 'ARTICLE';
        media.push({
          status: 'READY',
          originalUrl: post.link,
          title: { text: '' },
          description: { text: '' },
        });
      }

      const ugcBody = {
        author: authorUrn,
        lifecycleState: 'PUBLISHED',
        specificContent: {
          'com.linkedin.ugc.ShareContent': {
            shareCommentary: { text: this.buildText(post) },
            shareMediaCategory,
            media: media.length ? media : undefined,
          },
        },
        visibility: {
          'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC',
        },
      };

      const result = await this.fetchJson<LinkedInPostResponse>(
        `${LI_API}/ugcPosts`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${accessToken}`,
            'X-Restli-Protocol-Version': '2.0.0',
          },
          body: JSON.stringify(ugcBody),
        },
      );

      // LinkedIn returns the URN as the id
      const platformUrl = `https://www.linkedin.com/feed/update/${result.id}/`;

      this.logger.log(`LinkedIn post published: ${result.id}`);
      return { platformPostId: result.id, platformUrl };
    } catch (err) {
      return { error: (err as Error).message };
    }
  }

  // ÔöÇÔöÇ Token refresh ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async refreshToken(account: any): Promise<OAuthTokens> {
    const clientId = this.config.get<string>('LINKEDIN_CLIENT_ID') ?? '';
    const clientSecret = this.config.get<string>('LINKEDIN_CLIENT_SECRET') ?? '';
    const currentRefresh = this.decryptToken(account.refreshToken);

    const res = await this.fetchJson<{
      access_token: string;
      refresh_token?: string;
      expires_in: number;
    }>(`${LI_OAUTH}/accessToken`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: currentRefresh,
        client_id: clientId,
        client_secret: clientSecret,
      }).toString(),
    });

    return {
      accessToken: res.access_token,
      refreshToken: res.refresh_token,
      expiresAt: new Date(Date.now() + res.expires_in * 1000),
    };
  }

  async revokeToken(_account: any): Promise<void> {
    // LinkedIn does not have a programmatic token revocation endpoint;
    // deletion is handled by user through LinkedIn settings.
  }

  // ÔöÇÔöÇ Private helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async uploadMedia(
    mediaUrl: string,
    accessToken: string,
    ownerUrn: string,
    mediaType: 'image' | 'video',
  ): Promise<string> {
    const recipeType =
      mediaType === 'video'
        ? 'urn:li:digitalmediaRecipe:feedshare-video'
        : 'urn:li:digitalmediaRecipe:feedshare-image';

    // Register upload
    const registerRes = await this.fetchJson<LinkedInRegisterUploadResponse>(
      `${LI_API}/assets?action=registerUpload`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${accessToken}`,
        },
        body: JSON.stringify({
          registerUploadRequest: {
            recipes: [recipeType],
            owner: ownerUrn,
            serviceRelationships: [
              {
                relationshipType: 'OWNER',
                identifier: 'urn:li:userGeneratedContent',
              },
            ],
          },
        }),
      },
    );

    const uploadMechanism =
      registerRes.value.uploadMechanism[
        'com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest'
      ];
    const uploadUrl = uploadMechanism.uploadUrl;
    const asset = registerRes.value.asset;

    // Fetch media bytes and upload
    const mediaRes = await fetch(mediaUrl);
    if (!mediaRes.ok) {
      throw new Error(`Failed to fetch media for LinkedIn upload: ${mediaUrl}`);
    }
    const buffer = await mediaRes.arrayBuffer();

    await fetch(uploadUrl, {
      method: 'PUT',
      headers: {
        'Content-Type':
          mediaType === 'video' ? 'video/mp4' : 'image/jpeg',
        Authorization: `Bearer ${accessToken}`,
        ...uploadMechanism.headers,
      },
      body: buffer,
    });

    return asset;
  }

  private buildText(post: any): string {
    const parts: string[] = [post.content ?? ''];
    if (post.hashtags?.length) {
      parts.push(
        '\n\n' +
          (post.hashtags as string[]).map((h: string) => `#${h.replace(/^#/, '')}`).join(' '),
      );
    }
    if (post.link && !(post.mediaUrls?.length)) {
      parts.push(`\n\n${post.link}`);
    }
    return parts.join('').trim().substring(0, 3000);
  }
}

/**
 * Pinterest Publisher
 * Pinterest API v5 ÔÇö OAuth 2.0 with PKCE.
 * Supports image pins, video pins, and carousel (multi-image) boards.
 *
 * Compliance notes:
 *  - Requires "pins:read_secret" + "pins:write" + "boards:read" + "boards:write" scopes.
 *  - Rate limits: 1,000 pin creations / day per user (standard access).
 *  - Images: JPEG/PNG, max 32 MB, min 100├ù100 px; Recommended 1000├ù1500 (2:3).
 *  - Videos: MP4/MOV, max 2 GB, 4ÔÇô15 minutes.
 *  - Media must be uploaded via the media endpoint before creating pins.
 *
 * Ref: https://developers.pinterest.com/docs/api/v5/
 */

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { BasePlatformPublisher } from './base.publisher';
import {
  OAuthExchangeResult,
  OAuthTokens,
  PlatformPublishResult,
  PinterestPinResponse,
  PinterestMediaUploadResponse,
} from '../../types/social.types';

const PINTEREST_API = 'https://api.pinterest.com/v5';
const PINTEREST_OAUTH = 'https://www.pinterest.com/oauth';

const OAUTH_SCOPE = [
  'pins:read',
  'pins:write',
  'boards:read',
  'boards:write',
  'user_accounts:read',
].join(',');

@Injectable()
export class PinterestPublisher extends BasePlatformPublisher {
  private readonly logger = new Logger(PinterestPublisher.name);

  constructor(config: ConfigService) {
    super(config);
  }

  // ÔöÇÔöÇ OAuth ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  getAuthorizationUrl(redirectUri: string, state: string): string {
    const clientId = this.config.get<string>('PINTEREST_APP_ID') ?? '';
    const params = new URLSearchParams({
      client_id: clientId,
      redirect_uri: redirectUri,
      response_type: 'code',
      scope: OAUTH_SCOPE,
      state,
    });
    return `${PINTEREST_OAUTH}/?${params.toString()}`;
  }

  async exchangeCode(
    code: string,
    redirectUri: string,
  ): Promise<OAuthExchangeResult> {
    const clientId = this.config.get<string>('PINTEREST_APP_ID') ?? '';
    const clientSecret = this.config.get<string>('PINTEREST_APP_SECRET') ?? '';

    const basicAuth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');

    const tokenRes = await this.fetchJson<{
      access_token: string;
      refresh_token?: string;
      expires_in: number;
      scope: string;
      token_type: string;
    }>(`${PINTEREST_API}/oauth/token`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Authorization: `Basic ${basicAuth}`,
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code,
        redirect_uri: redirectUri,
      }).toString(),
    });

    // Get user info
    const userRes = await this.fetchJson<{
      id: string;
      username: string;
      profile_image?: string;
    }>(`${PINTEREST_API}/user_account`, {
      headers: { Authorization: `Bearer ${tokenRes.access_token}` },
    });

    return {
      accessToken: tokenRes.access_token,
      refreshToken: tokenRes.refresh_token,
      expiresAt: new Date(Date.now() + tokenRes.expires_in * 1000),
      scope: tokenRes.scope,
      platformUserId: userRes.id,
      displayName: userRes.username,
      avatar: userRes.profile_image,
    };
  }

  // ÔöÇÔöÇ Publish ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async publish(account: any, post: any): Promise<PlatformPublishResult> {
    try {
      const accessToken = this.decryptToken(account.accessToken);
      const mediaUrls: string[] = post.mediaUrls ?? [];

      // Resolve board ID ÔÇö use stored pageId (board ID) or fetch default board
      const boardId = account.pageId ?? (await this.getDefaultBoardId(accessToken, account.platformUserId));

      const title = post.content?.split('\n')[0]?.substring(0, 100) ?? 'Pin';
      const description = this.buildPinDescription(post);
      const link = post.link ?? undefined;

      if (mediaUrls.length === 0) {
        throw new Error('Pinterest pins require at least one image or video URL.');
      }

      const isVideo = /\.(mp4|mov|avi|mkv)$/i.test(mediaUrls[0]);

      let pinId: string;

      if (isVideo) {
        pinId = await this.createVideoPin(
          accessToken,
          boardId,
          mediaUrls[0],
          title,
          description,
          link,
        );
      } else if (mediaUrls.length > 1) {
        // Carousel pin (up to 5 images)
        pinId = await this.createCarouselPin(
          accessToken,
          boardId,
          mediaUrls.slice(0, 5),
          title,
          description,
          link,
        );
      } else {
        // Single image pin
        pinId = await this.createImagePin(
          accessToken,
          boardId,
          mediaUrls[0],
          title,
          description,
          link,
        );
      }

      const platformUrl = `https://www.pinterest.com/pin/${pinId}/`;
      this.logger.log(`Pinterest pin created: ${pinId}`);

      return { platformPostId: pinId, platformUrl };
    } catch (err) {
      return { error: (err as Error).message };
    }
  }

  // ÔöÇÔöÇ Token management ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async refreshToken(account: any): Promise<OAuthTokens> {
    const clientId = this.config.get<string>('PINTEREST_APP_ID') ?? '';
    const clientSecret = this.config.get<string>('PINTEREST_APP_SECRET') ?? '';
    const basicAuth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');
    const refreshToken = this.decryptToken(account.refreshToken);

    const res = await this.fetchJson<{
      access_token: string;
      refresh_token?: string;
      expires_in: number;
    }>(`${PINTEREST_API}/oauth/token`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Authorization: `Basic ${basicAuth}`,
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
      }).toString(),
    });

    return {
      accessToken: res.access_token,
      refreshToken: res.refresh_token,
      expiresAt: new Date(Date.now() + res.expires_in * 1000),
    };
  }

  async revokeToken(account: any): Promise<void> {
    // Pinterest does not have a token revocation endpoint.
    // We simply log this and move on.
    this.logger.log(`Pinterest token revocation requested for account ${account.id} ÔÇö no-op`);
  }

  // ÔöÇÔöÇ Private helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  /** Get the first available board for the user, filtered to the user's own boards. */
  private async getDefaultBoardId(accessToken: string, _userId: string): Promise<string> {
    const res = await this.fetchJson<{
      items: Array<{ id: string; owner?: { username: string } }>;
    }>(`${PINTEREST_API}/boards?page_size=1`, {
      headers: { Authorization: `Bearer ${accessToken}` },
    });

    if (!res.items?.length) {
      throw new Error('No boards found on the Pinterest account. Create a board first.');
    }

    return res.items[0].id;
  }

  /** Creates a single-image pin using the Pin Create API. */
  private async createImagePin(
    accessToken: string,
    boardId: string,
    imageUrl: string,
    title: string,
    description: string,
    link?: string,
  ): Promise<string> {
    const body: Record<string, any> = {
      board_id: boardId,
      title,
      description,
      media_source: {
        source_type: 'image_url',
        url: imageUrl,
      },
    };

    if (link) body['link'] = link;

    const res = await this.fetchJson<PinterestPinResponse>(
      `${PINTEREST_API}/pins`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${accessToken}`,
        },
        body: JSON.stringify(body),
      },
    );

    return res.id;
  }

  /**
   * Creates a carousel pin (multiple images).
   * Pinterest calls these "carousel pins" ÔÇö supported via media_source.items array.
   */
  private async createCarouselPin(
    accessToken: string,
    boardId: string,
    imageUrls: string[],
    title: string,
    description: string,
    link?: string,
  ): Promise<string> {
    const body: Record<string, any> = {
      board_id: boardId,
      title,
      description,
      media_source: {
        source_type: 'multiple_image_urls',
        items: imageUrls.map((url, idx) => ({
          title: `${title} ${idx + 1}`,
          description,
          link: link ?? undefined,
          source_url: url,
        })),
      },
    };

    if (link) body['link'] = link;

    const res = await this.fetchJson<PinterestPinResponse>(
      `${PINTEREST_API}/pins`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${accessToken}`,
        },
        body: JSON.stringify(body),
      },
    );

    return res.id;
  }

  /**
   * Creates a video pin using the two-step upload flow:
   *  1. Register media upload ÔåÆ get upload_url + media_id
   *  2. Upload video binary to upload_url
   *  3. Create pin referencing media_id (poll until READY)
   */
  private async createVideoPin(
    accessToken: string,
    boardId: string,
    videoUrl: string,
    title: string,
    description: string,
    link?: string,
  ): Promise<string> {
    // 1. Register media
    const mediaReg = await this.fetchJson<PinterestMediaUploadResponse>(
      `${PINTEREST_API}/media`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${accessToken}`,
        },
        body: JSON.stringify({ media_type: 'video' }),
      },
    );

    // 2. Download and upload video
    const videoRes = await fetch(videoUrl);
    if (!videoRes.ok) throw new Error(`Failed to fetch video: ${videoUrl}`);
    const videoBuffer = Buffer.from(await videoRes.arrayBuffer());

    const uploadRes = await fetch(mediaReg.upload_url, {
      method: 'POST',
      headers: mediaReg.upload_parameters,
      body: videoBuffer,
    });

    if (!uploadRes.ok) {
      const errText = await uploadRes.text().catch(() => '');
      throw new Error(`Pinterest video upload failed: ${errText}`);
    }

    // 3. Poll until media is READY (max 5 min)
    await this.waitForMedia(mediaReg.media_id, accessToken);

    // 4. Create the pin
    const body: Record<string, any> = {
      board_id: boardId,
      title,
      description,
      media_source: {
        source_type: 'video_id',
        media_id: mediaReg.media_id,
      },
    };

    if (link) body['link'] = link;

    const res = await this.fetchJson<PinterestPinResponse>(
      `${PINTEREST_API}/pins`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${accessToken}`,
        },
        body: JSON.stringify(body),
      },
    );

    return res.id;
  }

  /** Polls media status until READY or FAILED (max 60 attempts ├ù 5s). */
  private async waitForMedia(
    mediaId: string,
    accessToken: string,
  ): Promise<void> {
    const MAX_POLLS = 60;
    const POLL_DELAY_MS = 5_000;

    for (let i = 0; i < MAX_POLLS; i++) {
      const status = await this.fetchJson<{ status: string }>(
        `${PINTEREST_API}/media/${mediaId}`,
        { headers: { Authorization: `Bearer ${accessToken}` } },
      );

      if (status.status === 'succeeded') return;
      if (status.status === 'failed') {
        throw new Error(`Pinterest media upload failed for media_id ${mediaId}`);
      }

      await new Promise((r) => setTimeout(r, POLL_DELAY_MS));
    }

    throw new Error(`Pinterest media processing timed out for media_id ${mediaId}`);
  }

  /** Builds a Pinterest-appropriate description from post data. */
  private buildPinDescription(post: any): string {
    const parts: string[] = [];

    if (post.content) parts.push(post.content.substring(0, 500));

    if (post.hashtags?.length) {
      const tags = (post.hashtags as string[])
        .slice(0, 20)
        .map((h: string) => `#${h}`)
        .join(' ');
      parts.push(tags);
    }

    return parts.join('\n\n').substring(0, 800);
  }
}

import { Controller, Get, Post, Put, Body, Param, UseGuards } from '@nestjs/common';
import { SubscriptionsService } from './subscriptions.service';
import { JwtAuthGuard } from '../common/guards/jwt.guard';
import { TenantGuard } from '../common/guards/tenant.guard';
import { CurrentUser } from '../common/decorators/user.decorator';

@Controller('api/subscriptions')
@UseGuards(JwtAuthGuard)
export class SubscriptionsController {
  constructor(private subscriptionsService: SubscriptionsService) {}

  /**
   * GET /api/subscriptions/plans
   * Get available billing plans
   */
  @Get('plans')
  async getPlans() {
    return this.subscriptionsService.getPlans();
  }

  /**
   * GET /api/organizations/:organizationId/subscription
   * Get subscription for organization
   */
  @Get('organizations/:organizationId/subscription')
  @UseGuards(TenantGuard)
  async getSubscription(@Param('organizationId') organizationId: string) {
    return this.subscriptionsService.getSubscription(organizationId);
  }

  /**
   * POST /api/organizations/:organizationId/subscription
   * Create subscription
   */
  @Post('organizations/:organizationId/subscription')
  @UseGuards(TenantGuard)
  async createSubscription(
    @Param('organizationId') organizationId: string,
    @Body() body: { planId: string; billingProfileId: string },
  ) {
    return this.subscriptionsService.createSubscription(
      organizationId,
      body.planId,
      body.billingProfileId,
    );
  }

  /**
   * GET /api/organizations/:organizationId/invoices
   * Get organization invoices
   */
  @Get('organizations/:organizationId/invoices')
  @UseGuards(TenantGuard)
  async getInvoices(
    @Param('organizationId') organizationId: string,
    @CurrentUser('sub') userId: string,
  ) {
    return this.subscriptionsService.getInvoices(organizationId);
  }
}

import { Injectable } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';

@Injectable()
export class SubscriptionsService {
  constructor(private prisma: PrismaService) {}

  /**
   * Get subscription plans
   */
  async getPlans() {
    return this.prisma.billingPlan.findMany({
      orderBy: { pricePerMonth: 'asc' },
    });
  }

  /**
   * Get organization subscription
   */
  async getSubscription(organizationId: string) {
    const subscription = await this.prisma.subscription.findUnique({
      where: { organizationId },
      include: {
        plan: true,
        invoices: { take: 10, orderBy: { issuedAt: 'desc' } },
      },
    });

    if (!subscription) {
      return null;
    }

    return subscription;
  }

  /**
   * Create subscription (Stripe integration to be implemented)
   */
  async createSubscription(
    organizationId: string,
    planId: string,
    billingProfileId: string,
  ) {
    // TODO: Integrate with Stripe
    // 1. Create Stripe subscription
    // 2. Store subscription data
    // 3. Setup webhook for subscription events

    const subscription = await this.prisma.subscription.create({
      data: {
        organizationId,
        planId,
        status: 'TRIAL',
        currentPeriodStart: new Date(),
        currentPeriodEnd: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000), // 14 day trial
      },
    });

    return subscription;
  }

  /**
   * Cancel subscription
   */
  async cancelSubscription(organizationId: string) {
    // TODO: Integrate with Stripe to cancel subscription

    const subscription = await this.prisma.subscription.update({
      where: { organizationId },
      data: {
        status: 'CANCELLED',
        cancelledAt: new Date(),
      },
    });

    return subscription;
  }

  /**
   * Update billing profile
   */
  async updateBillingProfile(organizationId: string, billingData: any) {
    const profile = await this.prisma.billingProfile.updateMany({
      where: { organizationId },
      data: billingData,
    });

    return profile;
  }

  /**
   * Get invoices for organization
   */
  async getInvoices(organizationId: string, page: number = 1, limit: number = 10) {
    const skip = (page - 1) * limit;

    const [invoices, total] = await Promise.all([
      this.prisma.invoice.findMany({
        where: {
          subscription: { organizationId },
        },
        skip,
        take: limit,
        orderBy: { issuedAt: 'desc' },
      }),
      this.prisma.invoice.count({
        where: {
          subscription: { organizationId },
        },
      }),
    ]);

    return {
      data: invoices,
      total,
      page,
      pages: Math.ceil(total / limit),
    };
  }
}

