  @Min(0)
  @Max(1)
  lipSyncIntensity?: number;

  @IsOptional()
  @IsString()
  resolution?: '720p' | '1080p' | '4k';

  @IsOptional()
  @IsBoolean()
  enableCaptions?: boolean;

  @IsOptional()
  @IsBoolean()
  backgroundMusic?: boolean;

  @IsOptional()
  @IsString()
  aspectRatio?: '9:16' | '1:1' | '16:9';
}

/**
 * Video Job Processor (BullMQ Worker)
 * Handles all async video processing jobs from the queue.
 */

import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Job } from 'bullmq';
import { PrismaService } from '../../database/prisma.service';
import { FfmpegService } from '../services/ffmpeg.service';
import { TtsService } from '../services/tts.service';
import { SubtitleService } from '../services/subtitle.service';
import { StorageService } from '../services/storage.service';
import { VideoJobPayload } from '../types/video.types';
import { VideoJobStatus } from '@prisma/client';
import * as path from 'path';
import * as os from 'os';
import * as fs from 'fs';
import * as crypto from 'crypto';

export const VIDEO_QUEUE = 'video-processing';

@Processor(VIDEO_QUEUE)
export class VideoProcessor extends WorkerHost {
  private readonly logger = new Logger(VideoProcessor.name);

  constructor(
    private readonly prisma:    PrismaService,
    private readonly ffmpeg:    FfmpegService,
    private readonly tts:       TtsService,
    private readonly subtitles: SubtitleService,
    private readonly storage:   StorageService,
  ) {
    super();
  }

  async process(job: Job<VideoJobPayload>): Promise<void> {
    this.logger.log(`Processing job ${job.id} type=${job.data.type}`);

    const dbJob = await this.prisma.videoJob.findFirst({
      where: { bullJobId: String(job.id) },
    });

    if (dbJob) {
      await this.prisma.videoJob.update({
        where: { id: dbJob.id },
        data:  { status: VideoJobStatus.PROCESSING, startedAt: new Date() },
      });
    }

    try {
      switch (job.data.type) {
        case 'render':    await this.handleRender(job);    break;
        case 'tts':       await this.handleTts(job);       break;
        case 'subtitles': await this.handleSubtitles(job); break;
        case 'transcode': await this.handleTranscode(job); break;
        default:
          throw new Error(`Unknown job type: ${(job.data as any).type}`);
      }

      if (dbJob) {
        await this.prisma.videoJob.update({
          where: { id: dbJob.id },
          data:  { status: VideoJobStatus.DONE, completedAt: new Date(), progress: 100 },
        });
      }
    } catch (err: unknown) {
      const msg = (err as Error).message;
      this.logger.error(`Job ${job.id} failed: ${msg}`);
      if (dbJob) {
        await this.prisma.videoJob.update({
          where: { id: dbJob.id },
          data:  { status: VideoJobStatus.FAILED, errorMessage: msg },
        });
      }
      throw err;
    }
  }

  // ÔöÇÔöÇ Render ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handleRender(job: Job<VideoJobPayload>): Promise<void> {
    if (job.data.type !== 'render') return;
    const { projectId, organizationId, outputFormat, quality } = job.data;

    const project = await this.prisma.videoProject.findUnique({
      where:   { id: projectId },
      include: { scenes: { orderBy: { order: 'asc' } }, mediaAssets: true },
    });
    if (!project) throw new Error(`Project ${projectId} not found`);

    const tmpDir  = fs.mkdtempSync(path.join(os.tmpdir(), 'bel-render-'));
    const outFile = path.join(tmpDir, `output.${outputFormat}`);

    try {
      const options = {
        width:         project.width,
        height:        project.height,
        fps:           project.fps,
        format:        outputFormat,
        quality,
      };

      // Download and concatenate scene assets
      const segments = await this.buildSegments(project, tmpDir);

      if (segments.length > 0) {
        await this.ffmpeg.concatenateClips(segments, outFile, options, (pct) => {
          job.updateProgress(pct).catch(() => {});
        });
      } else {
        // No video assets ÔÇö create a black video placeholder
        await this.createBlackVideo(outFile, project.width, project.height, project.fps,
          (project.durationMs ?? 5000) / 1000, options);
      }

      // Generate thumbnail
      const thumbFile = path.join(tmpDir, 'thumb.jpg');
      await this.ffmpeg.generateThumbnail(outFile, thumbFile, 0, 1280, 720);

      // Upload final render + thumbnail
      const renderKey = `${organizationId}/renders/${projectId}-${Date.now()}.${outputFormat}`;
      const thumbKey  = `${organizationId}/renders/${projectId}-thumb.jpg`;

      await Promise.all([
        this.storage.upload(outFile,   renderKey, `video/${outputFormat}`),
        this.storage.upload(thumbFile, thumbKey, 'image/jpeg'),
      ]);

      await this.prisma.videoProject.update({
        where: { id: projectId },
        data:  {
          outputUrl:    this.storage.publicUrl(renderKey),
          thumbnailUrl: this.storage.publicUrl(thumbKey),
          status:       'READY',
        },
      });
    } finally {
      try { fs.rmSync(tmpDir, { recursive: true }); } catch { /* ignore */ }
    }
  }

  // ÔöÇÔöÇ TTS ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handleTts(job: Job<VideoJobPayload>): Promise<void> {
    if (job.data.type !== 'tts') return;
    const { sceneId, text, voiceId, organizationId } = job.data;

    const { audioPath, durationMs } = await this.tts.synthesize(text, { voice: voiceId as any });
    const key = await this.storage.uploadTemp(audioPath, organizationId, `vo-${sceneId}.mp3`);

    await this.prisma.videoScene.update({
      where: { id: sceneId },
      data:  { voiceoverUrl: this.storage.publicUrl(key), durationMs },
    });
  }

  // ÔöÇÔöÇ Subtitles ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handleSubtitles(job: Job<VideoJobPayload>): Promise<void> {
    if (job.data.type !== 'subtitles') return;
    const { projectId, audioUrl, language } = job.data;

    // Download audio to temp file for Whisper
    const tmpAudio = path.join(os.tmpdir(), `bel-audio-${crypto.randomUUID()}.mp3`);
    await this.storage.downloadToFile(audioUrl, tmpAudio);

    try {
      const result = await this.subtitles.transcribeAudio(tmpAudio, language);

      await this.prisma.subtitleTrack.create({
        data: {
          videoProjectId: projectId,
          language,
          srtContent:    result.srt,
          vttContent:    result.vtt,
          autoGenerated: true,
        },
      });
    } finally {
      try { fs.unlinkSync(tmpAudio); } catch { /* ignore */ }
    }
  }

  // ÔöÇÔöÇ Transcode ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async handleTranscode(job: Job<VideoJobPayload>): Promise<void> {
    if (job.data.type !== 'transcode') return;
    const { assetId, sourceKey, targetFormat, organizationId } = job.data;

    const tmpIn  = path.join(os.tmpdir(), `bel-src-${crypto.randomUUID()}`);
    const tmpOut = path.join(os.tmpdir(), `bel-out-${crypto.randomUUID()}.${targetFormat}`);

    await this.storage.downloadToFile(sourceKey, tmpIn);

    try {
      await this.ffmpeg.transcode(tmpIn, tmpOut, { format: targetFormat as any });

      const key = `${organizationId}/transcoded/${assetId}.${targetFormat}`;
      await this.storage.upload(tmpOut, key, `video/${targetFormat}`);

      await this.prisma.mediaAsset.update({
        where: { id: assetId },
        data:  {
          storageKey: key,
          publicUrl:  this.storage.publicUrl(key),
        },
      });
    } finally {
      try { fs.unlinkSync(tmpIn); }  catch { /* ignore */ }
      try { fs.unlinkSync(tmpOut); } catch { /* ignore */ }
    }
  }

  // ÔöÇÔöÇ Private helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async buildSegments(
    project: any,
    tmpDir: string,
  ): Promise<any[]> {
    const segments: any[] = [];

    for (const asset of project.mediaAssets.filter(
      (a: any) => a.mediaType === 'VIDEO_CLIP',
    )) {
      const localPath = path.join(tmpDir, `asset-${asset.id}${path.extname(asset.storageKey)}`);
      try {
        await this.storage.downloadToFile(asset.storageKey, localPath);
        segments.push({
          inputPath:  localPath,
          startMs:    0,
          durationMs: asset.durationMs ?? 5000,
          volume:     1,
          speed:      1,
          filters:    [],
        });
      } catch (err: unknown) {
        this.logger.warn(`Could not download asset ${asset.id}: ${(err as Error).message}`);
      }
    }

    return segments;
  }

  private async createBlackVideo(
    outputPath: string,
    width: number,
    height: number,
    fps: number,
    durationSec: number,
    _options: unknown,
  ): Promise<void> {
    return new Promise((resolve, reject) => {
      const ffmpegLib = require('fluent-ffmpeg');
      ffmpegLib()
        .input(`color=c=black:s=${width}x${height}:r=${fps}`)
        .inputOptions(['-f lavfi'])
        .input('anullsrc')
        .inputOptions(['-f lavfi'])
        .duration(durationSec)
        .videoCodec('libx264')
        .audioCodec('aac')
        .outputOptions(['-shortest', '-movflags +faststart'])
        .output(outputPath)
        .on('end', resolve)
        .on('error', reject)
        .run();
    });
  }
}

/**
 * Video Project Service
 * Orchestrates project CRUD, scene generation, render job dispatch, and timeline management.
 */

import {
  Injectable,
  Logger,
  NotFoundException,
  ForbiddenException,
  BadRequestException,
} from '@nestjs/common';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';
import { PrismaService } from '../../database/prisma.service';
import { SceneGeneratorService } from './scene-generator.service';
import { VIDEO_QUEUE } from '../processors/video.processor';
import {
  CreateProjectDto,
  GenerateFromScriptDto,
  RenderProjectDto,
  UpdateTimelineDto,
  GenerateSubtitlesDto,
  UpdateSceneDto,
} from '../dto/video.dto';
import { VideoJobType, VideoJobStatus, VideoStatus } from '@prisma/client';
import { TimelineState } from '../types/video.types';
@Injectable()
export class VideoProjectService {
  private readonly logger = new Logger(VideoProjectService.name);

  constructor(
    private readonly prisma:    PrismaService,
    private readonly generator: SceneGeneratorService,
    @InjectQueue(VIDEO_QUEUE)
    private readonly queue:     Queue,
  ) {}

  // ÔöÇÔöÇ Project CRUD ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async createProject(
    dto: CreateProjectDto,
    userId: string,
    organizationId: string,
  ) {
    const [width, height] = this.resolveResolution(dto.aspectRatio ?? '16:9');

    const project = await this.prisma.videoProject.create({
      data: {
        organizationId,
        createdById: userId,
        title:       dto.title,
        description: dto.description,
        script:      dto.script,
        status:      VideoStatus.DRAFT,
        width,
        height,
      },
    });

    this.logger.log(`Project created: ${project.id}`);
    return project;
  }

  async listProjects(organizationId: string, _userId: string) {
    return this.prisma.videoProject.findMany({
      where:   { organizationId },
      orderBy: { updatedAt: 'desc' },
      include: { _count: { select: { scenes: true, processingJobs: true } } },
    });
  }

  async getProject(projectId: string, organizationId: string) {
    const project = await this.prisma.videoProject.findFirst({
      where:   { id: projectId, organizationId },
      include: {
        scenes:         { orderBy: { order: 'asc' } },
        subtitleTracks: true,
        processingJobs: { orderBy: { createdAt: 'desc' }, take: 10 },
        mediaAssets:    { orderBy: { createdAt: 'desc' } },
      },
    });
    if (!project) throw new NotFoundException(`Project ${projectId} not found`);
    return project;
  }

  async updateProject(
    projectId: string,
    organizationId: string,
    patch: Partial<{ title: string; description: string; script: string }>,
  ) {
    await this.assertOwnership(projectId, organizationId);
    return this.prisma.videoProject.update({ where: { id: projectId }, data: patch });
  }

  async deleteProject(projectId: string, organizationId: string): Promise<void> {
    await this.assertOwnership(projectId, organizationId);
    await this.prisma.videoProject.update({
      where: { id: projectId },
      data:  { status: VideoStatus.ARCHIVED },
    });
    this.logger.log(`Project archived: ${projectId}`);
  }

  // ÔöÇÔöÇ Scene generation ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async generateFromScript(
    projectId: string,
    organizationId: string,
    dto: GenerateFromScriptDto,
  ): Promise<TimelineState> {
    await this.assertOwnership(projectId, organizationId);

    await this.prisma.videoProject.update({
      where: { id: projectId },
      data:  { status: VideoStatus.PROCESSING, script: dto.script },
    });

    try {
      const timeline = await this.generator.generateFromScript({
        projectId,
        organizationId,
        script:      dto.script,
        voiceId:     dto.voiceId,
        style:       dto.style,
        aspectRatio: dto.aspectRatio,
        language:    dto.language,
      });

      await this.prisma.videoProject.update({
        where: { id: projectId },
        data:  { status: VideoStatus.DRAFT },
      });

      return timeline;
    } catch (err: unknown) {
      await this.prisma.videoProject.update({
        where: { id: projectId },
        data:  { status: VideoStatus.FAILED },
      });
      throw err;
    }
  }

  // ÔöÇÔöÇ Timeline management ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async saveTimeline(
    projectId: string,
    organizationId: string,
    dto: UpdateTimelineDto,
  ) {
    await this.assertOwnership(projectId, organizationId);

    let parsed: TimelineState;
    try {
      parsed = JSON.parse(dto.timelineJson);
    } catch {
      throw new BadRequestException('Invalid timelineJson: not valid JSON');
    }

    return this.prisma.videoProject.update({
      where: { id: projectId },
      data:  { timelineJson: dto.timelineJson, durationMs: parsed.durationMs },
    });
  }

  async getTimeline(projectId: string, organizationId: string): Promise<TimelineState | null> {
    const project = await this.getProject(projectId, organizationId);
    if (!project.timelineJson) return null;
    return JSON.parse(project.timelineJson) as TimelineState;
  }

  // ÔöÇÔöÇ Scene management ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async updateScene(
    sceneId: string,
    projectId: string,
    organizationId: string,
    dto: UpdateSceneDto,
  ) {
    await this.assertOwnership(projectId, organizationId);
    return this.prisma.videoScene.update({
      where: { id: sceneId },
      data:  dto,
    });
  }

  // ÔöÇÔöÇ Render ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async queueRender(
    projectId: string,
    organizationId: string,
    dto: RenderProjectDto,
  ) {
    await this.assertOwnership(projectId, organizationId);

    const format  = dto.format  ?? 'mp4';
    const quality = dto.quality ?? 'medium';

    // Create DB job record
    const dbJob = await this.prisma.videoJob.create({
      data: {
        videoProjectId: projectId,
        jobType:        VideoJobType.RENDER,
        status:         VideoJobStatus.QUEUED,
        inputJson:      JSON.stringify({ format, quality }),
      },
    });

    // Add to BullMQ queue
    const bullJob = await this.queue.add(
      'render',
      { type: 'render', projectId, organizationId, outputFormat: format, quality },
      { attempts: 2, backoff: { type: 'exponential', delay: 5000 } },
    );

    // Store bullJob ID for tracking
    await this.prisma.videoJob.update({
      where: { id: dbJob.id },
      data:  { bullJobId: String(bullJob.id) },
    });

    await this.prisma.videoProject.update({
      where: { id: projectId },
      data:  { status: VideoStatus.PROCESSING },
    });

    this.logger.log(`Render queued: project=${projectId} bullJob=${bullJob.id}`);
    return { jobId: dbJob.id, bullJobId: bullJob.id };
  }

  async getRenderStatus(projectId: string, organizationId: string) {
    await this.assertOwnership(projectId, organizationId);
    return this.prisma.videoJob.findMany({
      where:   { videoProjectId: projectId, jobType: VideoJobType.RENDER },
      orderBy: { createdAt: 'desc' },
      take:    5,
    });
  }

  // ÔöÇÔöÇ Subtitles ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  async generateSubtitles(
    projectId: string,
    organizationId: string,
    dto: GenerateSubtitlesDto,
  ) {
    await this.assertOwnership(projectId, organizationId);
    const project = await this.getProject(projectId, organizationId);

    if (!project.outputUrl) {
      throw new BadRequestException('Project must be rendered before generating subtitles from audio');
    }

    const dbJob = await this.prisma.videoJob.create({
      data: {
        videoProjectId: projectId,
        jobType:        VideoJobType.GENERATE_SUBS,
        status:         VideoJobStatus.QUEUED,
      },
    });

    const bullJob = await this.queue.add(
      'subtitles',
      {
        type:      'subtitles',
        projectId,
        audioUrl:  project.outputUrl,
        language:  dto.language ?? 'en',
        organizationId,
      },
      { attempts: 2 },
    );

    await this.prisma.videoJob.update({
      where: { id: dbJob.id },
      data:  { bullJobId: String(bullJob.id) },
    });

    return { jobId: dbJob.id, bullJobId: bullJob.id };
  }

  async getSubtitles(projectId: string, organizationId: string) {
    await this.assertOwnership(projectId, organizationId);
    return this.prisma.subtitleTrack.findMany({ where: { videoProjectId: projectId } });
  }

  // ÔöÇÔöÇ Private ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

  private async assertOwnership(projectId: string, organizationId: string): Promise<void> {
    const project = await this.prisma.videoProject.findFirst({
      where: { id: projectId },
      select: { organizationId: true },
    });
    if (!project) throw new NotFoundException(`Project ${projectId} not found`);
    if (project.organizationId !== organizationId) throw new ForbiddenException('Access denied');
  }

  private resolveResolution(ratio: '16:9' | '9:16' | '1:1'): [number, number] {
    if (ratio === '9:16') return [1080, 1920];
    if (ratio === '1:1')  return [1080, 1080];
    return [1920, 1080];
  }
}

'use client';

import { useState } from 'react';
import { motion } from 'motion/react';
import { Wand2, Download, Loader, AlertCircle } from 'lucide-react';

export interface ImageGeneratorProps {
  onGenerated?: (urls: string[]) => void;
}

export const ImageGenerator = ({ onGenerated }: ImageGeneratorProps) => {
  const [prompt, setPrompt] = useState('');
  const [size, setSize] = useState('1024x1024');
  const [quantity, setQuantity] = useState(1);
  const [quality, setQuality] = useState<'standard' | 'hd'>('standard');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [images, setImages] = useState<string[]>([]);

  const handleGenerate = async () => {
    if (!prompt.trim()) {
      setError('Please enter an image description');
      return;
    }

    setIsLoading(true);
    setError('');

    try {
      const response = await fetch('/api/ai/image', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${localStorage.getItem('accessToken')}`,
        },
        body: JSON.stringify({
          prompt,
          size,
          quantity,
          quality,
        }),
      });

      if (!response.ok) {
        throw new Error('Image generation failed');
      }

      const data = await response.json();
      setImages(data.data.images);
      onGenerated?.(data.data.images);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Generation failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="max-w-6xl mx-auto"
    >
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-2">­ƒÄ¿ Image Generator</h1>
        <p className="text-black/60 dark:text-white/60">
          Create stunning AI-generated images from text descriptions
        </p>
      </div>

      {/* Controls */}
      <motion.div
        className="p-6 rounded-lg border border-black/10 dark:border-white/10 bg-white/50 dark:bg-black/50 mb-8"
      >
        <div className="space-y-4">
          {/* Prompt */}
          <div>
            <label className="block text-sm font-medium mb-2">Image Description</label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Describe the image you want to generate..."
              rows={4}
              className="w-full px-4 py-3 border rounded-lg border-black/10 dark:border-white/10 bg-white dark:bg-black/50 focus:outline-none focus:ring-2 focus:ring-primary"
            />
          </div>

          {/* Options Grid */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Size */}
            <div>
              <label className="block text-sm font-medium mb-2">Size</label>
              <select
                value={size}
                onChange={(e) => setSize(e.target.value)}
                className="w-full px-3 py-2 border rounded-lg border-black/10 dark:border-white/10 bg-white dark:bg-black/50"
              >
                <option>1024x1024</option>
                <option>1792x1024</option>
                <option>1024x1792</option>
              </select>
            </div>

            {/* Quantity */}
            <div>
              <label className="block text-sm font-medium mb-2">Quantity</label>
              <select
                value={quantity}
                onChange={(e) => setQuantity(Number(e.target.value))}
                className="w-full px-3 py-2 border rounded-lg border-black/10 dark:border-white/10 bg-white dark:bg-black/50"
              >
                {[1, 2, 3, 4].map((n) => (
                  <option key={n}>{n}</option>
                ))}
              </select>
            </div>

            {/* Quality */}
            <div>
              <label className="block text-sm font-medium mb-2">Quality</label>
              <select
                value={quality}
                onChange={(e) => setQuality(e.target.value as 'standard' | 'hd')}
                className="w-full px-3 py-2 border rounded-lg border-black/10 dark:border-white/10 bg-white dark:bg-black/50"
              >
                <option value="standard">Standard</option>
                <option value="hd">HD</option>
              </select>
            </div>
          </div>

          {/* Error */}
          {error && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="p-3 rounded-lg bg-red-100/10 border border-red-500/50 text-red-600 dark:text-red-400 flex items-start gap-2"
            >
              <AlertCircle className="w-5 h-5 flex-shrink-0 mt-0.5" />
              <span>{error}</span>
            </motion.div>
          )}

          {/* Generate Button */}
          <motion.button
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={handleGenerate}
            disabled={isLoading || !prompt.trim()}
            className="w-full px-4 py-3 rounded-lg bg-primary text-white font-semibold flex items-center justify-center gap-2 disabled:opacity-50"
          >
            {isLoading ? (
              <>
                <Loader className="w-5 h-5 animate-spin" />
                Generating Images...
              </>
            ) : (
              <>
                <Wand2 className="w-5 h-5" />
                Generate Images
              </>
            )}
          </motion.button>
        </div>
      </motion.div>

      {/* Generated Images */}
      {images.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
        >
          <h2 className="text-lg font-semibold mb-4">Generated Images</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            {images.map((url, idx) => (
              <motion.div
                key={idx}
                whileHover={{ scale: 1.05 }}
                className="relative group"
              >
                <img
                  src={url}
                  alt={`Generated image ${idx + 1}`}
                  className="w-full rounded-lg object-cover"
                />
                <motion.a
                  initial={{ opacity: 0 }}
                  whileHover={{ opacity: 1 }}
                  href={url}
                  download
                  className="absolute inset-0 flex items-center justify-center bg-black/50 rounded-lg"
                >
                  <Download className="w-6 h-6 text-white" />
                </motion.a>
              </motion.div>
            ))}
          </div>
        </motion.div>
      )}

      {/* Empty State */}
      {!isLoading && images.length === 0 && !error && (
        <div className="text-center py-12">
          <Wand2 className="w-12 h-12 text-black/20 dark:text-white/20 mx-auto mb-4" />
          <p className="text-black/60 dark:text-white/60">
            Enter a description and click Generate to create images
          </p>
        </div>
      )}
    </motion.div>
  );
};

export default ImageGenerator;

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { X } from 'lucide-react';
import { OAuthButtons } from './OAuthButtons';

export interface LoginModalProps {
  isOpen: boolean;
  onClose: () => void;
  onLoginSuccess?: (token: string) => void;
}

export const LoginModal = ({ isOpen, onClose, onLoginSuccess }: LoginModalProps) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);

  const handleEmailSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      const endpoint = isSignUp ? '/api/auth/register' : '/api/auth/login';
      const response = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      if (!response.ok) {
        throw new Error('Authentication failed');
      }

      const data = await response.json();
      localStorage.setItem('accessToken', data.accessToken);
      localStorage.setItem('refreshToken', data.refreshToken);

      onLoginSuccess?.(data.accessToken);
      onClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
    } finally {
      setIsLoading(false);
    }
  };

  const handleOAuthClick = async (provider: 'google' | 'apple' | 'facebook') => {
    setIsLoading(true);

    try {
      // Initialize OAuth flow based on provider
      const clientId = process.env[`NEXT_PUBLIC_${provider.toUpperCase()}_CLIENT_ID`];
      const redirectUri = `${window.location.origin}/oauth-callback`;

      let authUrl = '';

      switch (provider) {
        case 'google':
          authUrl = `https://accounts.google.com/o/oauth2/v2/auth?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code&scope=openid%20email%20profile`;
          break;
        case 'apple':
          authUrl = `https://appleid.apple.com/auth/authorize?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code&scope=openid%20email&response_mode=form_post`;
          break;
        case 'facebook':
          authUrl = `https://www.facebook.com/v18.0/dialog/oauth?client_id=${clientId}&redirect_uri=${redirectUri}&scope=email,public_profile`;
          break;
      }

      window.location.href = authUrl;
    } catch (err) {
      setError('OAuth initialization failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-md">
          <motion.div
            initial={{ scale: 0.95, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0.95, opacity: 0 }}
            className="relative w-full max-w-md p-6 rounded-2xl bg-white dark:bg-black border border-black/10 dark:border-white/10"
          >
            {/* Close Button */}
            <button
              onClick={onClose}
              className="absolute top-4 right-4 p-2 transition-colors rounded-lg hover:bg-black/5 dark:hover:bg-white/5"
            >
              <X className="w-5 h-5" />
            </button>

            {/* Header */}
            <div className="mb-8">
              <h2 className="text-2xl font-bold mb-2">
                {isSignUp ? 'Create Account' : 'Welcome Back'}
              </h2>
              <p className="text-sm text-black/60 dark:text-white/60">
                {isSignUp
                  ? 'Sign up to get started with Belsuite'
                  : 'Sign in to your account to continue'}
              </p>
            </div>

            {/* Error Message */}
            {error && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className="p-3 mb-4 text-sm rounded-lg bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300"
              >
                {error}
              </motion.div>
            )}

            {/* Email/Password Form */}
            <form onSubmit={handleEmailSubmit} className="mb-6 space-y-4">
              <div>
                <label className="block text-sm font-medium mb-2">Email</label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="you@example.com"
                  className="w-full px-4 py-2 border rounded-lg border-black/10 dark:border-white/10 bg-white dark:bg-black/50 focus:outline-none focus:ring-2 focus:ring-primary"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-2">Password</label>
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                  className="w-full px-4 py-2 border rounded-lg border-black/10 dark:border-white/10 bg-white dark:bg-black/50 focus:outline-none focus:ring-2 focus:ring-primary"
                  required
                />
              </div>

              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                type="submit"
                disabled={isLoading}
                className="w-full px-4 py-2 font-semibold text-white transition-all rounded-lg bg-primary hover:brightness-110 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isLoading ? 'Authenticating...' : isSignUp ? 'Sign Up' : 'Sign In'}
              </motion.button>
            </form>

            {/* Divider */}
            <div className="flex items-center gap-3 mb-6">
              <div className="flex-1 h-px bg-black/10 dark:bg-white/10" />
              <span className="text-sm text-black/60 dark:text-white/60">or</span>
              <div className="flex-1 h-px bg-black/10 dark:bg-white/10" />
            </div>

            {/* OAuth Buttons */}
            <OAuthButtons
              isLoading={isLoading}
              onGoogleClick={() => handleOAuthClick('google')}
              onAppleClick={() => handleOAuthClick('apple')}
              onFacebookClick={() => handleOAuthClick('facebook')}
            />

            {/* Toggle Sign Up/Sign In */}
            <div className="mt-6 text-center text-sm">
              <span className="text-black/60 dark:text-white/60">
                {isSignUp ? 'Already have an account?' : "Don't have an account?"}
              </span>
              <button
                onClick={() => {
                  setIsSignUp(!isSignUp);
                  setError('');
                }}
                className="ml-2 font-medium text-primary hover:underline"
              >
                {isSignUp ? 'Sign In' : 'Sign Up'}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

