'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import {
  FlaskConical,
  Plus,
  Play,
  Loader2,
  X,
  Trophy,
  BarChart2,
  AlertCircle,
} from 'lucide-react';
import { useABTests } from '@/hooks/useMarketing';
import type { ABTest, ABTestAnalysis } from '@/hooks/useMarketing';

function SignificanceBadge({ significant }: { significant: boolean }) {
  return (
    <span
      className={`text-xs px-2 py-0.5 rounded-full font-medium ${
        significant
          ? 'bg-emerald-400/10 text-emerald-400'
          : 'bg-zinc-700/50 text-zinc-400'
      }`}
    >
      {significant ? 'Significant' : 'Not significant'}
    </span>
  );
}

function StatBar({ label, value, max }: { label: string; value: number; max: number }) {
  const pct = max > 0 ? Math.min(100, (value / max) * 100) : 0;
  return (
    <div>
      <div className="flex justify-between text-xs mb-1">
        <span className="text-zinc-500">{label}</span>
        <span className="text-white">{value}</span>
      </div>
      <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
        <div className="h-full bg-primary rounded-full" style={{ width: `${pct}%` }} />
      </div>
    </div>
  );
}

function AnalysisCard({ analysis }: { analysis: ABTestAnalysis }) {
  const { variants, winnerVariantId, recommendation, isSignificant, pValue } = analysis;
  const maxConversions = Math.max(...variants.map((v) => v.conversions));

  return (
    <div className="bg-white/[0.02] border border-white/5 rounded-xl p-4 space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <BarChart2 className="w-4 h-4 text-zinc-500" />
          <p className="text-sm font-medium text-white">Analysis</p>
        </div>
        <SignificanceBadge significant={isSignificant} />
      </div>

      <div className="grid grid-cols-2 gap-2 text-xs text-zinc-500">
        <div>p-value: <span className="text-white">{pValue?.toFixed(4) ?? 'N/A'}</span></div>
      </div>

      <div className="space-y-3">
        {variants.map((v) => (
          <div
            key={v.variantId}
            className={`p-3 rounded-lg border ${
              v.variantId === winnerVariantId
                ? 'border-emerald-400/30 bg-emerald-400/5'
                : 'border-white/5 bg-white/[0.02]'
            }`}
          >
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                {v.variantId === winnerVariantId && <Trophy className="w-3.5 h-3.5 text-emerald-400" />}
                <p className="text-xs font-medium text-white">{v.label}</p>
                {v.isControl && <span className="text-xs text-zinc-600">control</span>}
              </div>
              <div className="flex items-center gap-3 text-xs">
                <span className="text-zinc-500">
                  CVR <span className="text-white">{(v.cvr * 100).toFixed(2)}%</span>
                </span>
                {v.relativeUplift !== undefined && v.relativeUplift !== 0 && (
                  <span className={v.relativeUplift > 0 ? 'text-emerald-400' : 'text-red-400'}>
                    {v.relativeUplift > 0 ? '+' : ''}{(v.relativeUplift * 100).toFixed(1)}%
                  </span>
                )}
              </div>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <StatBar label="Impressions" value={v.impressions} max={Math.max(...variants.map((x) => x.impressions))} />
              <StatBar label="Conversions" value={v.conversions} max={maxConversions} />
            </div>
          </div>
        ))}
      </div>

      {recommendation && (
        <div className="flex gap-2 bg-sky-400/5 border border-sky-400/20 rounded-lg p-3">
          <AlertCircle className="w-4 h-4 text-sky-400 shrink-0 mt-0.5" />
          <p className="text-xs text-zinc-300">{recommendation}</p>
        </div>
      )}
    </div>
  );
}

export function ABTestView({ campaignId }: { campaignId: string }) {
  const { tests, loading, createTest, startTest, getAnalysis, deleteTest } = useABTests(campaignId);

  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({
    name: '',
    trafficSplit: 50,
    metric: 'CVR',
    variants: [
      { name: 'Control', headline: '', body: '', cta: '' },
      { name: 'Variant B', headline: '', body: '', cta: '' },
    ],
  });
  const [creating, setCreating] = useState(false);
  const [startingId, setStartingId] = useState<string | null>(null);
  const [analyses, setAnalyses] = useState<Record<string, ABTestAnalysis>>({});
  const [loadingAnalysis, setLoadingAnalysis] = useState<string | null>(null);

  function setVariant(i: number, key: string, value: string) {
    setForm((prev) => {
      const copy = [...prev.variants];
      copy[i] = { ...copy[i], [key]: value };
      return { ...prev, variants: copy };
    });
  }

  function addVariant() {
    setForm((prev) => ({
      ...prev,
      variants: [...prev.variants, { name: `Variant ${String.fromCharCode(65 + prev.variants.length)}`, headline: '', body: '', cta: '' }],
    }));
  }

  function removeVariant(i: number) {
    if (form.variants.length <= 2) return;
    setForm((prev) => ({ ...prev, variants: prev.variants.filter((_, idx) => idx !== i) }));
  }

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    setCreating(true);
    try {
      await createTest({
        name: form.name,
        trafficSplit: form.trafficSplit,
        metric: form.metric,
        variants: form.variants,
      });
      setShowCreate(false);
      setForm({
        name: '',
        trafficSplit: 50,
        metric: 'CVR',
        variants: [
          { name: 'Control', headline: '', body: '', cta: '' },
          { name: 'Variant B', headline: '', body: '', cta: '' },
        ],
      });
    } finally {
      setCreating(false);
    }
  }

  async function handleStart(id: string) {
    setStartingId(id);
    try {
      await startTest(id);
    } finally {
      setStartingId(null);
    }
  }

  async function handleAnalysis(id: string) {
    if (analyses[id]) return;
    setLoadingAnalysis(id);
    try {
      const data = await getAnalysis(id);
      setAnalyses((prev) => ({ ...prev, [id]: data }));
    } finally {
      setLoadingAnalysis(null);
    }
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <p className="text-sm text-zinc-500">
          {tests.length} test{tests.length !== 1 ? 's' : ''}
        </p>
        <button
          onClick={() => setShowCreate(true)}
          className="flex items-center gap-2 bg-primary text-white text-sm px-4 py-2 rounded-lg hover:opacity-90 transition-opacity"
        >
          <Plus className="w-4 h-4" />
          New A/B Test
        </button>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <Loader2 className="w-5 h-5 animate-spin text-zinc-500" />
        </div>
      ) : tests.length === 0 ? (
        <div className="bg-white/[0.03] border border-white/5 rounded-xl py-16 text-center">
          <FlaskConical className="w-8 h-8 text-zinc-600 mx-auto mb-3" />
          <p className="text-sm text-zinc-500">No A/B tests yet for this campaign.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {tests.map((test, i) => (
            <motion.div
              key={test.id}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.04 }}
              className="bg-white/[0.03] border border-white/5 rounded-xl overflow-hidden"
            >
              <div className="px-4 py-3 flex items-center gap-3">
                <FlaskConical className="w-4 h-4 text-violet-400 shrink-0" />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <p className="text-sm font-medium text-white">{test.name}</p>
                    <span
                      className={`text-xs px-2 py-0.5 rounded-full font-medium shrink-0 ${
                        test.status === 'RUNNING'
                          ? 'bg-emerald-400/10 text-emerald-400'
                          : test.status === 'CONCLUDED'
                          ? 'bg-blue-400/10 text-blue-400'
                          : 'bg-zinc-700/50 text-zinc-400'
                      }`}
                    >
                      {test.status}
                    </span>
                  </div>
                  <p className="text-xs text-zinc-500">
                    {test.variants?.length ?? 0} variants ┬À {test.trafficSplit}% traffic ┬À {test.metric}
                  </p>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {test.status === 'DRAFT' && (
                    <button
                      onClick={() => handleStart(test.id)}
                      disabled={startingId === test.id}
                      className="flex items-center gap-1.5 bg-emerald-600 hover:bg-emerald-500 text-white text-xs px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50"
                    >
                      {startingId === test.id ? (
                        <Loader2 className="w-3.5 h-3.5 animate-spin" />
                      ) : (
                        <Play className="w-3.5 h-3.5" />
                      )}
                      Start
                    </button>
                  )}
                  {(test.status === 'RUNNING' || test.status === 'CONCLUDED') && (
                    <button
                      onClick={() => handleAnalysis(test.id)}
                      disabled={loadingAnalysis === test.id}
                      className="flex items-center gap-1.5 bg-white/5 hover:bg-white/10 border border-white/10 text-white text-xs px-3 py-1.5 rounded-lg transition-colors disabled:opacity-50"
                    >
                      {loadingAnalysis === test.id ? (
                        <Loader2 className="w-3.5 h-3.5 animate-spin" />
                      ) : (
                        <BarChart2 className="w-3.5 h-3.5" />
                      )}
                      Analysis
                    </button>
                  )}
                </div>
              </div>

              {analyses[test.id] && (
                <div className="border-t border-white/5 p-4">
                  <AnalysisCard analysis={analyses[test.id]} />
                </div>
              )}
            </motion.div>
          ))}
        </div>
      )}

      {/* Create modal */}
      <AnimatePresence>
        {showCreate && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4"
            onClick={(e) => e.target === e.currentTarget && setShowCreate(false)}
          >
            <motion.form
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              onSubmit={handleCreate}
              className="bg-[#111] border border-white/10 rounded-2xl p-6 w-full max-w-xl space-y-5 max-h-[90vh] overflow-y-auto"
            >
              <div className="flex items-center justify-between">
                <h3 className="text-base font-semibold text-white">New A/B Test</h3>
                <button type="button" onClick={() => setShowCreate(false)} className="text-zinc-500 hover:text-white">
                  <X className="w-4 h-4" />
                </button>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div className="col-span-2">
                  <label className="text-xs text-zinc-500 mb-1 block">Test Name *</label>
                  <input
                    required
                    value={form.name}
                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                    placeholder="Headline comparison test"
                    className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white placeholder-zinc-600 focus:outline-none focus:border-white/20"
                  />
                </div>
                <div>
                  <label className="text-xs text-zinc-500 mb-1 block">Metric</label>
                  <select
                    value={form.metric}
                    onChange={(e) => setForm({ ...form, metric: e.target.value })}
                    className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-white/20"
                  >
                    {['CVR', 'CTR', 'ROAS', 'CPA'].map((m) => (
                      <option key={m} value={m} className="bg-[#111]">{m}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="text-xs text-zinc-500 mb-1 block">Traffic Split (%)</label>
                  <input
                    type="number"
                    min={1}
                    max={99}
                    value={form.trafficSplit}
                    onChange={(e) => setForm({ ...form, trafficSplit: parseInt(e.target.value) || 50 })}
                    className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-white/20"
                  />
                </div>
              </div>

              {/* Variants */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <p className="text-xs text-zinc-500">Variants</p>
                  <button
                    type="button"
                    onClick={addVariant}
                    className="text-xs text-zinc-400 hover:text-white flex items-center gap-1"
                  >
                    <Plus className="w-3 h-3" /> Add
                  </button>
                </div>
                {form.variants.map((v, i) => (
                  <div key={i} className="bg-white/5 rounded-xl p-3 space-y-2">
                    <div className="flex items-center justify-between">
                      <p className="text-xs font-medium text-zinc-300">{v.name}</p>
                      {i > 1 && (
                        <button type="button" onClick={() => removeVariant(i)} className="text-zinc-600 hover:text-red-400">
                          <X className="w-3.5 h-3.5" />
                        </button>
                      )}
                    </div>
                    {(['headline', 'body', 'cta'] as const).map((field) => (
                      <input
                        key={field}
                        value={v[field]}
                        onChange={(e) => setVariant(i, field, e.target.value)}
                        placeholder={field.charAt(0).toUpperCase() + field.slice(1)}
                        className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-white placeholder-zinc-600 focus:outline-none focus:border-white/20"
                      />
                    ))}
                  </div>
                ))}
              </div>

              <button
                type="submit"
                disabled={creating}
                className="w-full flex items-center justify-center gap-2 bg-primary text-white text-sm py-2.5 rounded-lg hover:opacity-90 transition-opacity disabled:opacity-50"
              >
                {creating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Plus className="w-4 h-4" />}
                {creating ? 'CreatingÔÇª' : 'Create Test'}
              </button>
            </motion.form>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { motion } from 'motion/react';
import {
  Zap,
  Loader2,
  DollarSign,
  TrendingUp,
  AlertTriangle,
  CheckCircle,
  ChevronRight,
} from 'lucide-react';
import { useBudgetOptimizer } from '@/hooks/useMarketing';
import type { BudgetOptimizationResult } from '@/hooks/useMarketing';

function fmtCurrency(n: number) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
}

function AllocationBar({ allocated, total }: { allocated: number; total: number }) {
  const pct = total > 0 ? Math.min(100, (allocated / total) * 100) : 0;
  return (
    <div className="h-1.5 bg-white/5 rounded-full overflow-hidden mt-1">
      <div className="h-full bg-primary rounded-full" style={{ width: `${pct}%` }} />
    </div>
  );
}

export function BudgetOptimizerPanel({ campaignId }: { campaignId: string }) {
  const { running, optimize, apply, error: optimizerError, result } = useBudgetOptimizer();
  const [budget, setBudget] = useState('');
  const [applying, setApplying] = useState(false);
  const [applied, setApplied] = useState(false);

  const totalAllocated = result
    ? result.allocations.reduce((sum, a) => sum + a.allocatedBudget, 0)
    : 0;

  async function handleOptimize(e: React.FormEvent) {
    e.preventDefault();
    setApplied(false);
    await optimize(campaignId, parseFloat(budget) || undefined);
  }

  async function handleApply() {
    if (!result) return;
    setApplying(true);
    try {
      await apply(campaignId, result);
      setApplied(true);
    } finally {
      setApplying(false);
    }
  }

  return (
    <div className="space-y-5">
      {/* Input */}
      <form onSubmit={handleOptimize} className="bg-white/[0.03] border border-white/5 rounded-xl p-5">
        <div className="flex items-center gap-2 mb-4">
          <Zap className="w-4 h-4 text-amber-400" />
          <h3 className="text-sm font-semibold text-white">AI Budget Optimizer</h3>
        </div>
        <div className="flex gap-3">
          <div className="relative flex-1">
            <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
            <input
              type="number"
              min="1"
              step="any"
              value={budget}
              onChange={(e) => setBudget(e.target.value)}
              placeholder="Total budget to allocate (optional)"
              className="w-full bg-white/5 border border-white/10 rounded-lg pl-9 pr-3 py-2.5 text-sm text-white placeholder-zinc-600 focus:outline-none focus:border-white/20"
            />
          </div>
          <button
            type="submit"
            disabled={running}
            className="flex items-center gap-2 bg-amber-600 hover:bg-amber-500 text-white text-sm px-4 py-2.5 rounded-lg transition-colors disabled:opacity-50 shrink-0"
          >
            {running ? (
              <><Loader2 className="w-4 h-4 animate-spin" /> AnalyzingÔÇª</>
            ) : (
              <><Zap className="w-4 h-4" /> Optimize</>
            )}
          </button>
        </div>
        {optimizerError && <p className="text-xs text-red-400 mt-2">{optimizerError}</p>}
      </form>

      {running && (
        <div className="bg-white/[0.03] border border-white/5 rounded-xl py-14 text-center space-y-3">
          <Loader2 className="w-6 h-6 animate-spin text-amber-400 mx-auto" />
          <p className="text-sm text-zinc-500">AI is analyzing your ad performanceÔÇª</p>
        </div>
      )}

      {result && !running && (
        <>
          {/* Projected metrics */}
          <div className="grid grid-cols-3 gap-3">
            {[
              { label: 'Projected ROAS', value: `${result.projectedROAS?.toFixed(2) ?? 'ÔÇö'}x`, color: 'text-emerald-400' },
              { label: 'Projected Revenue', value: result.projectedRevenue ? fmtCurrency(result.projectedRevenue) : 'ÔÇö', color: 'text-white' },
              { label: 'Projected Conversions', value: result.projectedConversions?.toFixed(0) ?? 'ÔÇö', color: 'text-white' },
            ].map(({ label, value, color }) => (
              <div key={label} className="bg-white/[0.03] border border-white/5 rounded-xl p-4 text-center">
                <p className="text-xs text-zinc-500 mb-1">{label}</p>
                <p className={`text-xl font-bold ${color}`}>{value}</p>
              </div>
            ))}
          </div>

          {/* Allocations */}
          <div className="bg-white/[0.03] border border-white/5 rounded-xl overflow-hidden">
            <div className="px-5 py-3 border-b border-white/5 flex items-center justify-between">
              <h3 className="text-sm font-semibold text-white">Budget Allocation</h3>
              <span className="text-xs text-zinc-500">Total: {fmtCurrency(totalAllocated)}</span>
            </div>
            <div className="divide-y divide-white/[0.03]">
              {result.allocations.map((a, i) => (
                <motion.div
                  key={a.adId}
                  initial={{ opacity: 0, x: -8 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.04 }}
                  className="px-5 py-4"
                >
                  <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2 min-w-0">
                      <ChevronRight className="w-3.5 h-3.5 text-zinc-600 shrink-0" />
                      <p className="text-sm text-white font-medium truncate">{a.adId ?? 'Ad'}</p>
                    </div>
                    <div className="flex items-center gap-3 text-sm shrink-0">
                      <span className="text-white font-semibold">{fmtCurrency(a.allocatedBudget)}</span>
                      <span className="text-zinc-500">ÔåÆ</span>
                      <span className="text-emerald-400">{a.expectedROAS.toFixed(2)}x</span>
                    </div>
                  </div>
                  <AllocationBar allocated={a.allocatedBudget} total={totalAllocated} />
                  {a.reasoning && (
                    <p className="text-xs text-zinc-500 mt-1.5">{a.reasoning}</p>
                  )}
                </motion.div>
              ))}
            </div>
          </div>

          {/* AI Insights */}
          {result.aiInsights && result.aiInsights.length > 0 && (
            <div className="bg-white/[0.03] border border-white/5 rounded-xl p-4">
              <div className="flex items-center gap-2 mb-3">
                <TrendingUp className="w-4 h-4 text-sky-400" />
                <h3 className="text-sm font-semibold text-white">AI Insights</h3>
              </div>
              <ul className="space-y-2">
                {result.aiInsights.map((insight, i) => (
                  <li key={i} className="flex items-start gap-2 text-xs text-zinc-400">
                    <CheckCircle className="w-3.5 h-3.5 text-sky-400 shrink-0 mt-0.5" />
                    {insight}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Warnings */}
          {result.warnings && result.warnings.length > 0 && (
            <div className="bg-amber-400/5 border border-amber-400/20 rounded-xl p-4">
              <div className="flex items-center gap-2 mb-3">
                <AlertTriangle className="w-4 h-4 text-amber-400" />
                <h3 className="text-sm font-semibold text-amber-400">Warnings</h3>
              </div>
              <ul className="space-y-1.5">
                {result.warnings.map((w, i) => (
                  <li key={i} className="text-xs text-zinc-400 flex gap-2">
                    <span className="text-amber-400 shrink-0">┬À</span>
                    {w}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Apply button */}
          <button
            onClick={handleApply}
            disabled={applying || applied}
            className={`w-full flex items-center justify-center gap-2 text-sm py-3 rounded-xl font-medium transition-all disabled:opacity-60 ${
              applied
                ? 'bg-emerald-600/20 text-emerald-400 border border-emerald-400/20'
                : 'bg-primary text-white hover:opacity-90'
            }`}
          >
            {applying ? (
              <><Loader2 className="w-4 h-4 animate-spin" /> ApplyingÔÇª</>
            ) : applied ? (
              <><CheckCircle className="w-4 h-4" /> Optimization Applied</>
            ) : (
              <><Zap className="w-4 h-4" /> Apply Optimization</>
            )}
          </button>
        </>
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import {
  Plus,
  Play,
  Pause,
  Trash2,
  ChevronRight,
  DollarSign,
  Target,
  Calendar,
  Loader2,
  X,
} from 'lucide-react';
import { useCampaigns } from '@/hooks/useMarketing';
import type { Campaign } from '@/hooks/useMarketing';

const OBJECTIVES = [
  'AWARENESS',
  'TRAFFIC',
  'LEADS',
  'SALES',
  'ENGAGEMENT',
  'APP_INSTALLS',
  'VIDEO_VIEWS',
  'CONVERSIONS',
] as const;

const STATUS_STYLES: Record<string, string> = {
  ACTIVE: 'bg-emerald-400/10 text-emerald-400',
  PAUSED: 'bg-amber-400/10 text-amber-400',
  DRAFT: 'bg-zinc-700/50 text-zinc-400',
  COMPLETED: 'bg-blue-400/10 text-blue-400',
  CANCELLED: 'bg-red-400/10 text-red-400',
};

export function CampaignsView() {
  const { campaigns, loading, createCampaign, setStatus, deleteCampaign } = useCampaigns();
  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({
    name: '',
    objective: 'CONVERSIONS' as string,
    totalBudget: '',
    dailyBudget: '',
    description: '',
  });
  const [creating, setCreating] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [statusLoadingId, setStatusLoadingId] = useState<string | null>(null);

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    setCreating(true);
    try {
      await createCampaign({
        name: form.name,
        objective: form.objective as any,
        totalBudget: form.totalBudget ? parseFloat(form.totalBudget) : undefined,
        dailyBudget: form.dailyBudget ? parseFloat(form.dailyBudget) : undefined,
      });
      setShowCreate(false);
      setForm({ name: '', objective: 'CONVERSIONS', totalBudget: '', dailyBudget: '', description: '' });
    } finally {
      setCreating(false);
    }
  }

  async function handleToggleStatus(campaign: Campaign) {
    setStatusLoadingId(campaign.id);
    try {
      const nextStatus = campaign.status === 'ACTIVE' ? 'PAUSED' : 'ACTIVE';
      await setStatus(campaign.id, nextStatus);
    } finally {
      setStatusLoadingId(null);
    }
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this campaign? This action cannot be undone.')) return;
    setDeletingId(id);
    try {
      await deleteCampaign(id);
    } finally {
      setDeletingId(null);
    }
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <p className="text-sm text-zinc-500">
          {campaigns.length} campaign{campaigns.length !== 1 ? 's' : ''}
        </p>
        <button
          onClick={() => setShowCreate(true)}
          className="flex items-center gap-2 bg-primary text-white text-sm px-4 py-2 rounded-lg hover:opacity-90 transition-opacity"
        >
          <Plus className="w-4 h-4" />
          New Campaign
        </button>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <Loader2 className="w-5 h-5 animate-spin text-zinc-500" />
        </div>
      ) : campaigns.length === 0 ? (
        <div className="bg-white/[0.03] border border-white/5 rounded-xl py-16 text-center">
          <Target className="w-8 h-8 text-zinc-600 mx-auto mb-3" />
          <p className="text-sm text-zinc-500">No campaigns yet. Create your first one.</p>
        </div>
      ) : (
        <div className="grid gap-3">
          {campaigns.map((c, i) => (
            <motion.div
              key={c.id}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.03 }}
              className="bg-white/[0.03] border border-white/5 rounded-xl p-4 flex items-center gap-4"
            >
              {/* Status indicator */}
              <div
                className={`w-2 h-2 rounded-full shrink-0 ${
                  c.status === 'ACTIVE' ? 'bg-emerald-400' : 'bg-zinc-600'
                }`}
              />

              {/* Name + meta */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <p className="text-sm font-medium text-white truncate">{c.name}</p>
                  <span
                    className={`text-xs px-2 py-0.5 rounded-full font-medium shrink-0 ${
                      STATUS_STYLES[c.status] ?? 'bg-zinc-700/50 text-zinc-400'
                    }`}
                  >
                    {c.status}
                  </span>
                </div>
                <div className="flex items-center gap-4 text-xs text-zinc-500">
                  <span className="flex items-center gap-1">
                    <Target className="w-3 h-3" />
                    {c.objective.replace(/_/g, ' ')}
                  </span>
                  {c.totalBudget && (
                    <span className="flex items-center gap-1">
                      <DollarSign className="w-3 h-3" />
                      {new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(c.totalBudget)}
                    </span>
                  )}
                  {c.startDate && (
                    <span className="flex items-center gap-1">
                      <Calendar className="w-3 h-3" />
                      {new Date(c.startDate).toLocaleDateString()}
                    </span>
                  )}
                </div>

                {/* Budget bar */}
                {c.totalBudget && c.spentBudget != null && (
                  <div className="mt-2">
                    <div className="flex justify-between text-xs text-zinc-600 mb-1">
                      <span>
                        ${c.spentBudget.toFixed(0)} spent
                      </span>
                      <span>{Math.round((c.spentBudget / c.totalBudget) * 100)}%</span>
                    </div>
                    <div className="h-1 bg-white/5 rounded-full overflow-hidden">
                      <div
                        className="h-full bg-primary rounded-full"
                        style={{
                          width: `${Math.min(100, (c.spentBudget / c.totalBudget) * 100)}%`,
                        }}
                      />
                    </div>
                  </div>
                )}
              </div>

              {/* Ads count */}
              {c._count?.ads != null && (
                <div className="text-center shrink-0">
                  <p className="text-lg font-bold text-white">{c._count.ads}</p>
                  <p className="text-xs text-zinc-500">ads</p>
                </div>
              )}

              {/* Actions */}
              <div className="flex items-center gap-1 shrink-0">
                <button
                  onClick={() => handleToggleStatus(c)}
                  disabled={statusLoadingId === c.id}
                  className="p-2 rounded-lg hover:bg-white/5 text-zinc-400 hover:text-white transition-colors disabled:opacity-50"
                  title={c.status === 'ACTIVE' ? 'Pause' : 'Activate'}
                >
                  {statusLoadingId === c.id ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : c.status === 'ACTIVE' ? (
                    <Pause className="w-4 h-4" />
                  ) : (
                    <Play className="w-4 h-4" />
                  )}
                </button>
                <button
                  onClick={() => handleDelete(c.id)}
                  disabled={deletingId === c.id}
                  className="p-2 rounded-lg hover:bg-red-400/10 text-zinc-400 hover:text-red-400 transition-colors disabled:opacity-50"
                >
                  {deletingId === c.id ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    <Trash2 className="w-4 h-4" />
                  )}
                </button>
              </div>
            </motion.div>
          ))}
        </div>
      )}

      {/* Create modal */}
      <AnimatePresence>
        {showCreate && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4"
            onClick={(e) => e.target === e.currentTarget && setShowCreate(false)}
          >
            <motion.form
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              onSubmit={handleCreate}
              className="bg-[#111] border border-white/10 rounded-2xl p-6 w-full max-w-md space-y-4"
            >
              <div className="flex items-center justify-between">
                <h3 className="text-base font-semibold text-white">New Campaign</h3>
                <button
                  type="button"
                  onClick={() => setShowCreate(false)}
                  className="text-zinc-500 hover:text-white"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>

              <div>
                <label className="text-xs text-zinc-500 mb-1 block">Campaign Name *</label>
                <input
                  required
                  value={form.name}
                  onChange={(e) => setForm({ ...form, name: e.target.value })}
                  placeholder="Summer Sale 2025"
                  className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white placeholder-zinc-600 focus:outline-none focus:border-white/20"
                />
              </div>

              <div>
                <label className="text-xs text-zinc-500 mb-1 block">Objective</label>
                <select
                  value={form.objective}
                  onChange={(e) => setForm({ ...form, objective: e.target.value })}
                  className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-white/20"
                >
                  {OBJECTIVES.map((o) => (
                    <option key={o} value={o} className="bg-[#111]">
                      {o.replace(/_/g, ' ')}
                    </option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs text-zinc-500 mb-1 block">Total Budget ($)</label>
                  <input
                    type="number"
                    min="0"
                    step="0.01"
                    value={form.totalBudget}
