function AccountCard({
  account,
  onDisconnect,
  onManageRecipients,
}: {
  account: SocialAccount;
  onDisconnect: () => Promise<void>;
  onManageRecipients?: () => void;
}) {
  const [deleting, setDeleting] = useState(false);

  const isExpired = account.tokenExpiresAt && new Date(account.tokenExpiresAt) < new Date();

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      className="glass rounded-2xl border border-white/5 p-5 flex items-center gap-4"
    >
      {/* Avatar */}
      <div className="relative">
        {account.avatar ? (
          <img src={account.avatar} alt={account.displayName} className="w-12 h-12 rounded-full object-cover" />
        ) : (
          <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center text-xl">
            {PLATFORM_ICONS[account.platform]}
          </div>
        )}
        <div className="absolute -bottom-1 -right-1">
          <span className="text-sm">{PLATFORM_ICONS[account.platform]}</span>
        </div>
      </div>

      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2">
          <p className="font-semibold text-white truncate">{account.displayName || account.platformUsername}</p>
          {account.isActive && !isExpired ? (
            <CheckCircle2 className="w-3.5 h-3.5 text-emerald-400 shrink-0" />
          ) : (
            <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          )}
        </div>
        <div className="flex items-center gap-2 mt-0.5">
          <PlatformBadge platform={account.platform} size="xs" />
          {account.pageName && (
            <span className="text-[10px] text-zinc-500">{account.pageName}</span>
          )}
          {isExpired && (
            <span className="text-[10px] text-red-400">Token expired</span>
          )}
        </div>
        {account._count && (
          <p className="text-[10px] text-zinc-600 mt-1">{account._count.posts} posts</p>
        )}
      </div>

      <div className="flex items-center gap-1">
        {account.platform === 'WHATSAPP' && onManageRecipients && (
          <button
            onClick={onManageRecipients}
            className="p-2 rounded-lg text-zinc-500 hover:text-emerald-400 hover:bg-emerald-400/10 transition-colors"
            title="Manage recipients"
          >
            <Users className="w-4 h-4" />
          </button>
        )}
        <button
          onClick={async () => {
            setDeleting(true);
            try { await onDisconnect(); } finally { setDeleting(false); }
          }}
          disabled={deleting}
          className="p-2 rounded-lg text-zinc-600 hover:text-red-400 hover:bg-red-400/10 transition-colors disabled:opacity-40"
        >
          {deleting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
        </button>
      </div>
    </motion.div>
  );
}

export function AccountsPanel({
  accounts,
  loading,
  onRefresh,
}: {
  accounts: SocialAccount[];
  loading: boolean;
  onRefresh: () => void;
}) {
  const [showConnect, setShowConnect] = useState(false);
  const [whatsAppAccount, setWhatsAppAccount] = useState<SocialAccount | null>(null);
  const { disconnect, getOAuthUrl } = useSocialAccounts();

  const handleConnect = async (platform: SocialPlatform) => {
    setShowConnect(false);
    const redirectUri = `${window.location.origin}/api/social/oauth/callback/${platform}`;
    const url = await getOAuthUrl(platform, redirectUri);
    window.location.href = url;
  };

  const connectedPlatforms = new Set(accounts.map((a) => a.platform));

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h2 className="text-xl font-bold text-white">Connected Accounts</h2>
          <p className="text-sm text-zinc-400 mt-0.5">{accounts.length} of {ALL_PLATFORMS.length} platforms connected</p>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={onRefresh}
            className="p-2 rounded-lg border border-white/10 text-zinc-500 hover:text-white hover:bg-white/5 transition-colors"
          >
            <RefreshCw className="w-4 h-4" />
          </button>
          <button
            onClick={() => setShowConnect(true)}
            className="flex items-center gap-2 px-4 py-2 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold transition-colors"
          >
            <Plus className="w-4 h-4" /> Connect Account
          </button>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center h-32">
          <Loader2 className="w-6 h-6 text-primary animate-spin" />
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          <AnimatePresence>
            {accounts.map((a) => (
              <AccountCard
                key={a.id}
                account={a}
                onDisconnect={() => disconnect(a.id)}
                onManageRecipients={a.platform === 'WHATSAPP' ? () => setWhatsAppAccount(a) : undefined}
              />
            ))}
          </AnimatePresence>

          {/* Unconnected platform placeholders */}
          {ALL_PLATFORMS.filter((p) => !connectedPlatforms.has(p)).map((p) => (
            <button
              key={p}
              onClick={() => setShowConnect(true)}
              className="glass rounded-2xl border border-dashed border-white/10 p-5 flex items-center gap-4 hover:border-primary/30 hover:bg-primary/3 transition-colors text-left"
            >
              <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center text-xl">
                {PLATFORM_ICONS[p]}
              </div>
              <div>
                <p className="text-sm text-zinc-400 font-medium">
                  {p === 'TWITTER' ? 'X / Twitter' : p.charAt(0) + p.slice(1).toLowerCase()}
                </p>
                <p className="text-xs text-zinc-600">Click to connect</p>
              </div>
            </button>
          ))}
        </div>
      )}

      <AnimatePresence>
        {showConnect && (
          <ConnectModal onClose={() => setShowConnect(false)} onConnect={handleConnect} />
        )}
      </AnimatePresence>

      {whatsAppAccount && (
        <WhatsAppRecipientsModal
          account={whatsAppAccount}
          onClose={() => setWhatsAppAccount(null)}
        />
      )}
    </div>
  );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import {
  Plus, Trash2, Loader2, AlertCircle, CheckCircle2, Clock,
  ChevronDown, ChevronUp, X, Zap,
} from 'lucide-react';
import type { SocialAccount, BulkCreateInput, CreatePostInput, SocialPlatform } from '@/hooks/useSocial';
import { useBulk } from '@/hooks/useSocial';
import { PLATFORM_ICONS } from './PlatformBadge';

const STATUS_COLORS: Record<string, string> = {
  PENDING:    'text-zinc-400 bg-zinc-400/10',
  PROCESSING: 'text-amber-400 bg-amber-400/10',
  COMPLETED:  'text-emerald-400 bg-emerald-400/10',
  PARTIAL:    'text-orange-400 bg-orange-400/10',
  FAILED:     'text-red-400 bg-red-400/10',
};

interface DraftPost {
  content: string;
  accountIds: string[];
  scheduledAt: string;
  hashtags: string;
}

const EMPTY_DRAFT: DraftPost = { content: '', accountIds: [], scheduledAt: '', hashtags: '' };

function BulkCreateModal({
  accounts,
  onClose,
  onCreate,
  creating,
}: {
  accounts: SocialAccount[];
  onClose: () => void;
  onCreate: (input: BulkCreateInput) => Promise<void>;
  creating: boolean;
}) {
  const [name, setName]     = useState('');
  const [posts, setPosts]   = useState<DraftPost[]>([{ ...EMPTY_DRAFT }]);
  const [error, setError]   = useState('');

  const addRow = () => setPosts((p) => [...p, { ...EMPTY_DRAFT }]);
  const removeRow = (i: number) => setPosts((p) => p.filter((_, idx) => idx !== i));
  const updateRow = (i: number, patch: Partial<DraftPost>) =>
    setPosts((p) => p.map((r, idx) => (idx === i ? { ...r, ...patch } : r)));

  const toggleAccount = (i: number, accId: string) => {
    updateRow(i, {
      accountIds: posts[i].accountIds.includes(accId)
        ? posts[i].accountIds.filter((id) => id !== accId)
        : [...posts[i].accountIds, accId],
    });
  };

  const handleSubmit = async () => {
    if (!name.trim()) { setError('Batch name is required'); return; }
    const invalid = posts.findIndex((p) => !p.content.trim() || p.accountIds.length === 0);
    if (invalid !== -1) { setError(`Post ${invalid + 1}: content and at least one account required`); return; }

    const input: BulkCreateInput = {
      name: name.trim(),
      posts: posts.map((p) => ({
        content: p.content.trim(),
        accountIds: p.accountIds,
        hashtags: p.hashtags.split(/\s+/).filter(Boolean).map((h) => h.replace(/^#/, '')),
        scheduledAt: p.scheduledAt || undefined,
      } as CreatePostInput)),
    };

    await onCreate(input);
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/70 backdrop-blur-sm p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ opacity: 0, y: 32 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: 32 }}
        className="w-full max-w-3xl glass rounded-2xl border border-white/10 shadow-2xl flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 shrink-0">
          <div>
            <h2 className="text-base font-bold text-white">Bulk Create Posts</h2>
            <p className="text-xs text-zinc-400">Create up to 100 posts at once</p>
          </div>
          <button onClick={onClose} className="p-1.5 rounded-lg text-zinc-500 hover:text-white hover:bg-white/10 transition-colors">
            <X className="w-4 h-4" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4">
          <div>
            <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-1.5 block">Batch Name</label>
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g. March Campaign"
              className="w-full px-3.5 py-2.5 rounded-xl bg-white/5 border border-white/10 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary/40 transition-colors"
            />
          </div>

          {/* Post rows */}
          <div className="space-y-3">
            {posts.map((post, i) => (
              <div key={i} className="glass rounded-xl border border-white/5 p-4 space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-xs font-semibold text-zinc-500">Post {i + 1}</span>
                  {posts.length > 1 && (
                    <button onClick={() => removeRow(i)} className="p-1 text-zinc-600 hover:text-red-400 transition-colors">
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  )}
                </div>

                <textarea
                  value={post.content}
                  onChange={(e) => updateRow(i, { content: e.target.value })}
                  rows={3}
                  placeholder="Post contentÔÇª"
                  className="w-full px-3 py-2 rounded-xl bg-white/5 border border-white/10 text-sm text-white placeholder:text-zinc-600 resize-none focus:outline-none focus:border-primary/40 transition-colors"
                />

                <div className="flex items-center gap-3 flex-wrap">
                  {/* Account buttons */}
                  <div className="flex flex-wrap gap-1.5">
                    {accounts.map((a) => (
                      <button
                        key={a.id}
                        onClick={() => toggleAccount(i, a.id)}
                        className={`flex items-center gap-1 px-2 py-1 rounded-lg border text-[10px] font-medium transition-colors ${
                          post.accountIds.includes(a.id)
                            ? 'border-primary/60 bg-primary/10 text-primary'
                            : 'border-white/10 text-zinc-500 hover:text-zinc-300'
                        }`}
                      >
                        <span>{PLATFORM_ICONS[a.platform]}</span>
                        {a.displayName?.slice(0, 10)}
                      </button>
                    ))}
                  </div>

                  <input
                    type="datetime-local"
                    value={post.scheduledAt}
                    onChange={(e) => updateRow(i, { scheduledAt: e.target.value })}
                    className="px-2.5 py-1.5 rounded-lg bg-white/5 border border-white/10 text-xs text-white focus:outline-none focus:border-primary/40 transition-colors"
                  />
                </div>
              </div>
            ))}
          </div>

          <button
            onClick={addRow}
            className="w-full flex items-center justify-center gap-2 py-2.5 rounded-xl border border-dashed border-white/10 text-sm text-zinc-500 hover:text-zinc-300 hover:border-white/20 transition-colors"
          >
            <Plus className="w-4 h-4" /> Add Post
          </button>

          {error && (
            <div className="flex items-center gap-2 p-3 rounded-xl bg-red-500/10 border border-red-500/20">
              <AlertCircle className="w-4 h-4 text-red-400 shrink-0" />
              <p className="text-sm text-red-300">{error}</p>
            </div>
          )}
        </div>

        <div className="px-6 pb-6 pt-2 flex gap-3 border-t border-white/5 shrink-0">
          <button onClick={onClose} className="flex-1 py-2.5 rounded-xl border border-white/10 text-sm text-zinc-400 hover:text-white transition-colors">
            Cancel
          </button>
          <button
            disabled={creating || !name.trim()}
            onClick={handleSubmit}
            className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold disabled:opacity-40 transition-colors"
          >
            {creating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}
            Create {posts.length} Post{posts.length !== 1 ? 's' : ''}
          </button>
        </div>
      </motion.div>
    </motion.div>
  );
}

export function BulkView({ accounts }: { accounts: SocialAccount[] }) {
  const { batches, loading, error, refresh, createBulk } = useBulk();
  const [showCreate, setShowCreate] = useState(false);
  const [creating, setCreating]     = useState(false);
  const [createError, setCreateError] = useState('');

  const handleCreate = async (input: BulkCreateInput) => {
    setCreating(true);
    setCreateError('');
    try {
      await createBulk(input);
      setShowCreate(false);
    } catch (e) {
      setCreateError((e as Error).message);
    } finally {
      setCreating(false);
    }
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h2 className="text-xl font-bold text-white">Bulk Batches</h2>
          <p className="text-sm text-zinc-400 mt-0.5">Create and track bulk post campaigns</p>
        </div>
        <button
          onClick={() => setShowCreate(true)}
          className="flex items-center gap-2 px-4 py-2 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold transition-colors"
        >
          <Plus className="w-4 h-4" /> New Batch
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center h-32 items-center">
          <Loader2 className="w-6 h-6 text-primary animate-spin" />
        </div>
      ) : error ? (
        <p className="text-zinc-400 text-sm">{error}</p>
      ) : batches.length === 0 ? (
        <div className="flex flex-col items-center gap-3 h-40 justify-center text-center">
          <Zap className="w-8 h-8 text-zinc-700" />
          <p className="text-zinc-400 text-sm">No bulk batches yet</p>
          <button onClick={() => setShowCreate(true)} className="text-sm text-primary hover:underline">Create your first batch</button>
        </div>
      ) : (
        <div className="space-y-3">
          {batches.map((batch) => (
            <motion.div
              key={batch.id}
              initial={{ opacity: 0, y: 6 }}
              animate={{ opacity: 1, y: 0 }}
              className="glass rounded-2xl border border-white/5 p-5"
            >
              <div className="flex items-center justify-between mb-3">
                <div>
                  <p className="font-semibold text-white">{batch.name}</p>
                  <p className="text-xs text-zinc-500 mt-0.5">
                    {new Date(batch.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                  </p>
                </div>
                <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${STATUS_COLORS[batch.status] ?? 'text-zinc-400 bg-zinc-400/10'}`}>
                  {batch.status}
                </span>
              </div>

              <div className="grid grid-cols-4 gap-3">
                {[
                  { label: 'Total',     value: batch.totalPosts,     color: 'text-white' },
                  { label: 'Scheduled', value: batch.scheduledPosts, color: 'text-amber-400' },
                  { label: 'Published', value: batch.publishedPosts, color: 'text-emerald-400' },
                  { label: 'Failed',    value: batch.failedPosts,    color: 'text-red-400' },
                ].map(({ label, value, color }) => (
                  <div key={label} className="bg-white/3 rounded-xl p-3 text-center">
                    <p className={`text-xl font-bold ${color}`}>{value}</p>
                    <p className="text-[10px] text-zinc-600 mt-0.5">{label}</p>
                  </div>
                ))}
              </div>
            </motion.div>
          ))}
        </div>
      )}

      <AnimatePresence>
        {showCreate && (
          <BulkCreateModal
            accounts={accounts}
            onClose={() => { setShowCreate(false); setCreateError(''); }}
            onCreate={handleCreate}
            creating={creating}
          />
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState, useMemo } from 'react';
import { motion } from 'motion/react';
import { ChevronLeft, ChevronRight, Loader2, AlertCircle } from 'lucide-react';
import { useCalendar, type CalendarDay } from '@/hooks/useSocial';
import { PostStatusBadge } from './PostStatusBadge';
import { PlatformDot } from './PlatformBadge';

const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTHS = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December',
];

function getMonthDays(year: number, month: number) {
  const first = new Date(year, month, 1).getDay(); // 0-6
  const total = new Date(year, month + 1, 0).getDate();
  return { first, total };
}

export function CalendarView() {
  const today = new Date();
  const [year, setYear]   = useState(today.getFullYear());
  const [month, setMonth] = useState(today.getMonth());
  const [selectedDay, setSelectedDay] = useState<string | null>(null);

  const from = useMemo(() => new Date(year, month, 1), [year, month]);
  const to   = useMemo(() => new Date(year, month + 1, 0, 23, 59, 59), [year, month]);

  const { days, loading, error } = useCalendar(from, to);

  const dayMap = useMemo(() => {
    const m: Record<string, CalendarDay> = {};
    for (const d of days) m[d.date] = d;
    return m;
  }, [days]);

  const { first, total } = getMonthDays(year, month);

  const prevMonth = () => {
    if (month === 0) { setMonth(11); setYear(y => y - 1); }
    else setMonth(m => m - 1);
  };

  const nextMonth = () => {
    if (month === 11) { setMonth(0); setYear(y => y + 1); }
    else setMonth(m => m + 1);
  };

  const selectedDayData = selectedDay ? dayMap[selectedDay] : null;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      {/* Calendar grid */}
      <div className="lg:col-span-2">
        {/* Month nav */}
        <div className="flex items-center justify-between mb-5">
          <button onClick={prevMonth} className="p-2 rounded-lg border border-white/10 text-zinc-400 hover:text-white hover:bg-white/5 transition-colors">
            <ChevronLeft className="w-4 h-4" />
          </button>
          <h2 className="text-lg font-bold text-white">{MONTHS[month]} {year}</h2>
          <button onClick={nextMonth} className="p-2 rounded-lg border border-white/10 text-zinc-400 hover:text-white hover:bg-white/5 transition-colors">
            <ChevronRight className="w-4 h-4" />
          </button>
        </div>

        {/* Day-of-week headers */}
        <div className="grid grid-cols-7 mb-2">
          {DAYS.map((d) => (
            <div key={d} className="text-center text-[10px] font-semibold text-zinc-600 uppercase py-2">{d}</div>
          ))}
        </div>

        {loading ? (
          <div className="flex justify-center items-center h-64">
            <Loader2 className="w-6 h-6 text-primary animate-spin" />
          </div>
        ) : (
          <div className="grid grid-cols-7 gap-1">
            {/* Empty cells before first day */}
            {Array.from({ length: first }).map((_, i) => <div key={`e${i}`} />)}

            {/* Day cells */}
            {Array.from({ length: total }).map((_, i) => {
              const day = i + 1;
              const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              const data    = dayMap[dateStr];
              const isToday = dateStr === today.toISOString().slice(0, 10);
              const isSelected = selectedDay === dateStr;
              const hasPosts = data && data.posts.length > 0;

              return (
                <button
                  key={day}
                  onClick={() => setSelectedDay(isSelected ? null : dateStr)}
                  className={`relative aspect-square rounded-xl flex flex-col items-center justify-start p-1.5 transition-colors text-left ${
                    isSelected
                      ? 'bg-primary/20 border border-primary/40'
                      : isToday
                      ? 'bg-white/10 border border-white/20'
                      : hasPosts
                      ? 'bg-white/3 border border-white/5 hover:bg-white/8'
                      : 'hover:bg-white/5 border border-transparent'
                  }`}
                >
                  <span className={`text-xs font-semibold ${isToday ? 'text-primary' : 'text-zinc-400'}`}>
                    {day}
                  </span>

                  {hasPosts && (
                    <div className="flex flex-wrap gap-0.5 mt-1 justify-center">
                      {data.posts.slice(0, 3).flatMap((p) =>
                        p.platforms.slice(0, 2).map((pl, j) => (
                          <PlatformDot key={`${p.id}-${j}`} platform={pl} />
                        )),
                      ).slice(0, 4)}
                    </div>
                  )}

                  {hasPosts && data.posts.length > 1 && (
                    <span className="text-[9px] text-zinc-500 mt-0.5">{data.posts.length}</span>
                  )}
                </button>
              );
            })}
          </div>
        )}
      </div>

      {/* Side panel */}
      <div>
        {selectedDayData ? (
          <div>
            <h3 className="text-base font-bold text-white mb-4">
              {new Date(selectedDayData.date + 'T12:00:00').toLocaleDateString('en-US', {
                weekday: 'long', month: 'long', day: 'numeric',
              })}
            </h3>
            <div className="space-y-3">
              {selectedDayData.posts.map((post) => (
                <motion.div
                  key={post.id}
                  initial={{ opacity: 0, x: 8 }}
                  animate={{ opacity: 1, x: 0 }}
                  className="glass rounded-xl border border-white/5 p-4"
                >
                  <p className="text-sm text-zinc-300 line-clamp-2 mb-2">{post.content}</p>
                  <div className="flex items-center justify-between">
                    <PostStatusBadge status={post.status} />
                    <div className="flex gap-1">
                      {post.platforms.map((p, i) => <PlatformDot key={i} platform={p} />)}
                    </div>
                  </div>
                  {post.scheduledAt && (
                    <p className="text-[10px] text-zinc-500 mt-2">
                      {new Date(post.scheduledAt).toLocaleTimeString('en-US', {
                        hour: 'numeric', minute: '2-digit',
                      })}
                    </p>
                  )}
                </motion.div>
              ))}
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-48 text-center">
            <p className="text-zinc-500 text-sm">Click a day to see scheduled posts</p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { motion } from 'motion/react';
import {
  X, Sparkles, Clock, RotateCcw, Loader2, Plus, Hash, Link as LinkIcon,
  AlertCircle,
} from 'lucide-react';
import type { SocialAccount, SocialPlatform, CreatePostInput } from '@/hooks/useSocial';
import { useSocialPosts, useOptimalTimes, useAutoCreator } from '@/hooks/useSocial';
import { PlatformBadge, PLATFORM_ICONS } from './PlatformBadge';

const CHAR_LIMITS: Record<SocialPlatform, number> = {
  TWITTER: 280,
  INSTAGRAM: 2200,
  FACEBOOK: 63206,
  TIKTOK: 2200,
  LINKEDIN: 3000,
  PINTEREST: 800,
  WHATSAPP: 4096,
};

function AccountSelector({
  accounts,
  selected,
  onToggle,
}: {
  accounts: SocialAccount[];
  selected: Set<string>;
  onToggle: (id: string) => void;
}) {
  if (accounts.length === 0) {
    return (
      <div className="flex items-center gap-2 p-3 rounded-xl bg-amber-500/5 border border-amber-500/20">
        <AlertCircle className="w-4 h-4 text-amber-400 shrink-0" />
        <p className="text-xs text-amber-300">No connected accounts. Go to the Accounts tab to connect.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-wrap gap-2">
      {accounts.map((a) => (
        <button
          key={a.id}
          onClick={() => onToggle(a.id)}
          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full border text-xs font-medium transition-colors ${
            selected.has(a.id)
              ? 'border-primary bg-primary/10 text-primary'
              : 'border-white/10 text-zinc-400 hover:border-white/20 hover:text-zinc-200'
          }`}
        >
          <span>{PLATFORM_ICONS[a.platform]}</span>
          {a.displayName || a.platformUsername}
        </button>
      ))}
    </div>
  );
}

export function CreatePostModal({
  accounts,
  onClose,
  onCreated,
  initialContent = '',
}: {
  accounts: SocialAccount[];
  onClose: () => void;
  onCreated: () => void;
  initialContent?: string;
}) {
  const { createPost } = useSocialPosts();
  const { generating, generateCaption } = useAutoCreator();

  const [content, setContent]           = useState(initialContent);
  const [hashtags, setHashtags]         = useState('');
  const [link, setLink]                 = useState('');
  const [selectedAccounts, setSelected] = useState<Set<string>>(new Set());
  const [scheduledAt, setScheduledAt]   = useState('');
  const [useOptimal, setUseOptimal]     = useState(false);
  const [autoRepost, setAutoRepost]     = useState(false);
  const [repostDays, setRepostDays]     = useState(7);
  const [maxReposts, setMaxReposts]     = useState(3);
  const [saving, setSaving]             = useState(false);
  const [error, setError]               = useState('');
  const [aiPrompt, setAiPrompt]         = useState('');
  const [showAI, setShowAI]             = useState(false);

  // Determine primary platform for char limit
  const primaryPlatform = accounts.find((a) => selectedAccounts.has(a.id))?.platform ?? 'INSTAGRAM';
  const limit = CHAR_LIMITS[primaryPlatform];
  const charCount = content.length;
  const overLimit = charCount > limit;

  const { slots } = useOptimalTimes(
    useOptimal && selectedAccounts.size > 0
      ? (accounts.find((a) => selectedAccounts.has(a.id))?.platform ?? null)
      : null,
  );

  const toggleAccount = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const handleAIGenerate = async () => {
    if (!aiPrompt.trim()) return;
    try {
      const result = await generateCaption(aiPrompt, primaryPlatform);
      setContent(result.caption);
      setHashtags(result.hashtags.join(' '));
      setShowAI(false);
    } catch (e) {
      setError((e as Error).message);
    }
  };

  const handleSubmit = async () => {
    if (!content.trim()) { setError('Content is required'); return; }
    if (selectedAccounts.size === 0) { setError('Select at least one account'); return; }
    if (overLimit) { setError(`Content exceeds ${limit} characters for ${primaryPlatform}`); return; }

    setSaving(true);
    setError('');
    try {
      const input: CreatePostInput = {
        content: content.trim(),
        hashtags: hashtags.split(/\s+/).filter(Boolean).map((h) => h.replace(/^#/, '')),
        link: link.trim() || undefined,
        accountIds: Array.from(selectedAccounts),
        scheduledAt: scheduledAt || undefined,
        useOptimalTime: useOptimal,
        autoRepostEnabled: autoRepost,
        repostIntervalDays: autoRepost ? repostDays : undefined,
        maxReposts: autoRepost ? maxReposts : undefined,
      };
      await createPost(input);
      onCreated();
    } catch (e) {
      setError((e as Error).message);
      setSaving(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 16 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="w-full max-w-xl glass rounded-2xl border border-white/10 shadow-2xl flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-white/5 shrink-0">
          <h2 className="text-base font-bold text-white">Create Post</h2>
          <button onClick={onClose} className="p-1.5 rounded-lg text-zinc-500 hover:text-white hover:bg-white/10 transition-colors">
            <X className="w-4 h-4" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-5">
          {/* Account selector */}
          <div>
            <label className="block text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-2">Post To</label>
            <AccountSelector accounts={accounts} selected={selectedAccounts} onToggle={toggleAccount} />
          </div>

          {/* Content */}
          <div>
            <div className="flex items-center justify-between mb-1.5">
              <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider">Content</label>
              <div className="flex items-center gap-2">
                <span className={`text-xs ${overLimit ? 'text-red-400' : 'text-zinc-500'}`}>
                  {charCount}/{limit}
                </span>
                <button
                  onClick={() => setShowAI(!showAI)}
                  className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 transition-colors"
                >
                  <Sparkles className="w-3 h-3" /> AI
                </button>
              </div>
            </div>

            {showAI && (
              <div className="mb-2 flex gap-2">
                <input
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  placeholder="Describe what to writeÔÇª"
                  className="flex-1 px-3 py-2 rounded-xl bg-white/5 border border-white/10 text-xs text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary/40 transition-colors"
                />
                <button
                  onClick={handleAIGenerate}
                  disabled={generating}
                  className="px-3 py-2 rounded-xl bg-primary hover:bg-primary/90 text-white text-xs font-semibold disabled:opacity-40 transition-colors flex items-center gap-1"
                >
                  {generating ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                  Generate
                </button>
              </div>
            )}

            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              rows={5}
              placeholder="What do you want to share?"
              className={`w-full px-3.5 py-3 rounded-xl bg-white/5 border text-sm text-white placeholder:text-zinc-600 resize-none focus:outline-none transition-colors leading-relaxed ${
                overLimit ? 'border-red-400/40 focus:border-red-400/60' : 'border-white/10 focus:border-primary/40'
              }`}
            />
          </div>

          {/* Hashtags */}
          <div>
            <label className="flex items-center gap-1 text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-1.5">
              <Hash className="w-3 h-3" /> Hashtags
            </label>
            <input
              value={hashtags}
              onChange={(e) => setHashtags(e.target.value)}
              placeholder="#marketing #brand #product"
              className="w-full px-3.5 py-2.5 rounded-xl bg-white/5 border border-white/10 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary/40 transition-colors"
            />
          </div>

          {/* Link */}
          <div>
            <label className="flex items-center gap-1 text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-1.5">
              <LinkIcon className="w-3 h-3" /> Link (optional)
            </label>
            <input
              value={link}
              onChange={(e) => setLink(e.target.value)}
              placeholder="https://example.com"
              className="w-full px-3.5 py-2.5 rounded-xl bg-white/5 border border-white/10 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary/40 transition-colors"
            />
          </div>

          {/* Scheduling */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="flex items-center gap-1 text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-1.5">
                <Clock className="w-3 h-3" /> Schedule At
              </label>
              <input
                type="datetime-local"
                value={scheduledAt}
                onChange={(e) => { setScheduledAt(e.target.value); setUseOptimal(false); }}
                className="w-full px-3 py-2 rounded-xl bg-white/5 border border-white/10 text-sm text-white focus:outline-none focus:border-primary/40 transition-colors"
              />
            </div>

            <div className="flex flex-col justify-end">
              <button
                onClick={() => { setUseOptimal(!useOptimal); if (!useOptimal) setScheduledAt(''); }}
                className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-xs font-medium transition-colors ${
                  useOptimal
                    ? 'border-primary/60 bg-primary/10 text-primary'
                    : 'border-white/10 text-zinc-400 hover:border-white/20 hover:text-zinc-200'
                }`}
              >
                <Sparkles className="w-3 h-3" />
                {useOptimal ? 'Using AI optimal time' : 'Use AI optimal time'}
              </button>
              {useOptimal && slots.length > 0 && (
                <p className="text-[10px] text-zinc-500 mt-1">
                  Next slot: {new Date(slots[0]).toLocaleString()}
                </p>
              )}
            </div>
          </div>

          {/* Auto-repost */}
          <div className="p-4 rounded-xl bg-white/3 border border-white/5">
            <div className="flex items-center justify-between">
              <label className="flex items-center gap-2 text-sm font-medium text-zinc-300 cursor-pointer">
                <RotateCcw className="w-4 h-4 text-primary" />
                Auto-Repost
              </label>
              <button
                onClick={() => setAutoRepost(!autoRepost)}
                className={`w-10 h-5 rounded-full transition-colors relative ${autoRepost ? 'bg-primary' : 'bg-zinc-700'}`}
              >
                <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white transition-transform ${autoRepost ? 'translate-x-5' : 'translate-x-0.5'}`} />
              </button>
            </div>

            {autoRepost && (
              <div className="mt-3 grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[10px] text-zinc-500 mb-1 block">Repost every (days)</label>
                  <input
                    type="number"
                    min={1}
                    max={365}
                    value={repostDays}
                    onChange={(e) => setRepostDays(Number(e.target.value))}
                    className="w-full px-3 py-1.5 rounded-lg bg-white/5 border border-white/10 text-sm text-white focus:outline-none focus:border-primary/40 transition-colors"
                  />
                </div>
                <div>
                  <label className="text-[10px] text-zinc-500 mb-1 block">Max reposts</label>
                  <input
                    type="number"
                    min={1}
                    max={50}
                    value={maxReposts}
                    onChange={(e) => setMaxReposts(Number(e.target.value))}
                    className="w-full px-3 py-1.5 rounded-lg bg-white/5 border border-white/10 text-sm text-white focus:outline-none focus:border-primary/40 transition-colors"
                  />
                </div>
              </div>
            )}
          </div>

          {error && (
            <div className="flex items-center gap-2 p-3 rounded-xl bg-red-500/10 border border-red-500/20">
              <AlertCircle className="w-4 h-4 text-red-400 shrink-0" />
              <p className="text-sm text-red-300">{error}</p>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 pb-6 pt-2 flex gap-3 shrink-0 border-t border-white/5">
          <button
            onClick={onClose}
            className="flex-1 py-2.5 rounded-xl border border-white/10 text-sm text-zinc-400 hover:text-white hover:bg-white/5 transition-colors"
          >
            Cancel
          </button>
          <button
            disabled={saving || !content.trim() || selectedAccounts.size === 0}
            onClick={handleSubmit}
            className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-primary hover:bg-primary/90 text-white text-sm font-semibold disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
          >
            {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
            {scheduledAt || useOptimal ? 'Schedule Post' : 'Publish Now'}
          </button>
        </div>
      </motion.div>
    </motion.div>
  );
}

'use client';

import { useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import {
  Search, Filter, MoreVertical, Trash2, Clock, Edit3, RefreshCw,
  Loader2, AlertCircle, CheckCircle2, ExternalLink, RotateCcw,
} from 'lucide-react';
import type { SocialAccount, ScheduledPost, PostStatus, SocialPlatform } from '@/hooks/useSocial';
import { useSocialPosts } from '@/hooks/useSocial';
import { PostStatusBadge } from './PostStatusBadge';
import { PlatformBadge, PLATFORM_ICONS } from './PlatformBadge';
import { CreatePostModal } from './CreatePostModal';

const STATUS_OPTIONS: PostStatus[] = ['DRAFT', 'SCHEDULED', 'PUBLISHING', 'PUBLISHED', 'FAILED', 'CANCELLED'];
const PLATFORM_OPTIONS: SocialPlatform[] = ['INSTAGRAM', 'FACEBOOK', 'TIKTOK', 'TWITTER', 'LINKEDIN', 'PINTEREST', 'WHATSAPP'];

function PostCard({
  post,
  onCancel,
  onReschedule,
}: {
  post: ScheduledPost;
  onCancel: () => Promise<void>;
  onReschedule: (scheduledAt: string) => Promise<void>;
}) {
  const [menuOpen, setMenuOpen] = useState(false);
  const [rescheduling, setRescheduling] = useState(false);
  const [newDate, setNewDate] = useState('');
  const [busy, setBusy] = useState(false);

  const platforms = post.accounts.map((a) => a.account.platform);
  const successResults = post.publishResults.filter((r) => r.status === 'SUCCESS');
  const failedResults  = post.publishResults.filter((r) => r.status === 'FAILED');

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.97 }}
      className="glass rounded-2xl border border-white/5 hover:border-white/10 p-5 transition-colors"
    >
      <div className="flex items-start gap-4">
        {/* Platform icons */}
        <div className="flex flex-col gap-1 shrink-0 mt-0.5">
          {platforms.slice(0, 3).map((p, i) => (
            <span key={i} className="text-base leading-none">{PLATFORM_ICONS[p]}</span>
          ))}
          {platforms.length > 3 && (
            <span className="text-[10px] text-zinc-500">+{platforms.length - 3}</span>
          )}
        </div>

        <div className="flex-1 min-w-0">
          {/* Content preview */}
          <p className="text-sm text-zinc-200 line-clamp-2 leading-relaxed">
            {post.content}
          </p>

          {/* Hashtags */}
          {post.hashtags.length > 0 && (
            <p className="text-xs text-primary/70 mt-1 truncate">
              {post.hashtags.slice(0, 5).map((h) => `#${h}`).join(' ')}
            </p>
          )}

          {/* Meta row */}
          <div className="flex flex-wrap items-center gap-2 mt-2.5">
            <PostStatusBadge status={post.status} />

            {post.scheduledAt && (
              <span className="text-xs text-zinc-500 flex items-center gap-1">
                <Clock className="w-3 h-3" />
                {new Date(post.scheduledAt).toLocaleString('en-US', {
                  month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit',
                })}
              </span>
            )}

            {post.aiGenerated && (
              <span className="text-[10px] text-primary/70 border border-primary/20 px-1.5 py-0.5 rounded-full">AI</span>
            )}

            {post.autoRepostEnabled && (
              <span className="text-[10px] text-zinc-500 flex items-center gap-0.5">
                <RotateCcw className="w-2.5 h-2.5" /> {post.repostCount}/{post.maxReposts}
              </span>
            )}
          </div>

          {/* Publish results */}
          {post.publishResults.length > 0 && (
            <div className="flex gap-2 mt-2.5 flex-wrap">
              {post.publishResults.map((r) => (
                <div
                  key={r.id}
                  className={`flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full border ${
                    r.status === 'SUCCESS'
                      ? 'border-emerald-500/20 bg-emerald-500/5 text-emerald-400'
                      : r.status === 'FAILED'
                      ? 'border-red-500/20 bg-red-500/5 text-red-400'
                      : 'border-zinc-700 text-zinc-500'
                  }`}
                >
                  <span>{PLATFORM_ICONS[r.platform]}</span>
                  {r.status === 'SUCCESS' ? (
                    r.platformUrl ? (
                      <a href={r.platformUrl} target="_blank" rel="noopener noreferrer" className="hover:underline flex items-center gap-0.5">
                        View <ExternalLink className="w-2.5 h-2.5" />
                      </a>
                    ) : 'Published'
                  ) : r.status === 'FAILED' ? (
                    <span title={r.errorMessage ?? ''}>Failed</span>
                  ) : r.status}
                </div>
              ))}
            </div>
          )}

          {/* Reschedule inline form */}
          {rescheduling && (
            <div className="flex items-center gap-2 mt-3">
              <input
                type="datetime-local"
                value={newDate}
                onChange={(e) => setNewDate(e.target.value)}
                className="flex-1 px-3 py-1.5 rounded-lg bg-white/5 border border-white/10 text-xs text-white focus:outline-none focus:border-primary/40 transition-colors"
              />
              <button
                disabled={!newDate || busy}
                onClick={async () => {
                  setBusy(true);
                  try { await onReschedule(new Date(newDate).toISOString()); setRescheduling(false); }
                  finally { setBusy(false); }
                }}
                className="px-3 py-1.5 rounded-lg bg-primary text-white text-xs font-semibold hover:bg-primary/90 disabled:opacity-40 transition-colors"
              >
                {busy ? <Loader2 className="w-3 h-3 animate-spin" /> : 'Confirm'}
              </button>
              <button onClick={() => setRescheduling(false)} className="text-zinc-500 hover:text-white text-xs">Cancel</button>
            </div>
          )}
        </div>

        {/* Kebab menu */}
        <div className="relative shrink-0">
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className="p-1 rounded-lg text-zinc-600 hover:text-white hover:bg-white/10 transition-colors"
          >
            <MoreVertical className="w-4 h-4" />
          </button>
          <AnimatePresence>
            {menuOpen && (
              <motion.div
                initial={{ opacity: 0, scale: 0.9, y: -4 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.9 }}
                onMouseLeave={() => setMenuOpen(false)}
                className="absolute right-0 top-8 z-50 w-40 glass rounded-xl border border-white/10 overflow-hidden shadow-2xl"
              >
                {['DRAFT', 'SCHEDULED'].includes(post.status) && (
                  <>
                    <button
                      onClick={() => { setRescheduling(true); setMenuOpen(false); }}
                      className="w-full flex items-center gap-2 px-3 py-2.5 text-sm text-zinc-300 hover:bg-white/10 hover:text-white transition-colors"
                    >
                      <Clock className="w-3.5 h-3.5" /> Reschedule
                    </button>
                    <button
                      onClick={async () => {
                        setMenuOpen(false);
                        setBusy(true);
                        try { await onCancel(); } finally { setBusy(false); }
                      }}
                      className="w-full flex items-center gap-2 px-3 py-2.5 text-sm text-red-400 hover:bg-red-400/10 transition-colors"
                    >
                      <Trash2 className="w-3.5 h-3.5" /> Cancel
                    </button>
                  </>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </motion.div>
  );
}

export function PostsView({ accounts }: { accounts: SocialAccount[] }) {
  const [showCreate, setShowCreate] = useState(false);
  const [search, setSearch]         = useState('');
  const [filterStatus, setFilterStatus] = useState<PostStatus | ''>('');
  const [filterPlatform, setFilterPlatform] = useState<SocialPlatform | ''>('');

  const { posts, loading, error, refresh, cancelPost, reschedule, applyFilters } = useSocialPosts();

  const filtered = posts.filter((p) =>
    p.content.toLowerCase().includes(search.toLowerCase()),
  );

  const handleFilterChange = (status: PostStatus | '', platform: SocialPlatform | '') => {
    setFilterStatus(status);
    setFilterPlatform(platform);
    applyFilters({
      status: status || undefined,
      platform: platform || undefined,
    });
  };

  return (
    <div>
      {/* Toolbar */}
      <div className="flex flex-wrap items-center gap-3 mb-6">
        <div className="relative flex-1 min-w-48">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search postsÔÇª"
            className="w-full pl-9 pr-4 py-2 rounded-xl bg-white/5 border border-white/10 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-primary/30 transition-colors"
          />
        </div>

        <select
          value={filterStatus}
          onChange={(e) => handleFilterChange(e.target.value as PostStatus | '', filterPlatform)}
          className="px-3 py-2 rounded-xl bg-white/5 border border-white/10 text-sm text-zinc-300 focus:outline-none focus:border-primary/30 transition-colors"
        >
          <option value="">All Statuses</option>
          {STATUS_OPTIONS.map((s) => <option key={s} value={s}>{s}</option>)}
        </select>

        <select
          value={filterPlatform}
          onChange={(e) => handleFilterChange(filterStatus, e.target.value as SocialPlatform | '')}
          className="px-3 py-2 rounded-xl bg-white/5 border border-white/10 text-sm text-zinc-300 focus:outline-none focus:border-primary/30 transition-colors"
        >
          <option value="">All Platforms</option>
          {PLATFORM_OPTIONS.map((p) => <option key={p} value={p}>{p}</option>)}
        </select>

        <button onClick={() => { void refresh(); }} className="p-2 rounded-xl border border-white/10 text-zinc-500 hover:text-white hover:bg-white/5 transition-colors">
          <RefreshCw className="w-4 h-4" />
        </button>
      </div>

      {/* List */}
      {loading ? (
        <div className="flex justify-center h-40 items-center">
          <Loader2 className="w-6 h-6 text-primary animate-spin" />
        </div>
      ) : error ? (
        <div className="flex flex-col items-center gap-3 h-40 justify-center text-center">
          <AlertCircle className="w-8 h-8 text-red-400" />
          <p className="text-zinc-400 text-sm">{error}</p>
        </div>
      ) : filtered.length === 0 ? (
        <div className="flex flex-col items-center gap-3 h-40 justify-center text-center">
          <p className="text-zinc-400 text-sm">No posts found</p>
        </div>
      ) : (
        <div className="space-y-3">
          <AnimatePresence>
            {filtered.map((post) => (
              <PostCard
                key={post.id}
                post={post}
                onCancel={() => cancelPost(post.id)}
                onReschedule={async (at) => {
                  await reschedule(post.id, at);
                }}
              />
            ))}
          </AnimatePresence>
        </div>
      )}

      <AnimatePresence>
        {showCreate && (
          <CreatePostModal
            accounts={accounts}
            onClose={() => setShowCreate(false)}
            onCreated={() => { setShowCreate(false); refresh(); }}
          />
        )}
      </AnimatePresence>
    </div>
  );
}

